-- Poems batch 355
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('10346336-22c9-4906-9a90-8cb470ab5b91','春日遊金明池','李昭玘','宋','宋诗','song-poetry','','[]','日有江湖思，坐無車馬塵。',48,'全唐诗/poet.song.73000.json','["日有江湖思，坐無車馬塵。", "橫橋自照水，啼鳥不驚人。", "輦路晴飛絮，宮門暗鎖春。", "多情老園吏，灑地喜相親。"]'),
('7ab1aac5-0194-4bb9-aefe-b72c2cd7bb0e','觀劉孝嗣寫真','李昭玘','宋','宋诗','song-poetry','','[]','程生高價傳兩都，劉子骨相真丈夫。',128,'全唐诗/poet.song.73000.json','["程生高價傳兩都，劉子骨相真丈夫。", "呼兒當軒試一展，噱噱指點相驚呼。", "此應前日坐頭客，何乃不語嚴襟裾。", "胸中豪氣不可狀，但見粉墨無紆餘。", "虎頭食肉亦天賦，尺面封侯宜不誣。", "須知中令有真相，忽效香山悲故吾。", "凌烟功臣易磨滅，貞觀學士猶傳模。", "當時人物不易得，曾看風神有此無。"]'),
('a60043a4-cc7c-4ae5-8e7c-c27afd09683f','觀畫','李昭玘','宋','宋诗','song-poetry','','[]','夢澤正天寒，南峰带秋色。',144,'全唐诗/poet.song.73000.json','["夢澤正天寒，南峰带秋色。", "詩人句不盡，餘意傳粉墨。", "年來兩眼昏，吏牘苦侵迫。", "明窗展橫素，刮膜謝砭石。", "往時蓬萊宮，圖畫燦東壁。", "拾遺老陰峭，思訓麗春碧。", "經年一過眼，行繞不暇食。", "太行逢李生，筆勢妙思索。", "未成真營丘，不俗已高格。", "安得十萬錢，盡致鵝溪白。", "不須念衣裘，䃜灰日滋殖。", "寫我江湖心，浩蕩滿千尺。"]'),
('46aaa413-9cb8-471b-a594-ac5bad6fef97','深山','李昭玘','宋','宋诗','song-poetry','','[]','日出斂蒼靄，雨餘生曉凉。',24,'全唐诗/poet.song.73000.json','["日出斂蒼靄，雨餘生曉凉。", "鳥啼人不見，花落樹猶香。"]'),
('3c953264-a355-4972-8762-29fa530d4a2f','詩一首','李昭玘','宋','宋诗','song-poetry','','[]','託身深秋困泥沙，鼓腹垂頤暴水涯。',32,'全唐诗/poet.song.73000.json','["託身深秋困泥沙，鼓腹垂頤暴水涯。", "天上月輪勞注想，草中咫尺有長蛇。"]'),
('8b8c87cf-14d6-49f2-b607-32ba62dac287','中頂','李昭玘','宋','宋诗','song-poetry','','[]','策足穿雲表，都無幾尺天。',24,'全唐诗/poet.song.73000.json','["策足穿雲表，都無幾尺天。", "人寰莽何在，萬里一荒烟。"]'),
('3f636ab7-885b-4b63-9862-0516b6ef070e','回馬嶺','李昭玘','宋','宋诗','song-poetry','','[]','緩轡不可度，疾驅應更危。',24,'全唐诗/poet.song.73000.json','["緩轡不可度，疾驅應更危。", "平生幾兩屐，解有慰人時。"]'),
('9f4719a4-73d1-40ca-914f-432b265c0991','句  其一','李昭玘','宋','宋诗','song-poetry','','[]','日邊雁带臘寒去，雪裏梅將春信來。',16,'全唐诗/poet.song.73000.json','["日邊雁带臘寒去，雪裏梅將春信來。"]'),
('7a0f811f-e5e6-4d03-9f61-c9a7baacb474','句  其二','李昭玘','宋','宋诗','song-poetry','','[]','東林夫子知予意。',8,'全唐诗/poet.song.73000.json','["東林夫子知予意。"]'),
('3705cb2e-8f1e-42f7-bc06-b42abbe66c6d','臨安自述  其一','趙期','宋','宋诗','song-poetry','','[]','塵生宮闕霧濛濛，萬騎龍飛幸越中。',64,'全唐诗/poet.song.73000.json','["塵生宮闕霧濛濛，萬騎龍飛幸越中。", "在野三閭君不顧，乘軒衛鶴懿何功。", "雖知四海同文久，未合中原武備空。", "星落夜原妖氣滿，漢家麟閣待英雄。"]'),
('a906ad96-7f66-4e98-9ad0-6e0a69730da9','臨安自述  其二','趙期','宋','宋诗','song-poetry','','[]','臨安皓月色如珪，清景傷時一慘悽。',67,'全唐诗/poet.song.73000.json','["臨安皓月色如珪，清景傷時一慘悽。", "未見山前歸牧馬，猶聞江上带征{馬卑}。", "鯤爲魚隊潜鱗困，鶴處雞羣病翅低。", "正是四郊多壘日，波濤早晚靜鯨鯢。"]'),
('0e076adc-d4d3-4b6a-9f34-7c1bc9f15906','感時','趙期','宋','宋诗','song-poetry','','[]','誰人共挽天河水，盡洗中原犬虜腥。',32,'全唐诗/poet.song.73000.json','["誰人共挽天河水，盡洗中原犬虜腥。", "角巾私第不復言，兵迨留守宗澤疏。"]'),
('5b4f5297-d2fa-4ca2-ba8b-36499e2716eb','自述  其一','趙期','宋','宋诗','song-poetry','','[]','萬木陰中一草廬，溪風山月弄清虛。',32,'全唐诗/poet.song.73000.json','["萬木陰中一草廬，溪風山月弄清虛。", "主人靜坐心無物，讀盡人間未見書。"]'),
('a4f11c44-774c-41f1-9666-bec57b440690','自述  其二','趙期','宋','宋诗','song-poetry','','[]','高山流水興無窮，杖策携琴踏軟紅。',32,'全唐诗/poet.song.73000.json','["高山流水興無窮，杖策携琴踏軟紅。", "莫怨子期呼不起，請君一曲奏南風。"]'),
('d4e596bf-398e-4699-80f7-663f11813d1b','句','趙期','宋','宋诗','song-poetry','','[]','早向江南征義旅，星馳千里自嫌遲。',16,'全唐诗/poet.song.73000.json','["早向江南征義旅，星馳千里自嫌遲。"]'),
('f5ba8cd9-d76a-4ee0-ab51-fa7f99ed9f4f','崑山夜泊舟中遣懷','胡嶧','宋','宋诗','song-poetry','','[]','念昔扶衰別故城，敢期身見稍休兵。',64,'全唐诗/poet.song.73000.json','["念昔扶衰別故城，敢期身見稍休兵。", "連年防患秋更急，此節浮家夜亦行。", "夢裏不應追昨夢，生前聊復且偷生。", "空中鳥跡誰能記，萬古由來一妄情。"]'),
('a04584c8-c732-44a1-a54b-864c14a21fca','泊崑山','胡嶧','宋','宋诗','song-poetry','','[]','疾風欺雨透蓬船，擁被和衣晝亦眠。',32,'全唐诗/poet.song.73000.json','["疾風欺雨透蓬船，擁被和衣晝亦眠。", "兒女登臨餘脚力，更隨明月遶山前。"]'),
('84a28a21-f109-459d-ae8d-5476f72d7e2e','同仲南弟遊慧聚寺','胡嶧','宋','宋诗','song-poetry','','[]','政欲相携紫翠間，不堪風雨徑催還。',32,'全唐诗/poet.song.73000.json','["政欲相携紫翠間，不堪風雨徑催還。", "何時更上月華閣，細認真山與假山。"]'),
('36fc31d5-e794-4ddf-a782-2a7a732333a6','過百家瀼','胡嶧','宋','宋诗','song-poetry','','[]','風雨留人阻去程，扶衰上冢過清明。',32,'全唐诗/poet.song.73000.json','["風雨留人阻去程，扶衰上冢過清明。", "百家瀼裏猶掀簸，那得江神不世情。"]'),
('11045c60-4559-498f-976d-fc9dafad6070','留題衡嶽觀','張兟','宋','宋诗','song-poetry','','[]','靈嶽峰前遊古觀，此中何別蕊珠宮。',64,'全唐诗/poet.song.73000.json','["靈嶽峰前遊古觀，此中何別蕊珠宮。", "五雲仙客形皆異，十洞烟花景不同。", "鍊藥爐香金石氣，醮星壇冷薜蘿風。", "因聞大道修真訣，咫尺三清路可沖。"]'),
('52cfe1b7-6e93-4b34-bc93-5591e4e84aa3','五峰巖','張茂先','宋','宋诗','song-poetry','','[]','五峰巖竇倚層巒，偷暇登臨到此山。',64,'全唐诗/poet.song.73000.json','["五峰巖竇倚層巒，偷暇登臨到此山。", "泉石靜中無俗客，樓臺深處鎖禪關。", "憑高林野依稀盡，望闊雲天繚繞還。", "回首夕陽歸去路，紅塵隨馬轉溪灣。"]'),
('6de94139-e208-472b-a3fd-21fa582a46a2','句  其一','張茂先','宋','宋诗','song-poetry','','[]','重衾無暖氣，挾纊如懷冰。',12,'全唐诗/poet.song.73000.json','["重衾無暖氣，挾纊如懷冰。"]'),
('0d01ccfd-8086-409a-80e8-36fe36803be1','句  其二','張茂先','宋','宋诗','song-poetry','','[]','德輶如羽。',5,'全唐诗/poet.song.73000.json','["德輶如羽。"]'),
('6affb946-b3f6-4aa1-99aa-0be71d5e34ae','句  其三','張茂先','宋','宋诗','song-poetry','','[]','熠熠宵流。',5,'全唐诗/poet.song.73000.json','["熠熠宵流。"]'),
('4d92e63e-39b9-4a36-9c58-2cb2cd5652e9','句  其四','張茂先','宋','宋诗','song-poetry','','[]','煥若春華敷。',6,'全唐诗/poet.song.73000.json','["煥若春華敷。"]'),
('78968a9d-f35e-44ea-833e-e6b658126b17','南禪寺','熊浚明','宋','宋诗','song-poetry','','[]','老榕挹翠拂雙垣，流水相通郭外村。',64,'全唐诗/poet.song.73000.json','["老榕挹翠拂雙垣，流水相通郭外村。", "一竹便堪勝謂畝，千花應不羨桃源。", "漁樵小徑斜通市，雞犬誰家半掩門。", "最好風光孤坐處，亭亭海月破黄昏。"]'),
('0e55f020-72ed-4742-972d-6f82464fb356','句','熊浚明','宋','宋诗','song-poetry','','[]','卓筆一峰當殿閣，合圍千嶂鎖林泉。',16,'全唐诗/poet.song.73000.json','["卓筆一峰當殿閣，合圍千嶂鎖林泉。"]'),
('9543d9e3-e044-4414-9c79-7ebf454378af','還家塗中','曾繹','宋','宋诗','song-poetry','','[]','疏林殘嶺起昏鴉，臘盡行人喜近家。',32,'全唐诗/poet.song.73000.json','["疏林殘嶺起昏鴉，臘盡行人喜近家。", "江北江南春信早，傍籬穿竹見梅花。"]'),
('e310d34e-ac6d-4062-81a6-d5b443aae19d','句','曾繹','宋','宋诗','song-poetry','','[]','已無醜扇几邊亂，空見春鉏天際飛。',16,'全唐诗/poet.song.73000.json','["已無醜扇几邊亂，空見春鉏天際飛。"]'),
('200196c1-ac77-4d23-9067-289c9cbf01a8','斗南樓','朱師服','宋','宋诗','song-poetry','','[]','危構參寥廓，星躔耿北窗。',48,'全唐诗/poet.song.73000.json','["危構參寥廓，星躔耿北窗。", "戰餘塵沒馬，魚散月澄江。", "遲暮憐孤客，寬閒樂此邦。", "坐中詩有待，端欲受誰降。"]'),
('f9388a08-3e59-4d40-8259-81227552a817','句','朱師服','宋','宋诗','song-poetry','','[]','子牟心未老，愁上越王臺。',12,'全唐诗/poet.song.73000.json','["子牟心未老，愁上越王臺。"]'),
('311e17ba-e0f1-49b7-a955-45923f889622','薦福院雙柏','李常','宋','宋诗','song-poetry','','[]','當日雙縑直萬緡，買留柯葉拂星辰。',32,'全唐诗/poet.song.73000.json','["當日雙縑直萬緡，買留柯葉拂星辰。", "上巢絕頂饒千鶴，下憩清陰可百人。"]'),
('5666deba-644b-494b-9814-1d6ee4442115','送別呂子進自中舍出知睦州','張惇','宋','宋诗','song-poetry','','[]','籬鷃雲鵬各有程，匆匆相別未忘情。',32,'全唐诗/poet.song.73000.json','["籬鷃雲鵬各有程，匆匆相別未忘情。", "恨君不在蓬窗底，共聽蕭蕭夜雨聲。"]'),
('ffa41585-296c-4b34-ac45-09508d7d64f0','夢中作','張惇','宋','宋诗','song-poetry','','[]','楚峽雲嬌宋玉愁，月明溪浄印銀鈎。',32,'全唐诗/poet.song.73000.json','["楚峽雲嬌宋玉愁，月明溪浄印銀鈎。", "襄王定是思前夢，又抱霞衾上玉樓。"]'),
('08414809-4cff-4f97-9068-648fbf4e0c1b','題山宮法安院','章憑','宋','宋诗','song-poetry','','[]','山家門逕鎖寒松，更向烟蘿第幾重。',64,'全唐诗/poet.song.73000.json','["山家門逕鎖寒松，更向烟蘿第幾重。", "幽鳥啼花歸舊谷，應龍飛雨過前峰。", "分持皂蓋歌千騎，入冠黄扉祿萬鍾。", "一見高吟重興感，清名長在木陰濃。"]'),
('396a49c8-97bf-4361-b314-3ed88443dcf4','題靈康廟','章憑','宋','宋诗','song-poetry','','[]','山邊清氣擁祥氛，遺跡流傳漢史存。',64,'全唐诗/poet.song.73000.json','["山邊清氣擁祥氛，遺跡流傳漢史存。", "金殿已頒新號美，劍崖猶隠舊痕昏。", "據簷焚鼎驚魚市，浮蓋呼風過海門。", "千里陰功誠不淺，紛紛餘事豈須論。"]'),
('8db736c8-b426-4323-8595-4d794a5df1a2','凝真宮','章憑','宋','宋诗','song-poetry','','[]','昔人騰碧落，餘地掃巖隈。',48,'全唐诗/poet.song.73000.json','["昔人騰碧落，餘地掃巖隈。", "石壁雲長在，松梢風自來。", "暗扉通浩蕩，古蔓接崔嵬。", "更欲窮幽隠，仙源路已回。"]'),
('9c9ad35b-a6e0-406d-800d-08280a4bca2a','流花亭','章憑','宋','宋诗','song-poetry','','[]','亭榜得佳名，山鬟擁翠闉。',48,'全唐诗/poet.song.73000.json','["亭榜得佳名，山鬟擁翠闉。", "風流傳晉客，談笑憶秦人。", "水出桃源路，花浮洞府春。", "未應迷俗駕，行處是通津。"]'),
('a7e9963c-576c-4737-9f30-2f55b3d399a2','石橋','章憑','宋','宋诗','song-poetry','','[]','昔聞天台山，方廣寺尤勝。',48,'全唐诗/poet.song.73000.json','["昔聞天台山，方廣寺尤勝。", "石梁元自成，茶花隨所應。", "見此絕世蹤，嗟我拘三乘。", "更聽寒泉聲，不獨發清興。"]'),
('10f85712-9fdc-4f2c-99a4-61681b383184','句','吳臧','宋','宋诗','song-poetry','','[]','葛巾竹杖閒來此，可是心清跡亦清。',16,'全唐诗/poet.song.73000.json','["葛巾竹杖閒來此，可是心清跡亦清。"]'),
('3bb8810e-1a6e-4fbb-8160-5f7f4704ab01','黄龍洞','林同叔','宋','宋诗','song-poetry','','[]','黄龍一洞與天通，仰視星辰目睫中。',32,'全唐诗/poet.song.73000.json','["黄龍一洞與天通，仰視星辰目睫中。", "人去壇虛今已矣，祇留手植七株松。"]'),
('945117c8-4906-4afc-8a3b-21188ade9b4a','七星壇','林同叔','宋','宋诗','song-poetry','','[]','十年客夢憶南徐，玉案曾看綠篆書。',32,'全唐诗/poet.song.73000.json','["十年客夢憶南徐，玉案曾看綠篆書。", "今日星壇香一瓣，恍如身再到沖虛。"]'),
('dbe0a98a-efa0-4455-ae66-45025b6b0f63','九眼井','林同叔','宋','宋诗','song-poetry','','[]','幽人鑿井住羅浮，暇日吾伊興自由。',32,'全唐诗/poet.song.73000.json','["幽人鑿井住羅浮，暇日吾伊興自由。", "仙鳥避吟來照影，九龍飛動碧雲秋。"]'),
('f53c9079-2963-4a2f-bb9e-be31dc026c7b','莫道人','林同叔','宋','宋诗','song-poetry','','[]','萬古烟霞隠石門，洞中別是一乾坤。',32,'全唐诗/poet.song.73000.json','["萬古烟霞隠石門，洞中別是一乾坤。", "仙翁自不知年歲，山下於今幾代孫。"]'),
('577095b8-9ecc-4a74-827d-54448d3bc031','題栝蒼洞宮','劉光','宋','宋诗','song-poetry','','[]','古洞藏真不記年，翠崖蒼壁故依然。',32,'全唐诗/poet.song.73000.json','["古洞藏真不記年，翠崖蒼壁故依然。", "怪來一夜清無夢，身在仙家第十天。"]'),
('1977aa62-786f-4290-ac28-28f09a06b443','題南峰藍光軒','劉光','宋','宋诗','song-poetry','','[]','百尺擎空窣堵波，羣峰奈此獨高何。',64,'全唐诗/poet.song.73000.json','["百尺擎空窣堵波，羣峰奈此獨高何。", "鼓鐘鳴處是非外，天地望中蒼翠多。", "閒看野雲披玉柱，醉眠秋浪捲銀河。", "問師乞取窗前月，一榻清風許我麽。"]'),
('af59dc35-9351-4d44-8c8c-253dfb08b877','妙香堂','鄭敦芳','宋','宋诗','song-poetry','','[]','山勢巍巍千萬重，來游仍覺思無窮。',64,'全唐诗/poet.song.73000.json','["山勢巍巍千萬重，來游仍覺思無窮。", "峰巒合匝溪如斷，巖谷迴旋徑忽通。", "石屋凄凉飛瀑布，竹窗虛寂灑香風。", "開軒無限崢嶸景，盡日閒觀屬遠公。"]'),
('ef1980bf-598a-4372-8754-65f51a4bc5e9','有懷楊沖遠','雍沖','宋','宋诗','song-poetry','','[]','積雪蓋重峰，巖松迷翠影。',48,'全唐诗/poet.song.73000.json','["積雪蓋重峰，巖松迷翠影。", "扶筇啟靜扉，耐此茅簷冷。", "幽澗凍鳴泉，釣翁立舴艋。", "伊人不可即，憂懷結怲怲。"]'),
('ea95b7b6-6e41-4ec8-b44e-8d2e2bf94096','澹山巖  其一','張如遠','宋','宋诗','song-poetry','','[]','試將□懇種青霄，遂話田疇萬里焦。',32,'全唐诗/poet.song.73000.json','["試將□懇種青霄，遂話田疇萬里焦。", "不是湫龍解興雨，元來滴滴是心苗。"]'),
('d317b525-5405-4a11-a0ce-c71dccc6941b','澹山巖  其二','張如遠','宋','宋诗','song-poetry','','[]','禱澤何妨抵死求，分明在處有神湫。',32,'全唐诗/poet.song.73000.json','["禱澤何妨抵死求，分明在處有神湫。", "只消一念精誠格，立使風雷布九州。"]'),
('7c296cda-2c85-4f0f-8e60-4320a9d098ea','澹山巖  其三','張如遠','宋','宋诗','song-poetry','','[]','幽谷復來分外清，那堪雨過月華新。',32,'全唐诗/poet.song.73000.json','["幽谷復來分外清，那堪雨過月華新。", "行將高謝浮名事，卜築巖旁效子真。"]'),
('c30a290d-42ff-4cc1-a36d-fa01f4fb166e','絕句','蹇汝明','宋','宋诗','song-poetry','','[]','我聞敬亭無足取，岑寂況在東南崖。',32,'全唐诗/poet.song.73000.json','["我聞敬亭無足取，岑寂況在東南崖。", "聲名一日遍宇宙，正以謝守詩瑰奇。"]'),
('f9562db1-0f89-4d35-859d-4b8b14439e77','題翰林灘','蹇汝明','宋','宋诗','song-poetry','','[]','灘崖猶刻翰林名，鑿鑿寒波潄玉聲。',32,'全唐诗/poet.song.73000.json','["灘崖猶刻翰林名，鑿鑿寒波潄玉聲。", "遊子淒其感今昔，臨流不敢濯塵纓。"]'),
('7058e6cf-c4f9-4e64-bae9-75183b890307','建炎己酉冬自婺女携家至臨海歲首泛舟憩天柱精舍謁吳君文叟山林感泉石之勝歎城邑之人沈酣勢利不知山中之樂也','蘇遲','宋','宋诗','song-poetry','','[]','列嶂崢嶸植翠屏，寒泉綠浄浸軒楹。',64,'全唐诗/poet.song.73000.json','["列嶂崢嶸植翠屏，寒泉綠浄浸軒楹。", "衣巾清潤玻瓈上，窗牖疏明圖畫成。", "塵世正趨名利域，山居不識鼓鼙聲。", "莫年憂患將何適，暫喜滄浪可濯纓。"]'),
('12459b89-fc77-4fd0-93f7-08a37a992aad','偈','釋杲','宋','宋诗','song-poetry','','[]','歸宗會斬蛇，禾山解打鼓。',24,'全唐诗/poet.song.73000.json','["歸宗會斬蛇，禾山解打鼓。", "萬象與森羅，皆從這裏去。"]'),
('69eb4a7f-20a5-4c51-9699-2d85c9d1e9e3','景陽井','王元甫','宋','宋诗','song-poetry','','[]','動地隋兵至，君王尚晏安。',48,'全唐诗/poet.song.73000.json','["動地隋兵至，君王尚晏安。", "須知天下窄，不及井中寬。", "樓外鋒交白，溪邊血染丹。", "無情是殘月，依舊照闌干。"]'),
('b30ff0be-0d9f-4ff4-b41f-8618a45ca6f0','送外','謝氏','宋','宋诗','song-poetry','','[]','此去唯宜早早還，休教重起望夫山。',32,'全唐诗/poet.song.73000.json','["此去唯宜早早還，休教重起望夫山。", "君看湘水祠前竹，不是男兒淚染斑。"]'),
('29783ef0-1a52-4af9-8dcc-865e5c388f79','予至壽陽道因訪造華嚴論李長者舊居','楊謨','宋','宋诗','song-poetry','','[]','方山百里路崎嶇，按部因尋長者廬。',32,'全唐诗/poet.song.73000.json','["方山百里路崎嶇，按部因尋長者廬。", "伏虎已歸天女去，隴頭新見萬松株。"]'),
('a8a7c39b-f288-438d-b201-e924678a9ba5','琵琶泓','楊謨','宋','宋诗','song-poetry','','[]','晉城出郭十里餘，嫩柳山花滿巖麓。',64,'全唐诗/poet.song.73000.json','["晉城出郭十里餘，嫩柳山花滿巖麓。", "蒼苔蹭蹬步亦艱，百丈懸崖掛層屋。", "老僧正睡門不閉，習習陰風起幽谷。", "耳聵不聞琵琶聲，但見一泓春水綠。"]'),
('03b7e80b-05e4-4356-92ee-3c1f1e146fc1','感春','慕容彥逢','宋','宋诗','song-poetry','','[]','橋門並馳道，車轂聲摩空。',144,'全唐诗/poet.song.73000.json','["橋門並馳道，車轂聲摩空。", "重廊隔囂鬨，闃若林巒中。", "黎明寮寀集，聯騎紛蹄鬃。", "交情金蘭契，晤語藥石攻。", "翰墨時間作，辭氣爭豪雄。", "微蹤幸接武，徒愧勞無功。", "軒窗鑒晴日，簷外鳴春蟲。", "沉迷驚節物，飲啄嗟樊籠。", "沂風漸澹蕩，璧水初沖融。", "坐想名園花，芳菲衒青紅。", "儒宮異拘窘，胡爲苦匆匆。", "來時招客醉，駕言與君同。"]'),
('14fed4a4-86db-4342-9e45-71495cc01375','夜深偶成','慕容彥逢','宋','宋诗','song-poetry','','[]','同舍諸稚子，初更坦腹眠。',120,'全唐诗/poet.song.73000.json','["同舍諸稚子，初更坦腹眠。", "須臾起鼻息，洶洶如奔泉。", "而我憂且病，欲卧輒遷延。", "坐久覺疲倦，就枕如臨淵。", "展轉復長吁，情緒更凄然。", "睡思暫彷彿，征雁鳴九天。", "使我不能寐，體氣寧不便。", "身心貴攝理，事累宜棄捐。", "而我無所答，泣涕但漣漣。", "是時月當午，素影隙中圓。"]'),
('67f33ea4-3a14-44b1-92cf-b140d065e987','晝卧偶成用前韵','慕容彥逢','宋','宋诗','song-poetry','','[]','我如邊孝先，性愛日晝眠。',144,'全唐诗/poet.song.73000.json','["我如邊孝先，性愛日晝眠。", "眠眠曷能寐，愁思如湧泉。", "東風穆穆和，午影遲遲延。", "憂多首自旋，猶如瞰面淵。", "人皆喜春色，而我今猶然。", "叱奴啟南窗，欹枕望青天。", "浮雲來飄飄，飛鳥去還還。", "望眼無窮極，移卧窗之前。", "焉能夢栩栩，徒自腹便便。", "悠思慕范蠡，心形得兩捐。", "輕舟泛五湖，短棹鼓清漣。", "規矩不我制，所意成方圓。"]'),
('f137e597-6478-44f0-bcce-e0a68631ba2a','讀揚子','慕容彥逢','宋','宋诗','song-poetry','','[]','子雲不偶時，晏如在空屋。',72,'全唐诗/poet.song.73000.json','["子雲不偶時，晏如在空屋。", "席有玄虛文，門無權倖牘。", "法言譏異戶，解嘲懼赤族。", "忿悱賦長楊，羞愧登天祿。", "立俗思徇道，制行依聖讀。", "身死名不朽，馨香藹蘭菊。"]'),
('c52648d0-c712-4071-9890-9ba6c8519101','讀陶淵明集','慕容彥逢','宋','宋诗','song-poetry','','[]','晉末何所似，波心躍長鯨。',156,'全唐诗/poet.song.73000.json','["晉末何所似，波心躍長鯨。", "生民畏擾攘，蹙頞視欃槍。", "淵明當此時，棄爵務躬耕。", "葛巾漉家酎，盃乾壺再傾。", "恢然聊寄傲，無心事將迎。", "眼底不足語，筆下漫攄情。", "襟懷有佳趣，落紙字字清。", "有如碎寒冰，貯之琉璃罃。", "又如湛秋水，含茲霜月明。", "秀氣如可掬，妙理不可名。", "辭中有餘意，此致尤更精。", "班豪誠可厭，曹侈無足評。", "斯文孰比擬，誦之清風生。"]'),
('64103118-8a5a-448d-9417-f0fdaf50fc75','三月雨霽遊壽聖寺','慕容彥逢','宋','宋诗','song-poetry','','[]','新霽澤國凈，禽聲落雲天。',96,'全唐诗/poet.song.73000.json','["新霽澤國凈，禽聲落雲天。", "精廬巧營構，重扉鎖春妍。", "簷楹曳晴絲，池沼鳴細泉。", "卉木互凌沒，鉛華刷澄鮮。", "檜樅屹如削，榴櫻開欲然。", "零蕊莓苔鮮，幽香雜蘭荃。", "俛仰欣所遇，塵埃坐自捐。", "云何寫軒曠，松風鳴素弦。"]'),
('95502889-52c8-4030-a2de-f9f40a553faa','留題聖壽院','慕容彥逢','宋','宋诗','song-poetry','','[]','休征日欲沉，晚風薄虛翠。',96,'全唐诗/poet.song.73000.json','["休征日欲沉，晚風薄虛翠。", "深秋景物清，蓮宮有佳致。", "疏林速凄凉，黄花弄明媚。", "山烟入寥廓，螽聲失幽邃。", "翻經瞥聞音，掃葉不待篲。", "危軒逗寒色，飛禽示真意。", "勤役何足辭，妙觀良可秘。", "歸歟誠未央，爾耳悲所志。"]'),
('fd3c310e-44ab-40c6-943f-b35358be1da6','留題覺慈寺','慕容彥逢','宋','宋诗','song-poetry','','[]','勤役大無悰，駕言從勝遊。',96,'全唐诗/poet.song.73000.json','["勤役大無悰，駕言從勝遊。", "蕭蕭野色凈，行行村逕修。", "逶迤轉隈隩，初見巖巒幽。", "喬木聳霄漢，風籟凌清秋。", "稅鞅得精舍，雲遶空中樓。", "簷楹列清障，下有百丈湫。", "紅塵不到處，俛仰銷百憂。", "喟然問圓頂，有此能樂不。"]'),
('71b3146e-8660-4786-b76c-413c193381ef','留題智者寺','慕容彥逢','宋','宋诗','song-poetry','','[]','天工剖山腹，翻然納虛秀。',72,'全唐诗/poet.song.73000.json','["天工剖山腹，翻然納虛秀。", "環岡插修蔭，斜巔倚寒溜。", "危軒列層級，橫梁跨深竇。", "浮烟羃輕縷，飛禽引鳴脰。", "沖襟得清盼，佳致絕纖垢。", "夢想脫冠來，塵緣苦相逗。"]'),
('ecbbaecb-a052-4bc2-90f9-d9c7d649dffc','留題婺州智者寺','慕容彥逢','宋','宋诗','song-poetry','','[]','宿雨雖乍晴，輕雲猶出岫。',120,'全唐诗/poet.song.73000.json','["宿雨雖乍晴，輕雲猶出岫。", "春深卉木繁，千巖衒芳秀。", "誰云山逕幽，涓涓響寒溜。", "時禽助好音，百囀引鳥脰。", "老僧邀客留，蒲簾捲圭竇。", "側耳石鼎傍，蠅聲辯湯候。", "茶品頗自修，擊拂振襟袖。", "勤劬爇鑪香，挹試殆三嗅。", "稍定與之言，飄然出塵垢。", "坐久月華生，澄潭明列宿。"]'),
('4fec6fe8-645d-4a38-80f2-359994926257','和吳顯道','慕容彥逢','宋','宋诗','song-poetry','','[]','澤國破秋仲，景物兆冬索。',288,'全唐诗/poet.song.73000.json','["澤國破秋仲，景物兆冬索。", "回飆卷林尾，宿霧泛寥廓。", "泮水還闤闍，層巒瞰籬落。", "啟牖挹蒨葱，開徑徒參錯。", "虀鹽雖寂寥，文史欣博約。", "論古到鴻荒，談經愧穿鑿。", "逸志想鴻冥，靦顔羞雉啄。", "於焉得真趣，豁若解其縛。", "環窗惟載籍，一視等糟粕。", "了了見本來，端如契圓覺。", "沖襟遊汗漫，高步趨廣莫。", "同心有名儒，攝官在戎幕。", "學識造淵醇，詞章臻炳鑠。", "良驥服鹽車，白駒縶場藿。", "念昔始傾蓋，考正于狐貉。", "韵宇凜可欽，標致湛無著。", "觴豆陪餘歡，翰墨時間作。", "晨嬉風力勁，夜語霜威虐。", "屈指兩炎凉，流年信迴薄。", "九重躋帝德，四海絕民瘼。", "南征奠蠻侮，西戍弭戎掠。", "吾道斯爲亨，君才顧何怍。", "行當坐天祿，看書資筆削。", "不然冥成均，闡教助飛躍。"]'),
('113a0f8a-f906-480b-b88e-98c4ff935e49','題諸暨王秀才華軒','慕容彥逢','宋','宋诗','song-poetry','','[]','卜居遠喧闐，山中有清意。',96,'全唐诗/poet.song.73000.json','["卜居遠喧闐，山中有清意。", "中爲風月軒，周詩得標置。", "琴書道自樂，花柳春爭媚。", "紛華非所事，安恬養天智。", "君家逸少後，芬芬今不墜。", "文章擅場屋，孝弟先閭比。", "小淹何足嗟，懿德天所秘。", "醖藉勿感慨，雲雷起平地。"]'),
('85f821c4-983e-446b-8f48-a0fc8b58181d','次韵葉權之南宮春興','慕容彥逢','宋','宋诗','song-poetry','','[]','三年客京華，雰埃侵鬢綠。',144,'全唐诗/poet.song.73000.json','["三年客京華，雰埃侵鬢綠。", "花時豈相關，藜藿欣自足。", "故春鎖膠庠，庭槐如兔目。", "沂風清晝吟，璧水泛晨矚。", "今我復來茲，芳菲照華屋。", "日長簾幕深，欠伸倦晴燠。", "英英同舍郎，文采命騷僕。", "真想寄吟哦，詩壇令何肅。", "惟時屆清明，千官賜休沐。", "我事未渠央，矧敢念歸宿。", "何當榜貢書，諸生駭神速。", "君歌我乃賡，聊以慰局趣。"]'),
('dbdd1165-17b3-4c7e-93a5-11c4ebc30a88','再次前韵贈葉權之','慕容彥逢','宋','宋诗','song-poetry','','[]','廣文新决科，恩袍鬭春綠。',144,'全唐诗/poet.song.73000.json','["廣文新决科，恩袍鬭春綠。", "香名滿衆耳，要路策高足。", "阿房得第五，中眉嗟志目。", "平明趨省門，容儀聳旁矚。", "廩薄雖屢空，潤身非潤屋。", "朅來鎖南宮，迨此東風燠。", "吟哦夜不休，立侍窘童僕。", "詩成字字清，華星點秋肅。", "中含不盡意，往往念歸沐。", "遥知卧鴟夷，獨酌慰齋宿。", "云誰可與飲，鄰有三不速。", "篇卷正沉迷，當以從事趣。"]'),
('68b9d31c-e428-4b22-a0b6-f3f1d9d4c05d','次韵答翟公巽見戲','慕容彥逢','宋','宋诗','song-poetry','','[]','鞘中長鋏鳴，將軍出天山。',72,'全唐诗/poet.song.73000.json','["鞘中長鋏鳴，將軍出天山。", "前驅七萃士，鐵衣照朱顔。", "萬馬飲瀚海，丸泥封玉關。", "何必學孫吳，功成談笑間。", "西顧浄無塵，仰視太白閒。", "歸來佐天子，坐使淳風還。"]'),
('eaeaa717-8848-43bc-8f0d-835c3a5dbd96','贈明智大師','慕容彥逢','宋','宋诗','song-poetry','','[]','上人真法器，根性宿明悟。',96,'全唐诗/poet.song.73000.json','["上人真法器，根性宿明悟。", "閱書一再過，覆誦絕遺誤。", "教乘浩無涯，秋毫析紛互。", "援證窮理窟，辭源百川注。", "曉堂列圓頂，瞻仰祛未晤。", "執熱濯清風，中痟飲甘露。", "瑩如壺中冰，潔如機上素。", "鱗角雖出羣，豹文方隠霧。"]'),
('cd1efdb6-4a5f-4723-a0f8-5c1a8558d099','送安宣義還雒陽','慕容彥逢','宋','宋诗','song-poetry','','[]','學省無吏窘，官穩如林丘。',120,'全唐诗/poet.song.73000.json','["學省無吏窘，官穩如林丘。", "寮寀得之子，一語消百憂。", "虀鹽對晨餉，菘韭餘時羞。", "淡薄本同適，言歸異初謀。", "親庭奉喜慶，退有園池幽。", "樂事迺如此，攬執安肯留。", "塵區饒滯念，役役無時休。", "沖襟得高躅，視身等虛舟。", "嵩少多逸士，盍往從之遊。", "相見試舉似，此語頗勝不。"]'),
('78123420-6ea8-4db0-a1c2-d02f975c0b9c','送趙節推沿檄還鄉','慕容彥逢','宋','宋诗','song-poetry','','[]','蠶月舒以長，麥天和更清。',144,'全唐诗/poet.song.73000.json','["蠶月舒以長，麥天和更清。", "初荷吐香芽，新蒲生紫英。", "濟濟幕中客，眉間黄生明。", "膏車指鄉國，言歸奉壽觥。", "上堂拜嘉慶，喜雨淪飛甍。", "斑衣學古戲，芳蘭逗春榮。", "世態今猶昔，萬緒水火爭。", "奔馳浪自苦，心胸沸庖烹。", "賢哉吾景崇，養志輕利名。", "效官求便郡，晨暮請安平。", "茲行天所佳，祥烟送曉征。", "要當感星聚，豈徒資月評。"]'),
('d3196d6c-aeb1-4021-8873-8067cbcff309','送曾正直','慕容彥逢','宋','宋诗','song-poetry','','[]','往歲別君去，匆匆殊未饜。',120,'全唐诗/poet.song.73000.json','["往歲別君去，匆匆殊未饜。", "來茲諧宿願，一笑忘虀鹽。", "俛仰復去我，促裝難暫淹。", "重江逼潮信，掛席程欲兼。", "諸暨號繁劇，牒訴紛黎黔。", "君才古循吏，公庭耿秋蟾。", "借留適民願，坐變六凉炎。", "政術久彌勵，謠頌喧閭閻。", "朝廷方籲俊，延訪降宸嚴。", "行矣决顯用，此理君奚占。"]'),
('1240cc01-d299-48c9-b62e-7fc5c2a4ab9b','李縣丞美替作此詩餞之','慕容彥逢','宋','宋诗','song-poetry','','[]','東陽見夫子，格調駭心目。',84,'全唐诗/poet.song.73000.json','["東陽見夫子，格調駭心目。", "相逢恨不早，請違何太速。", "咄咄空中字，便便榻間腹。", "暫留腸九回，言歸日三卜。", "到家樂應顛，登舟喜堪掬。", "題橋釋舊誓，彈冠俟新沐。", "偃蹇何足嗟，君看松與竹。"]'),
('2a2974a4-2649-4b81-9e19-f1a0b2dca834','友人有小石數顆以余酷愛將輟惠佳者唯求一詩賦以贈之','慕容彥逢','宋','宋诗','song-poetry','','[]','公子有佳石，丹碧非一狀。',84,'全唐诗/poet.song.73000.json','["公子有佳石，丹碧非一狀。", "磊磊不盈掬，巧奪三山狀。", "貯以白玉斗，挹注秋滉瀁。", "有如澄江浄，隠映朝霞上。", "泮林官獨冷，悅此助清曠。", "唯求詩句易，於焉窺雅尚。", "山陰昔換鵝，流傳信非妄。"]'),
('9949b7e7-dcd2-46ab-8a37-d57f4c601603','同呂文剛吳邦獻馬子才賦白菊得采字','慕容彥逢','宋','宋诗','song-poetry','','[]','紅紫春爭妍，那復俟秋宰。',120,'全唐诗/poet.song.73000.json','["紅紫春爭妍，那復俟秋宰。", "茲花如端人，凌飆振輝彩。", "英英剪輕雲，粲粲絡珍琲。", "天清月色留，日淡霜華在。", "高標比松竹，芳氣壓蘭茝。", "飄零飫夕餐，韡韡富晨采。", "中有神仙滋，收功逸而倍。", "調丹雜樗楮，服之毋豫怠。", "能駐好容顔，延齡向千載。", "事著抱朴書，劉生豈予紿。"]'),
('e61ec019-db52-46ca-9b42-ea36b17c7115','次韵張察推詠密印竹軒','慕容彥逢','宋','宋诗','song-poetry','','[]','衛尉才豪雖卓絕，溺志奢淫愧明哲。',160,'全唐诗/poet.song.73000.json','["衛尉才豪雖卓絕，溺志奢淫愧明哲。", "羅綺叢中醉復醒，趁拍佳人不成列。", "黄門侍郎天機深，傲世忘榮事高潔。", "侯印公主不解顔，好竹之心了無節。", "紛華必竟致青螺，恬澹有誰賡白雪。", "此君佳致識者稀，千古清風與明月。", "高僧欲現菩提心，種竹滿軒功未徹。", "嬋娟人共得觀臨，蕭瑟師當知演說。", "率然相造師勿嗔，勝遊本爲吾僧設。", "對君不惜洛生吟，更待詩酣歌一闋。"]'),
('19c620da-9a3f-4326-8d5e-3c14299a8839','次韵鮮于學錄太一宮海棠','慕容彥逢','宋','宋诗','song-poetry','','[]','巍巍樓觀神君宅，晝鎖眠魚斷人迹。',160,'全唐诗/poet.song.73000.json','["巍巍樓觀神君宅，晝鎖眠魚斷人迹。", "囂塵不到春自濃，海棠繞砌花如織。", "日窺絳彩艷朝霞，露浥芳苞點靈液。", "枝侵香霧拂桁梧，乘風欲鬭蜿虹赩。", "都城三月賞花天，爭騁纖驪并赭白。", "廣文官冷苦無悰，偶到殊庭欣有得。", "嬌嬈初值欲開時，迴視羣葩澹無色。", "許昌風雅譏少陵，玉壘繞山夸蜀客。", "豈知移根古壽宮，瑶草華枝伴蕃殖。", "雨餘濃麗應更妍，負賞牽吟心未息。"]'),
('a5af6609-daac-409b-9a8b-5d542528223c','赴省試到闕偶成','慕容彥逢','宋','宋诗','song-poetry','','[]','去年隋隄一丈雪，雪路苦寒那可行。',128,'全唐诗/poet.song.73000.json','["去年隋隄一丈雪，雪路苦寒那可行。", "行人畏寒兼畏滑，滿蹊堅冰如鑑明。", "行裝人與馬成二，身不自惜旁人驚。", "崎嶇千里到京闕，痛定回思雙淚傾。", "伊予少小親翰墨，應敵豈解前無勍。", "今者西來皆計吏，妄與羣俊爭文鳴。", "無田歸耕曷爲養，得失未易秋毫輕。", "作歌聊用寫情素，擁鼻微吟同洛生。"]'),
('91737454-0f9d-4832-81de-b7d1995a318f','蘭溪葉宰以某阻水治山頂僧舍見邀作此詩以謝','慕容彥逢','宋','宋诗','song-poetry','','[]','月輪一夜離天畢，山川吐雲翳朝日。',144,'全唐诗/poet.song.73000.json','["月輪一夜離天畢，山川吐雲翳朝日。", "飛廉吼空馳霹靂，雨勢霶𩃱兩溪溢。", "橫流不復相望軼，浪花飛起三千尺。", "我時艤舟酣戰慄，眼看民居半沉溺。", "邑令之賢誰等匹，爲治公居寄家室。", "顧盼奔濤心暇逸，寓居恰倚青山脊。", "吁嗟此驚身未歷，折腰遠來甘恐惕。", "餐霞先生今鎩翼，附郭相君無所食。", "愁霖謝子雖非敵，少宦徐郎良未懌。"]'),
('843586ff-399a-4615-a8be-bfc69770ad4a','和岑運使題趙吏部容膝齋詩','慕容彥逢','宋','宋诗','song-poetry','','[]','公不見金谷樓臺插寥廓，珠璣映出琉璃薄。',246,'全唐诗/poet.song.73000.json','["公不見金谷樓臺插寥廓，珠璣映出琉璃薄。", "滿甑青螺甲第空，富貴回頭驚旅泊。", "又不見淵明三徑似元卿，藍縷茅簷僅容著。", "心知侈汰非遠謀，寄傲南窗安所託。", "二子薰蕕古至今，遺臭傳芬皆自作。", "中郎天機湛秋水，涵泳源流潄芳酌。", "小齋容膝思易安，顧盼俗緣嗟自縛。", "琴書對眼助清閑，杖履從人笑疏略。", "紅塵一點不到處，只許爐香度帷箔。", "吁嗟淡靜世所艱，此味要之屬丘壑。", "能以膏粱甘寂寥，道德高風信玄邈。", "真長標置自非凡，區區乃念東山樂。", "見嗤逸少固所宜，詎識此生如寄殻。", "會須掩關友松菊，俗子扣門從剝啄。", "揮殘麈尾雖可佳，弄絕韋編良不惡。"]'),
('93af919a-ee64-40c8-aa0e-70163070a670','爲陳秀才題墨妙堂','慕容彥逢','宋','宋诗','song-poetry','','[]','寶池當几潤滑并，蟾蜍玉竇寒泉傾。',224,'全唐诗/poet.song.73000.json','["寶池當几潤滑并，蟾蜍玉竇寒泉傾。", "墨花泛泛花脚輕，雲牋皎皎月色明。", "凝然嗣將先管城，一掃神怪吁難名。", "騰龍舞鳳相回縈，倒日翻星草隸行。", "或如懸崖倚孤撐，又如脫兔馳萬兵。", "猿攀虎怒勢爭鯨，奔蜃駭駛波浪驚。", "篆斯隸邈草伯英，鍾蔡衛索更品評。", "逸少兼之集大成，寥寥千載無與京。", "鼠鬚蠶繭秘跡清，玉華遺言同誓盟。", "埋藏不計申與庚，模蹤間出相光晶。", "太丘佳士天氣清，訪求寶字金滿籯。", "編聯軸卷紛縱橫，名家諸妙皆有聲。", "文餘高致超八閎，深求衆法窺忘情。", "會當臨池染澄瀛，銀鈎萬字揮崢嶸。"]'),
('f4d36be9-fc2d-4e8c-a5c0-164578cde5d2','送葉朝奉','慕容彥逢','宋','宋诗','song-poetry','','[]','夫君才調天所旌，胸襟洞然秋月明。',152,'全唐诗/poet.song.73000.json','["夫君才調天所旌，胸襟洞然秋月明。", "兩以文章對集英，老拳再中匠者驚。", "割鷄已詠劉江陵，盤根錯節君所輕。", "斷蛟剸割無能攖，懿效翹然宜彙征。", "列章論薦仁且明，炎凉三歲歌有成。", "千室不放休車行，斑衣歸學嬰兒聲。", "靈椿丹桂芬芷蘅，上堂獻壽樂事并。", "餘歡洽比賦丁丁，我之別兮不識情。", "君之愛我勤且誠，祝君轉飛九萬程，男兒功業貴崢嶸。"]'),
('90137ba7-43c0-4aac-80bc-bd3975343ff5','上毛運使','慕容彥逢','宋','宋诗','song-poetry','','[]','人各有求心靡同，世路奔馳如捕風。',291,'全唐诗/poet.song.73000.json','["人各有求心靡同，世路奔馳如捕風。", "我獨不願萬戶封，悁悁所願識毛公。", "我公高才真國器，醖藉聰明天所秘。", "子師氣格千里駒，廣基文章一枝桂。", "學優入仕斯義榮，我公所至皆可稱。", "來暮已歌廉叔度，去思還似謝吳興。", "天心憂勤念方面，外臺遴選皆英彥。", "我公所至綽有聲，炯炯精金經百鍊。", "昨夜使星入斗牛，鵲聲曉送傳書郵。", "報言有詔下天闕，公按濱江十四州。", "審報已真驚且喜，入戶不知摧屐齒。", "拜塵潘子行有緣，倒屣蔡公何敢擬。", "自嗟此誠今未通，何時垂翅附冥鴻。", "眉間黄色已可慶，襟懷不復歎秋蓬。", "公不見張華一賦致高位，阮瞻三言得清議。", "刻畫無鹽雖有心，滓穢太清徒自愧。", "朝廷言路方坦夷，比年漢詔下天墀。", "所念淵明方爲米，會須平子爲玄題。"]'),
('bc54bf49-2a5c-4fe9-a9e5-b732047a0a33','答王及之賢良見寄','慕容彥逢','宋','宋诗','song-poetry','','[]','公圭侯印人所優，利鎖名韁吾所羞。',224,'全唐诗/poet.song.73000.json','["公圭侯印人所優，利鎖名韁吾所羞。", "耿耿有懷非隠憂，思得佳士從之游。", "今年折腰來佐縣，辭采接君心自見。", "懷刺過尋不問程，剝啄扣關諧所願。", "誰云白首交如新，傾蓋相逢如故人。", "囊中製作絕倫類，和璧隋珠無足珍。", "心醉歸來書文室，却怪前宵夢椽筆。", "至音寂寞知者稀，安得論文永足日。", "可嗟吏道事奔馳，信信不見元紫芝。", "胸襟不復憂鄙吝，圓緘寄我愁霖詩。", "得詩三復雲牋卷，喜氣填膺光滿面。", "一首能輕萬戶侯，綠髮幸交三語掾。", "我今爾耳何爲哉，汗漫如君心自灰。", "爲君挹盡雙溪水，不發纖塵污兩耳。"]'),
('dff27b1b-d47d-4d7a-bc80-81e5b68b4de2','醉歌行次韵','慕容彥逢','宋','宋诗','song-poetry','','[]','嘗聞醉鄉之樂真且全，青州從事鄉之賢。',210,'全唐诗/poet.song.73000.json','["嘗聞醉鄉之樂真且全，青州從事鄉之賢。", "盃鐺三百沃軒曠，眼看萬有心陶然。", "平生不識飲中趣，糟漿逆鼻憂頹顛。", "捧甖徒知詠酒頌，側弁未始陪賓筵。", "丈人襟懷湛秋水，塵埃滌盡中恬淵。", "美哉家釀藏之久，誓可與飲無留涓。", "宴開設此杯中物，意如割炙何勤虔。", "歡誠感激忘既醉，是日飲興輕金船。", "房櫳蠶老舒長晝，郊野麥秀清和天。", "主人放懷客盡量，談間標韵凌雲烟。", "醉歌耳熱匪吾事，兩腋清風同玉川。", "願言乘茲騰倒景，清都謁帝羅羣仙。", "酒闌逸思不可遏，筆端詩句如奔泉。"]'),
('ae2821b7-b64b-4f1a-a083-7dfe15b436a3','求畫','慕容彥逢','宋','宋诗','song-poetry','','[]','伯父有畫美且都，丹青彷彿顔色渝。',224,'全唐诗/poet.song.73000.json','["伯父有畫美且都，丹青彷彿顔色渝。", "塵埃漬漬相染污，惟有筆畫存規模。", "隔步看之有若無，想像人物淪烟蕪。", "刲羊刺鹿皆糢糊，皮毛狼籍血盤盂。", "巨索懸鼎地爲爐，薪火炎炎勝西隅。", "庖人握刀盼精麤，几上獸肉縱橫鋪。", "中有一人與衆殊，戴帽被甲腰屬鏤。", "昂藏形貌長髭鬚，眼看手指如典徒。", "一奴禿首携酒壺，酌之飲衆蘇勞痡。", "衆人得酒停烹屠，延頸飲之舉兩腢。", "有壇數級如闉闍，壇側毅然一武夫。", "負弓韜矢手執殳，左右不敢肆闞𨵦。", "此是胡中祭天圖，故應先日事庖厨。", "微生見之嘗覬覦，好之不啻千金姝。"]'),
('daa43f7d-2aaf-448f-9668-e39a6b952867','贈宗室順國軍節度使開府儀同三司仲公','慕容彥逢','宋','宋诗','song-poetry','','[]','儀比公槐峻，恩分將鉞華。',48,'全唐诗/poet.song.73000.json','["儀比公槐峻，恩分將鉞華。", "楚詩能教子，沛易自名家。", "較藝聯千佛，藏書閱五車。", "風猷齊往哲，豈謂史臣誇。"]'),
('f7dcbc90-bf92-492a-9233-97c53cf684d4','挽贈開府儀同三司朱公二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','戚畹聯榮久，三朝慕遇隆。',48,'全唐诗/poet.song.73000.json','["戚畹聯榮久，三朝慕遇隆。", "身雖居寵貴，志益守謙沖。", "聞譽揚中外，哀榮備始終。", "新阡標氏族，官是漢儀同。"]'),
('42095e1c-d791-4df9-999a-887d9b2de437','挽贈開府儀同三司朱公二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','襄事涓辰吉，華旌拂曉參。',48,'全唐诗/poet.song.73000.json','["襄事涓辰吉，華旌拂曉參。", "車輿尊廣陌，宅兆指遥岑。", "寂寂泉扃閟，冥冥隧路深。", "堪傷純孝子，揮淚血霑襟。"]'),
('7382cf5e-0a49-485d-884b-8563314d9fe1','挽祕閣校理知湖州余使君二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','桂籍冠羣英，驚人在一鳴。',48,'全唐诗/poet.song.73000.json','["桂籍冠羣英，驚人在一鳴。", "遡風淹鷁路，擊水失鵬程。", "已協三刀夢，空嗟五鼓聲。", "惟應文苑傳，不愧史臣評。"]'),
('dc387465-f0b7-42af-825e-3dbd222a58b3','挽祕閣校理知湖州余使君二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','惟昔都門別，于今歲屢更。',48,'全唐诗/poet.song.73000.json','["惟昔都門別，于今歲屢更。", "周旋如昨日，慷慨敘平生。", "短牘方傳鯉，長歌未報瓊。", "仁賢何太嗇，此理信誰明。"]'),
('73d82ca0-32cd-4bf1-88de-108d94302f2d','和劉著作偉明貢院即事韵','慕容彥逢','宋','宋诗','song-poetry','','[]','簪紱千齡會，朝廷百度明。',288,'全唐诗/poet.song.73000.json','["簪紱千齡會，朝廷百度明。", "規摹追古治，符瑞協炎精。", "九敘民歌遂，三階夜彩平。", "秉文稱濟濟，樂育詠菁菁。", "經術漸摩久，人材長養成。", "禮闈參衆聽，文鑒肅羣情。", "預貢觀能吏，來游盡碩生。", "胸襟窮底藴，頭角競崢嶸。", "蔌蔌珠璣墮，喧喧虎豹爭。", "氣衝牛斗動，詞感鬼神驚。", "收視疑無我，湛思詎有聲。", "袍紛晨霧委，幘岸宿雲橫。", "納試庭除晚，遄歸步武輕。", "身雖同脫鞅，心亦類摇旌。", "三級看鱗化，千金想睇迎。", "膏粱搜衛霍，行伍擢韓英。", "巧思憐金注，塵言沮海行。", "正迷花錦亂，忽睹玉壺清。", "奧義窺儒寢，純音發帝莖。", "鉛刀慚利割，瓦釜失虛鳴。", "已奏青錢選，初聞白雪賡。", "句從天外得，思與海同傾。", "相對一杯酒，當前二尺檠。", "詩壇瞻宿將，筆陣却驍兵。"]'),
('e379e44b-5129-4d60-ade7-37d257817a60','蔣穎叔生日','慕容彥逢','宋','宋诗','song-poetry','','[]','宗派源流遠，家聲竹帛垂。',240,'全唐诗/poet.song.73000.json','["宗派源流遠，家聲竹帛垂。", "靈暉鍾嶽瀆，吉夢襲熊羆。", "夙擅鄉評美，尋膺國士知。", "文章追往哲，學識判羣疑。", "試若穿楊葉，科如摘頷髭。", "繡衣趨觀闕，霜簡照軒墀。", "諫拂龍鱗逆，身探虎穴危。", "忠猷聳鴛鷺，直氣懾狐狸。", "要路淹風鷁，丹心比日葵。", "使臺專漕輓，帥閫肅邊陲。", "久鬰公台望，初還輦轂時。", "缿筩爭訟息，囊櫜寇攘衰。", "蓮炬驚宵漏，花磚候曉曦。", "暫分方面寄，復演禁林詞。", "廊廟先圖任，樞衡遂倚毗。", "雍容承晝接，密勿奉疇咨。", "已冠中樞府，猶虛百斛姿。", "兩轓將畫鹿，五總舊名龜。", "儒效流弦吹，王功鏤鼎彝。", "更增箕翼壽，餘慶在庭芝。"]'),
('09ab0613-e451-4cf9-b189-228532537fff','許沖元生日','慕容彥逢','宋','宋诗','song-poetry','','[]','良月當初吉，昌時叶半千。',288,'全唐诗/poet.song.73000.json','["良月當初吉，昌時叶半千。", "氣鍾奎壁粹，壽稟角亢全。", "殖學優前哲，香名自妙年。", "文章魁桂籍，風采冠櫻筵。", "要路諧先據，清班閱屢遷。", "芸書讎甲乙，黼坐謁溫宣。", "丹陛趨文石，彤庭詠綺錢。", "雲梯滋穩步，風翮正孤騫。", "清切陪華蹕，雍容進邇聯。", "夜歸驚寶燭，曉直候花磚。", "餘力兼京輔，能聲映簡編。", "寇清桴鼓絕，訟息缿筩捐。", "入謝雖言邁，徂齊遽式遄。", "詞林俄再入，政轄遂詳延。", "鯁議違時去，丹心許國堅。", "賜環朝帝所，曳履上星躔。", "樞憲仍圖舊，巖廊慶得賢。", "珥璫鸞渚上，鳴佩鳳池邊。", "默識通倫類，先幾炳眇綿。", "龍輈迎舜日，鼇柱拱堯天。", "夾轂占轓鹿，飛冠兆冕蟬。", "鶴齡偕集木，龜算等巢蓮。", "丙魏君臣契，韋平父子傳。", "功成五福具，永作地行仙。"]'),
('e6b47239-6d6f-4c8d-98c5-a5c5ba1bc1e2','恭和元日受寶詩二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','聖主規模冠百王，考茲秦寶欲更張。',64,'全唐诗/poet.song.73000.json','["聖主規模冠百王，考茲秦寶欲更張。", "玉因天授來殊域，工與神謀軼舊章。", "羣辟竦觀稱萬壽，廣廷昭受襲多祥。", "宸慈特紀千齡遇，詩似奎躔夜吐光。"]'),
('631799e3-6175-4f17-ad2f-c081efcb5cd9','恭和元日受寶詩二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','層墀班序列華紳，萬歲聲中八寶陳。',64,'全唐诗/poet.song.73000.json','["層墀班序列華紳，萬歲聲中八寶陳。", "映日浮筠盈黼座，如虹佳氣繞楓宸。", "珍符休顯光圖牒，惠澤汪洋浹士民。", "天佑聖神方錫羨，從茲諸福與詩新。"]'),
('0ae72b00-8b24-49ba-a4ca-d176c6ee51bb','恭和御製回鑾詩二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','日轉蓬瀛詔蹕歸，晚陰風色倍清微。',64,'全唐诗/poet.song.73000.json','["日轉蓬瀛詔蹕歸，晚陰風色倍清微。", "從教小雨霑花潤，不放纖塵傍輦飛。", "萬井歡心陪盛觀，盈塗嘉頌紀鴻徽。", "時和歲稔民同樂，古昔昇平似此稀。"]'),
('23ab4a0f-c70e-45b0-9c1b-7678901060c3','恭和御製回鑾詩二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','十萬宮花簇馬歸，宜秋門道晚陰微。',64,'全唐诗/poet.song.73000.json','["十萬宮花簇馬歸，宜秋門道晚陰微。", "雲隨香霧相縈去，塵傍珠韉不敢飛。", "盛事傳爲堯壤頌，薰風催入舜琴徽。", "年年池苑春如許，天子持盈燕幸稀。"]'),
('1cba1259-9954-4e60-80dd-e6c8c541b6c0','恭和御製幸池詩','慕容彥逢','宋','宋诗','song-poetry','','[]','乘時遊豫屬皇明，芝蓋重臨太液清。',64,'全唐诗/poet.song.73000.json','["乘時遊豫屬皇明，芝蓋重臨太液清。", "鵷鷺舊臣稱壽斝，魚龍嘉戲出僊瀛。", "長堤映柳千門啟，翠水涵空一鑑平。", "天意自同民意樂，無知草木解欣榮。"]'),
('43ffbe15-9a27-415d-9f7c-0007212abd50','恭和御賜陽德觀碧桃溪新竹詩','慕容彥逢','宋','宋诗','song-poetry','','[]','三千迸籜拂朝雲，想見坤祇夜駿奔。',64,'全唐诗/poet.song.73000.json','["三千迸籜拂朝雲，想見坤祇夜駿奔。", "嶰谷掄材聞古帝，桃溪呈瑞屬神孫。", "如犀亟應絲綸命，带粉初縈雨露痕。", "欲測九重宸算永，會須億萬數靈根。"]'),
('323f15c5-3c6b-484b-92c3-ccc16f61c886','恭和御製朵樓特宴之什','慕容彥逢','宋','宋诗','song-poetry','','[]','東闕岧嶢宴特頒，樓前寶燭萬星寒。',64,'全唐诗/poet.song.73000.json','["東闕岧嶢宴特頒，樓前寶燭萬星寒。", "鼓聲泛樂鼉靈震，鑪篆回風翠鳳盤。", "積有嘉祥占歲稔，寵因芳夕慶時安。", "厭厭既醉君恩重，歸路繁華緩轡看。"]'),
('59a95449-aec2-42cb-acea-c7ad55ff06ad','次韵祝通直甘露詩二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','聖心天意兩無違，露灑文昌若應機。',64,'全唐诗/poet.song.73000.json','["聖心天意兩無違，露灑文昌若應機。", "甘自蜜房分瑞液，瑩疑蟾窟借圓輝。", "遍裝叢柳春爭麗，高應晴空午不晞。", "豈止臣民胥鼓舞，故應殊裔亦心歸。"]'),
('7de408f2-9bf4-486f-b2e4-15943c72b255','次韵祝通直甘露詩二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','露液無聲降自天，清英含味滿丘園。',64,'全唐诗/poet.song.73000.json','["露液無聲降自天，清英含味滿丘園。", "日中垂溜真珠落，風後寒澌雜珮翻。", "呈瑞未央曾紀歲，襲芬儀鳳亦更元。", "廣寒應德彰嘉祉，臣子相看眉宇軒。"]'),
('37bf972d-2754-4d62-aa59-b7e8d3e9e1de','恭和御製以節近嘉平時雪驟應詩','慕容彥逢','宋','宋诗','song-poetry','','[]','翳翳同雲結晚陰，六花宵降聳瑶林。',64,'全唐诗/poet.song.73000.json','["翳翳同雲結晚陰，六花宵降聳瑶林。", "一犂共慶農疇足，四海安知帝力深。", "陽位涓成初奠玉，真祠昭謝正齋心。", "况當節紀嘉平近，時雪時暘自溥臨。"]'),
('1886c78b-5941-4672-b909-3763f3ee411b','恭和御製元會之次日嘉雪應候錫宴於公相之第詩','慕容彥逢','宋','宋诗','song-poetry','','[]','三元盛禮冠年華，翼日朝隄雪覆沙。',64,'全唐诗/poet.song.73000.json','["三元盛禮冠年華，翼日朝隄雪覆沙。", "端爲聖時調玉燭，故當餘臘雨天花。", "萬箱占瑞民胥慶，青輅迎春節尚遐。", "錫宴賜詩知有喜，自應和氣浹潜芽。"]'),
('ac74e13c-4706-421d-9860-82907e181ca6','恭和御製以嘉雪愆候躬致懇禱精意上孚靈貺昭格己卯庚辰降雪盈尺賜相臣詩二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','皇心閔雪正傾祈，盈尺呈祥靡願違。',64,'全唐诗/poet.song.73000.json','["皇心閔雪正傾祈，盈尺呈祥靡願違。", "潤浹土膏占歲稔，和生民氣敵鑪輝。", "千門瓊瓦連雲聳，九陌瑶花撲面飛。", "聖德格天超曠古，更須宸翰述沉幾。"]'),
('0552862e-6fe4-4ced-8d4e-f00fc19f7475','恭和御製以嘉雪愆候躬致懇禱精意上孚靈貺昭格己卯庚辰降雪盈尺賜相臣詩二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','嘉平紀月近正端，時雪時暘軫念寬。',64,'全唐诗/poet.song.73000.json','["嘉平紀月近正端，時雪時暘軫念寬。", "雲色乍收銀闕角，月華徐轉綵旂竿。", "映階積素光相射，迎吹餘花舞向闌。", "最是三農知歲樂，歡欣無復歎祁寒。"]'),
('b6891a5a-f5cb-46d0-88ea-6a4db52ac4b5','恭和御製喜雪','慕容彥逢','宋','宋诗','song-poetry','','[]','需宴宸章次第頒，祥霙宜入詠歌間。',64,'全唐诗/poet.song.73000.json','["需宴宸章次第頒，祥霙宜入詠歌間。", "心知旦暮千齡遇，目睹聲詩六義還。", "治格雨暘皆順序，慶均朝野共怡顔。", "微臣叨預承恩列，賡和才菲若負山。"]'),
('34c6bfaf-2211-4449-aa54-568d2f6a4837','恭和御製觀儺詩','慕容彥逢','宋','宋诗','song-poetry','','[]','日近新正臘已殘，鼕鼕儺鼓響晴寒。',64,'全唐诗/poet.song.73000.json','["日近新正臘已殘，鼕鼕儺鼓響晴寒。", "神資颯爽來羣祀，舞節蹁躚應七盤。", "門磔交修邦典備，物疵銷盡里民安。", "欲知聖主憂勤意，深拜宸章仔細看。"]'),
('6948acde-6398-4779-8856-96a57927da1d','次韵和吳右丞恭覽神宗皇帝御集詩','慕容彥逢','宋','宋诗','song-poetry','','[]','永裕規橅映萬春，孝思今見聖心循。',64,'全唐诗/poet.song.73000.json','["永裕規橅映萬春，孝思今見聖心循。", "仁言盡集絲綸舊，細札初刊琬琰新。", "盛比鈞天張九奏，麗如華衮繪三辰。", "邇僚拜賜榮懷甚，亦輟餘編寵諫臣。"]'),
('0028e68c-ce51-40df-9391-fb4f5abfa7a2','次韵伯父元夕有感','慕容彥逢','宋','宋诗','song-poetry','','[]','往歲元宵寓帝京，天光黯淡雪奔騰。',64,'全唐诗/poet.song.73000.json','["往歲元宵寓帝京，天光黯淡雪奔騰。", "揚鑣公子羅千騎，隨計書生對一燈。", "舊事悠悠頻入夢，新愁鬰鬰更填膺。", "低頭懶看南軒月，撥盡爐灰對好朋。"]'),
('042ffd9e-250c-4400-b271-a4eecb19ec8f','試燈日侍親遊戒珠寺','慕容彥逢','宋','宋诗','song-poetry','','[]','雪花新霽玉雲閒，慶侍來遊古蕺山。',64,'全唐诗/poet.song.73000.json','["雪花新霽玉雲閒，慶侍來遊古蕺山。", "稅駕且需明月上，捧觴徐戲綵衣還。", "樓臺燈火青冥外，市井笙歌縹緲間。", "膝下歡娛誰與共，棣華相對醉酡顔。"]'),
('250cb33b-1351-4fb3-bd14-16e9daab9e0b','和中書梁侍郎君臣慶會閣賜御筵詩','慕容彥逢','宋','宋诗','song-poetry','','[]','巍巍層閣倚雲開，閣上書從帝所來。',64,'全唐诗/poet.song.73000.json','["巍巍層閣倚雲開，閣上書從帝所來。", "率土士民瞻慶會，華筵樽俎幸參陪。", "宸文正比天文麗，春力應隨筆力回。", "主聖臣賢千載遇，欲形歌頌愧非才。"]'),
('026fda73-7234-4106-98d7-0a1d0de9d3e1','和中書梁侍郎喜雪賜御筵詩','慕容彥逢','宋','宋诗','song-poetry','','[]','康莊雪景曜重關，宴錫潭潭府第間。',64,'全唐诗/poet.song.73000.json','["康莊雪景曜重關，宴錫潭潭府第間。", "愛日似隨人意出，祥風時泛樂聲還。", "歡謠已見喧民俗，喜氣遥知動帝顔。", "溫詔許持金斝醉，戴恩同祝壽如山。"]'),
('9fa564df-0d04-4638-98be-7af73880ff3d','和蔣秀才牡丹次韵','慕容彥逢','宋','宋诗','song-poetry','','[]','如霞如錦色何鮮，映日欹風特地妍。',64,'全唐诗/poet.song.73000.json','["如霞如錦色何鮮，映日欹風特地妍。", "獨占一春疑得勢，平欺羣卉若當權。", "自知麗艷能傾國，須放香苞趁禁烟。", "花市試詢桃李價，從今不直半分錢。"]'),
('c402278d-5932-4b2d-8d83-d1ff1423a5cf','次韵阮承書詠桃花菊六月開','慕容彥逢','宋','宋诗','song-poetry','','[]','怪來籬下欲成蹊，菊似桃花賞客迷。',64,'全唐诗/poet.song.73000.json','["怪來籬下欲成蹊，菊似桃花賞客迷。", "清郁雖同彭澤逕，嬌紅全是武陵溪。", "露沾宿蘂金絲潤，日炙繁英玉葉低。", "占斷春光與秋色，薰風特地與留題。"]'),
('acae2523-e045-41a7-adf0-67b263b47e84','和余秀才遊綠浄堂以詩見寄','慕容彥逢','宋','宋诗','song-poetry','','[]','佳名誰爲牓嶇岑，牽惹詩翁躡屐尋。',64,'全唐诗/poet.song.73000.json','["佳名誰爲牓嶇岑，牽惹詩翁躡屐尋。", "綠外清風先見竹，靜中新囀不妨禽。", "沈酣山水真君事，汩沒文書豈我心。", "待撥頻煩聊一賞，振衣閒坐洛生吟。"]'),
('a0bfbb32-a1fe-4e24-ba06-88b0441fd2ce','次韵題任承事清樂齋','慕容彥逢','宋','宋诗','song-poetry','','[]','塵襟滌盡更無餘，兩字名齋信起予。',64,'全唐诗/poet.song.73000.json','["塵襟滌盡更無餘，兩字名齋信起予。", "物外清標輕紱冕，閒中樂事付琴書。", "蘭生階砌青春好，槐覆門庭過客疏。", "更有孤吟寫幽思，篇成渾似琢璠璵。"]'),
('c7ac9c06-b9ec-4698-b7f4-12c89908204c','詠蔣秀才西軒詩','慕容彥逢','宋','宋诗','song-poetry','','[]','園池佳處闢幽軒，西揖湖光入坐筵。',64,'全唐诗/poet.song.73000.json','["園池佳處闢幽軒，西揖湖光入坐筵。", "藥本自生芳草地，花陰長到夕陽天。", "就閒頗似陶潜逕，適意何須范蠡船。", "此覽清虛有真趣，不勞他境覓林泉。"]'),
('6f1658f3-c7da-435b-9dd6-f3175d03ab1d','和元卿二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','水根山脚最荒凉，子隠頹祠足感傷。',64,'全唐诗/poet.song.73000.json','["水根山脚最荒凉，子隠頹祠足感傷。", "廊廡傾顛春草綠，門庭寂靜野花香。", "聞之自可成酸鼻，見此如何不斷腸。", "追想舊蹤徒悵望，淡烟淺露忽斜陽。"]'),
('a05d70f0-b2b0-4b67-aaff-a2d99f15e7a8','和元卿二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','荆吳豪俊最繽紛，功烈平西自出羣。',64,'全唐诗/poet.song.73000.json','["荆吳豪俊最繽紛，功烈平西自出羣。", "節操不慚張御史，功名終似李將軍。", "安仁句語聊書實，宣佩聲猷更襲芬。", "豈謂千年有遺恨，數間頹屋枕溪垠。"]'),
('cce97cfd-159e-42f8-9088-cd4494ffd5a6','知縣沈奉議所至榜雙清於書室諸公篇詠甚多猥以見屬輒賦四韵','慕容彥逢','宋','宋诗','song-poetry','','[]','燕居隨處榜雙清，借問何修稱此名。',64,'全唐诗/poet.song.73000.json','["燕居隨處榜雙清，借問何修稱此名。", "迹似壺中冰瑩潔，心如潭底月澄明。", "棠陰人散紅塵靜，爐篆香飄翠霧輕。", "不必林泉堪寄傲，林泉雖勝尚關情。"]'),
('e34d948a-ed46-4e6b-ae13-d0977d3a8d3a','和四十伯父見寄二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','入夏情懷轉不中，多愁多病愈乖慵。',64,'全唐诗/poet.song.73000.json','["入夏情懷轉不中，多愁多病愈乖慵。", "匡詩該博終難繼，蔣逕幽閒頗願從。", "頼得古文消日月，更無佳友話心胸。", "吾宗幸有邊經笥，却得時時一叩鐘。"]'),
('1f1cda99-54c3-4f89-bb13-c26f88c725dc','和四十伯父見寄二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','比來維日捧詩筒，久廢吟哦覺懶慵。',64,'全唐诗/poet.song.73000.json','["比來維日捧詩筒，久廢吟哦覺懶慵。", "韵險不容更屬和，意勤須索强隨從。", "深思往往花盈睫，得句常常汗浹胸。", "萬事始知關習否，賡酬本合類撞鐘。"]'),
('63e45076-b452-499e-b0cc-dd1604bc081f','答王賢良見寄仍次元韵','慕容彥逢','宋','宋诗','song-poetry','','[]','一觀清表喜良儔，三惠佳章歎暗投。',64,'全唐诗/poet.song.73000.json','["一觀清表喜良儔，三惠佳章歎暗投。", "已駭談鋒傾海瀆，復驚文怪埒蛇牛。", "敢將晚路輕王述，决有亨途待薛收。", "君欲獻書真得計，我今亦作董生謀。"]'),
('ee8f400c-dc1c-45ac-be39-9b6afebd01f1','遊天章寺陪越帥邵司業京東漕呂侍講通判錢承議行','慕容彥逢','宋','宋诗','song-poetry','','[]','路轉湖天宿霧開，碧霞深處涌樓臺。',64,'全唐诗/poet.song.73000.json','["路轉湖天宿霧開，碧霞深處涌樓臺。", "山川到午晴暉秀，林木先春綠意迴。", "舞鳳寶書藏琬琰，換鵝塵跡鎖莓苔。", "賤遊不畏風霜動，擬看雲尖送月來。"]'),
('a46c6443-4a54-4bf4-97dc-551789c544c6','和彥昇聞更聲','慕容彥逢','宋','宋诗','song-poetry','','[]','蝶夢回來側耳聽，夜深風細轉分明。',64,'全唐诗/poet.song.73000.json','["蝶夢回來側耳聽，夜深風細轉分明。", "嗟予觸物徒勞感，顧爾于人豈有情。", "宰寺樓高聲更遠，楚天霜冷韵何清。", "因茲却憶南軒宿，兄弟之言悉至誠。"]'),
('515f528f-9d36-43cc-acf8-7a9a4a4e20a0','題白沙驛壁','慕容彥逢','宋','宋诗','song-poetry','','[]','未忍歌歸去，行當獻子虛。',24,'全唐诗/poet.song.73000.json','["未忍歌歸去，行當獻子虛。", "自嗟渥洼種，垂耳服鹽車。"]'),
('988fbace-7b2d-4024-babf-91071fd28ece','題婺州道傍水閣','慕容彥逢','宋','宋诗','song-poetry','','[]','勞生成底事，寸祿解縈人。',24,'全唐诗/poet.song.73000.json','["勞生成底事，寸祿解縈人。", "陽羨溪山好，歸歟未有因。"]'),
('755c2446-34cb-45e9-90e0-59ab6155ee4a','留題婺州孝順鎮寺','慕容彥逢','宋','宋诗','song-poetry','','[]','處靜未有計，徒勞真可傷。',24,'全唐诗/poet.song.73000.json','["處靜未有計，徒勞真可傷。", "山僧應笑我，只爲斗升忙。"]'),
('b781394b-1776-4466-9fd5-0e10aa626e38','甲申十一月夢中詠假山','慕容彥逢','宋','宋诗','song-poetry','','[]','欲雨烟雲凝，經秋苔蘚多。',24,'全唐诗/poet.song.73000.json','["欲雨烟雲凝，經秋苔蘚多。", "憑君莫拋擲，留取伴吟哦。"]'),
('114df828-6698-4d8c-822b-1a5e8d4749d1','和王推官正月十三日遊戒珠寺竹軒詩二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','誰種篔簹翠掃天，擬將風月度流年。',32,'全唐诗/poet.song.73000.json','["誰種篔簹翠掃天，擬將風月度流年。", "當軒便是真如境，到岸何須般若船。"]'),
('7ee1a571-d3a8-4df3-8671-b55f2f09af5c','和王推官正月十三日遊戒珠寺竹軒詩二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','積雪滿山寒不釋，碧琅玕遶玉樓臺。',32,'全唐诗/poet.song.73000.json','["積雪滿山寒不釋，碧琅玕遶玉樓臺。", "林梢清韵風吹到，簷底疏陰月送來。"]'),
('bbc81175-1ed1-4014-a9dc-131390af4156','貢院即事  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','自崇寧癸未叨備從班，距今十有四年間。',31,'全唐诗/poet.song.73000.json','["自崇寧癸未叨備從班，距今十有四年間。", "五知貢舉，文官花在試廳前。"]'),
('11bb58c6-09f7-4cf5-b4dd-9392e9a7f4dc','貢院即事  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','文官花畔揖羣英，紫案香焚曉霧橫。',32,'全唐诗/poet.song.73000.json','["文官花畔揖羣英，紫案香焚曉霧橫。", "十四年間五知舉，粉牌時拂舊題名。"]'),
('723200bb-c131-407b-b5b3-ef829b7c31ab','醴泉觀宿齋詩','慕容彥逢','宋','宋诗','song-poetry','','[]','昔陪清蹕款靈真，曾對疏篁縯帝綸。',32,'全唐诗/poet.song.73000.json','["昔陪清蹕款靈真，曾對疏篁縯帝綸。", "十載重來渾似舊，惟應雙鬢二毛新。"]'),
('0740ab0f-0a5f-4ab6-a9e5-b039b907a044','月夜偶成示翟公巽二首  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','一杯誰與細論文，對影成三更此君。',32,'全唐诗/poet.song.73000.json','["一杯誰與細論文，對影成三更此君。", "却憶當年少陵客，空吟春木與江雲。"]'),
('3db81ab8-e2dc-4e26-abb9-27b19c10e548','月夜偶成示翟公巽二首  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','非關色相與聲聞，此意如何舉似君。',32,'全唐诗/poet.song.73000.json','["非關色相與聲聞，此意如何舉似君。", "真馬不須鞭影露，本來誰道有迷雲。"]'),
('90a1a1b0-41db-40c8-9902-c4d1357f29da','和兵部何侍郎宜香閨五絕  其一','慕容彥逢','宋','宋诗','song-poetry','','[]','香如雲彩出無心，一室初凝畫舫深。',32,'全唐诗/poet.song.73000.json','["香如雲彩出無心，一室初凝畫舫深。", "靜對氛氳永終日，誰知真相在清襟。"]'),
('f0b4446f-a0a5-4315-8c66-a2c0f59a8cb2','和兵部何侍郎宜香閨五絕  其二','慕容彥逢','宋','宋诗','song-poetry','','[]','夕薰猶泛絳紗中，曉炷重添翠遶空。',32,'全唐诗/poet.song.73000.json','["夕薰猶泛絳紗中，曉炷重添翠遶空。", "欲識芬芳何所似，百花叢裏度香風。"]'),
('a05322ac-03fa-40e5-8082-60d9475b1d0c','和兵部何侍郎宜香閨五絕  其三','慕容彥逢','宋','宋诗','song-poetry','','[]','暗窗日色鑒重幃，香霧橫襟進講歸。',32,'全唐诗/poet.song.73000.json','["暗窗日色鑒重幃，香霧橫襟進講歸。", "西學尚賢恩禮重，惟將經術贊沈幾。"]'),
('21a73f58-1d51-4862-9ac3-8984a61ee2be','和兵部何侍郎宜香閨五絕  其四','慕容彥逢','宋','宋诗','song-poetry','','[]','鄉賦蒙收一日長，文闈恩地自宗房。',32,'全唐诗/poet.song.73000.json','["鄉賦蒙收一日長，文闈恩地自宗房。", "摳衣獲造芝蘭室，猶認當年月桂香。"]'),
('80807c57-6ed3-46c3-ae38-944d1a954602','和兵部何侍郎宜香閨五絕  其五','慕容彥逢','宋','宋诗','song-poetry','','[]','不問無言與有言，香山何事解聞禪。',32,'全唐诗/poet.song.73000.json','["不問無言與有言，香山何事解聞禪。", "須知篆縷摇空處，便是重重說萬緣。"]'),
('b985efc2-7562-4dd4-a1d9-1c57e9405780','次韵上酬郭慎求長官','慕容彥逢','宋','宋诗','song-poetry','','[]','金盆馳問請閽人，郵信浮沈杳未聞。',32,'全唐诗/poet.song.73000.json','["金盆馳問請閽人，郵信浮沈杳未聞。", "二十八言還寄我，一揮多謝管城君。"]'),
('fbf1a91b-c65a-42a3-aa6d-ee918a39707a','次韵上酬四十伯父','慕容彥逢','宋','宋诗','song-poetry','','[]','南郭先生物外人，鏘金佳製喜重聞。',32,'全唐诗/poet.song.73000.json','["南郭先生物外人，鏘金佳製喜重聞。", "寫成圖軸閒來展，要似徽之愛此君。"]'),
('ae254c6d-f0c8-4ae6-96cd-c3d063dc6eaa','寄單季隠','慕容彥逢','宋','宋诗','song-poetry','','[]','別時新柳拂烟汀，已見黄花照眼明。',32,'全唐诗/poet.song.73000.json','["別時新柳拂烟汀，已見黄花照眼明。", "却憶荆溪寒雨夜，笑聽屐齒出相迎。"]'),
('b8f68c85-9c61-46ee-9416-f49a5aef0a78','題婺州多福寺壁','慕容彥逢','宋','宋诗','song-poetry','','[]','我僕雖勞日未央，秋風行色稻花香。',32,'全唐诗/poet.song.73000.json','["我僕雖勞日未央，秋風行色稻花香。", "歸心那解同元亮，官况由來似偉長。"]'),
('044b8ff4-ee19-429d-a7d2-c42c6fd4df2b','和衡姪題孫德明墨梅','慕容彥逢','宋','宋诗','song-poetry','','[]','霜風栗烈砭人肌，又是江南梅發時。',32,'全唐诗/poet.song.73000.json','["霜風栗烈砭人肌，又是江南梅發時。", "寫影尋真未端的，此心隠處是南枝。"]'),
('9de3c1cb-87fa-471e-9a85-d681b71273ac','上知府張朝請','慕容彥逢','宋','宋诗','song-poetry','','[]','我公政事誰與儔，宛似當年陳太丘。',262,'全唐诗/poet.song.73000.json','["我公政事誰與儔，宛似當年陳太丘。", "德星光芒臨寶婺，和氣薰蒸凌素秋。", "天理人爲默相應，果見豐盈入謳詠。", "浙濱諸郡正憂勞，穀上三農獨歡慶。", "雨調風若無乖愆，六穟三禾大有年。", "不須更看斗魁覆，賜自我公休論天。", "朝廷勤勤念方面，天以公從人主願。", "返火還珠昔謾聞，多稌遺秉今纔見。", "德度恢恢真絕倫，北斗以南能幾人。", "繡衣風憲榮光近，熊軾威儀恩命新。", "荆溪之子少也賤，爲米折腰來佐縣。", "五袴于今預蜀歌，三語何時同晉掾。", "公不見黄金百鎰未爲優，季布一諾百不愁。", "又不見李白不願萬戶侯，惟願一識韓荆州。", "賤子聞公名已久，今幸將身托趨走。", "短歌不惜賦漁陽，此聲未便羞雞口。"]'),
('b3e7ca04-eda7-4ad4-bfd8-0fb2884070d1','示道三偈 隨流','釋清遠','宋','宋诗','song-poetry','','[]','千聖靈蹤百草頭，車然放去號隨流。',32,'全唐诗/poet.song.73000.json','["千聖靈蹤百草頭，車然放去號隨流。", "後教萬古無人識，笑殺溈山水牯牛。"]'),
('01c594eb-b19d-4be4-bd49-ee31b74b8774','示道三偈 合轍','釋清遠','宋','宋诗','song-poetry','','[]','水中月是天邊月，南北東西更無別。',32,'全唐诗/poet.song.73000.json','["水中月是天邊月，南北東西更無別。", "新羅打鐵火星飛，燒著指頭名合轍。"]'),
('6fc36f1f-8d69-4a8f-9285-6f96160cb1c5','示道三偈 雙唱','釋清遠','宋','宋诗','song-poetry','','[]','坐斷千差古路頭，解開種岸濟人舟。',32,'全唐诗/poet.song.73000.json','["坐斷千差古路頭，解開種岸濟人舟。", "明明一句該羣象，善唱非聲作麽求。"]'),
('e24933d8-caad-466b-8082-b71db4e194bb','標指六偈 迷悟','釋清遠','宋','宋诗','song-poetry','','[]','迷者迷悟，悟者悟迷。',240,'全唐诗/poet.song.73000.json','["迷者迷悟，悟者悟迷。", "迷悟同體，悟者方知。", "迷南爲北，實情取則。", "北本是南，悟無移忒。", "返究迷緣，莫得來處。", "忽悟正方，迷復何去。", "其迷則迷，妄自高低。", "生死惡覺，枉受膠黐。", "達迷無妄，歡喜無量。", "殺無明賊，祇在一餉。", "一餉之間，冥通大千。", "直下了了，三際虛玄。", "無始時來，總由今日。", "盡未來際，更不尋覓。", "當念無念，靈光焰焰。", "靈焰騰輝，心智難掩。", "靈源蕩碧，森羅普入。", "海印發明，非關動息。", "根塵不偶，心珠寧守。", "返不我觀，出兮還有。", "有無齊出，無有蹤跡。", "智用雖奇，猶遭悟覓。", "悟爲法障，身招罔象。", "犴貉無風，徒勞展掌。"]'),
('3d899b54-2e17-4262-9979-4853183ef80c','標指六偈 坐禪','釋清遠','宋','宋诗','song-poetry','','[]','心光虛映，體絕偏圓。',240,'全唐诗/poet.song.73000.json','["心光虛映，體絕偏圓。", "金波匝匝，動寂常禪。", "念起念滅，不用止絕。", "任運滔滔，何曾起滅。", "起滅寂滅，現大迦葉。", "坐卧經行，未曾間歇。", "禪何不坐，坐何不禪。", "了得如是，始號坐禪。", "坐者何人，禪是何物。", "而欲坐之，用佛覓佛。", "佛不用覓，覓之轉失。", "坐不我觀，禪非外術。", "初心鬧亂，未免回換。", "所以多方，教渠靜觀。", "端坐收神，初則紛紜。", "久久恬淡，虛閑六門。", "六門稍歇，於中分別。", "分別纔生，似成起滅。", "起滅轉變，從自心現。", "還用自心，返觀一徧。", "一返不再，圓光頂戴。", "靈焰騰輝，心心無礙。", "橫該豎入，生死永息。", "一粒還丹，點金成汁。"]'),
('53130681-eeff-494a-a76c-0d44c72e3c54','標指六偈 入道','釋清遠','宋','宋诗','song-poetry','','[]','道本無瑕，擬心已差。',240,'全唐诗/poet.song.73000.json','["道本無瑕，擬心已差。", "纔生眹兆，徧界空花。", "若欲全舉，除非直與。", "不用增添，現成規矩。", "洞徹根源，法法周圓。", "靈明法爾，妙絕言詮。", "言詮不得，得亦差忒。", "迥出根塵，古今取則。", "存不可見，亡兮對面。", "匪存匪亡，森羅自現。", "心外無法，法外無心。", "心法齊照，境智甚深。", "心忘照滅，境智同歇。", "一道通同，十方俱攝。", "生死涅槃，元無兩般。", "四生六道，息苦停酸。", "平等大道，無有邪正。", "胡漢不來，欲何爲鏡。", "像虛鏡皎，鏡像斯照。", "像去鏡亡，千聖非妙。", "此門難入，唯君自息。", "若入此門，半錢不直。", "不直半錢，萬國爭觀。", "所以說云，大道體寬。"]'),
('92f077d9-c4a7-4ee3-9309-b12af678d726','標指六偈 見聞','釋清遠','宋','宋诗','song-poetry','','[]','見極垂光，聽圓含響。',200,'全唐诗/poet.song.73000.json','["見極垂光，聽圓含響。", "若謂見聞，法成塵想。", "光流大千，響傳沙界。", "對現全彰，無在不在。", "聲不是聲，色不是色。", "非色非聲，山高水急。", "眼不可見，耳不可聞。", "非見非聞，宛爾見聞。", "見色聞聲，脫出根塵。", "水月鏡像，夢幻施陳。", "文殊寶剎，觀音普門。", "周羅法界，唯子一人。", "身土交映，妙絕凡聖。", "本有天真，非病不病。", "長歌且唱，妙舞更誇。", "東西南北，示現空花。", "生死去來，去來生死。", "若不如是，多過多咎。", "茲言未諦，此語皆宗。", "標指若示，古人同風。"]'),
('fcb1a745-cdb8-4760-9812-52c566e05ddb','標指六偈 水月','釋清遠','宋','宋诗','song-poetry','','[]','水月指陳，最疏最親。',240,'全唐诗/poet.song.73000.json','["水月指陳，最疏最親。", "若謂可見，還带重輪。", "月皎於上，水流於下。", "彼此非干，應緣何假。", "聲回響轉，垛成招箭。", "指喻孰明，標門誰辨。", "凡夫見聞，月皎水渾。", "心波業識，奔流苦門。", "二乘聞見，如鏡中面。", "對像迷真，渠還未薦。", "水澄月映，孤光迥迥。", "滅此化城，更須前進。", "一月耀天，光吞大千。", "森羅頓現，亙爾無邊。", "齊含寶月，交光廓徹。", "非中非外，一多融攝。", "毗盧性海，自他無礙。", "迷悟悟迷，相亡相在。", "一塵百億，百億一塵。", "奔走塵剎，不動本身。", "光亡月落，幾人摸索。", "四十九年，渾用不著。", "丈夫壯志，自有行市。", "十字路頭，看人失利。"]'),
('4bb214e3-ed20-4adf-9c55-ca1069f37e93','標指六偈 語默','釋清遠','宋','宋诗','song-poetry','','[]','至道非言，言亦可傳。',240,'全唐诗/poet.song.73000.json','["至道非言，言亦可傳。", "可傳何也，應物而宣。", "言雖應物，物自無物。", "無物之言，言音自沒。", "絕言之語，妙應還普。", "道非晦明，語默同取。", "舉復誰唱，物物虛曠。", "咸通大千，徧乎塵想。", "品類非一，同言異出。", "圓音落落，凡聖俱適。", "千品萬類，薰含種智。", "故此一門，稱無量義。", "山河宣演，草木揚音。", "長說無間，所謂甚深。", "深兮甚淺，不動情見。", "最省工夫，凡夫不薦。", "不薦最親，妙義敷陳。", "歡言即笑，恚怒即嗔。", "嗔爲金剛，喜爲迦葉。", "華藏毗盧，心心相接。", "接兮可見，莫看背面。", "無字密言，從茲出現。", "現復誰論，非用耳聞。", "六根共戶，妙偈星分。"]'),
('b77084de-64d4-4990-8573-500d34b14ad1','彼我不二','釋清遠','宋','宋诗','song-poetry','','[]','諸人行李處，非我君不能。',84,'全唐诗/poet.song.73000.json','["諸人行李處，非我君不能。", "我今憑子力，還與汝同心。", "彼我無差忒，超然絕古今。", "千差非止水，生死自平沉。", "對容誰不妙，拂袖省知音。", "不墮機前路，明明定淺深。", "其如未覺了，彼我徒自侵。"]'),
('c2eac607-0e8e-4fc0-b5ca-79d9d988e0bc','動靜常一','釋清遠','宋','宋诗','song-poetry','','[]','本自未常迷，何勞今日悟。',108,'全唐诗/poet.song.73000.json','["本自未常迷，何勞今日悟。", "守住寂寞城，知君還錯悞。", "從前諸聖人，元是凡夫做。", "豈有別路岐，教人離憂苦。", "祇者生死中，即是佛去處。", "有人忽踏著，選甚浄穢土。", "一向不回頭，喚之亦不顧。", "千聖不奈何，何不省言語。", "了却貪嗔癡，即是諸佛母。"]'),
('6daee561-b604-46cc-86a3-c1e18f08f346','妙語方知','釋清遠','宋','宋诗','song-poetry','','[]','佛與祖師言，拈花示癡子。',72,'全唐诗/poet.song.73000.json','["佛與祖師言，拈花示癡子。", "我今發此談，何言顛倒爾。", "當人自天真，譬之秋潭水。", "一物著不得，豈用安名字。", "切莫向其中，認之還不是。", "不見須菩提，空空達彼彼。"]'),
('58e5b751-43a7-4907-bc69-2d0ac00d2b92','了妄元真','釋清遠','宋','宋诗','song-poetry','','[]','問汝貪嗔癡，家住在何處。',144,'全唐诗/poet.song.73000.json','["問汝貪嗔癡，家住在何處。", "我今要與汝，各各分頭去。", "好好細思量，免被他官府。", "大者名爲貪，養得二舍弟。", "三郎都一處，日夜共活計。", "令汝家戶大，使汝善調制。", "子今苦厭我，我與子發誓。", "一要子自知，二要子依例。", "三要當處生，四要歡喜偈。", "與汝善和同，一一無凡穢。", "一覺一切了，何須去煩翳。", "我是諸佛母，十方及三世。"]'),
('e037ee5b-92bb-418b-adf8-b17ef27ebd8b','物我無差','釋清遠','宋','宋诗','song-poetry','','[]','青山是我身，流水爲我命。',84,'全唐诗/poet.song.73000.json','["青山是我身，流水爲我命。", "養之以四時，蕭然自條正。", "覆育諸衆生，六度自修省。", "栽花種菩提，拂石要安靜。", "不見楊柳飛，自有蒲萄影。", "玩之且不厭，去亦無冤競。", "一性一切性，娑婆大圓鏡。"]'),
('2020e5ed-0525-4d1d-bf6d-f5215497e2c0','同居善說','釋清遠','宋','宋诗','song-poetry','','[]','世人不識我，求我以形容。',96,'全唐诗/poet.song.73000.json','["世人不識我，求我以形容。", "形容不相似，徒觀紙上龍。", "若要識得我，問取主人翁。", "主人好家業，物物要安藏。", "六兄誇藝術，三母足溫良。", "南廳善書算，北庫多財糧。", "住來但覺久，懶去問張王。", "君若一識得，與汝同屋梁。"]'),
('ff18213c-274c-4f40-b87c-bf2c7c7e81aa','美容可觀','釋清遠','宋','宋诗','song-poetry','','[]','一別海山中，十年春草綠。',48,'全唐诗/poet.song.73000.json','["一別海山中，十年春草綠。", "相思在方寸，顔容皎如玉。", "音書杳不來，桃李繁且熟。", "唯有意中人，使我眉頭蹙。"]'),
('7e7fb95e-5725-417b-a563-36a7fba1511f','妙容非睹','釋清遠','宋','宋诗','song-poetry','','[]','通身無影像，脫體露堂堂。',48,'全唐诗/poet.song.73000.json','["通身無影像，脫體露堂堂。", "不話非聲色，何曾有短長。", "河沙恒徧現，故號法中王。", "優曇花正開，嗅著不聞香。"]'),
('39d3822e-e7f4-4917-aa33-2a660da777e2','延促自爾','釋清遠','宋','宋诗','song-poetry','','[]','春日春山裏，春事盡皆春。',48,'全唐诗/poet.song.73000.json','["春日春山裏，春事盡皆春。", "春光照春水，春氣結春雲。", "春客春情動，春詩春更新。", "唯有識春人，萬劫元一春。"]'),
('a743c39b-392b-469a-9d7c-7893b4d85467','寂體咸周','釋清遠','宋','宋诗','song-poetry','','[]','妙體無方具徧知，近邦遠利絕毫釐。',32,'全唐诗/poet.song.73000.json','["妙體無方具徧知，近邦遠利絕毫釐。", "根塵應念周沙界，坐斷毗盧發大機。"]'),
('774db6ed-6877-45d5-8893-691752cb13b8','應緣不錯','釋清遠','宋','宋诗','song-poetry','','[]','法法無差是正修，見聞從此絕漂流。',32,'全唐诗/poet.song.73000.json','["法法無差是正修，見聞從此絕漂流。", "窮心未到忘心處，一聚根塵安得休。"]'),
('c41ed811-05c5-4f09-b26d-42fd98cf9cc0','祖師地種花及總頌四首 地','釋清遠','宋','宋诗','song-poetry','','[]','性地本無生，因生說有地。',24,'全唐诗/poet.song.73000.json','["性地本無生，因生說有地。", "流傳古至今，非愚亦非智。"]'),
('a31fa6f7-5126-4d65-ae1a-a0c299a7399f','祖師地種花及總頌四首 種','釋清遠','宋','宋诗','song-poetry','','[]','從昔未曾迷，於今何所悟。',24,'全唐诗/poet.song.73000.json','["從昔未曾迷，於今何所悟。", "祇緣種性深，更亦無別路。"]'),
('df826489-edf5-4b04-bc78-070976e709bc','祖師地種花及總頌四首 花','釋清遠','宋','宋诗','song-poetry','','[]','有種有心地，因緣花自開。',24,'全唐诗/poet.song.73000.json','["有種有心地，因緣花自開。", "要知成果處，却笑祖師來。"]'),
('169600b3-8b9e-4414-96f6-f1fe28391e29','祖師地種花及總頌四首 總','釋清遠','宋','宋诗','song-poetry','','[]','五葉花開後，山長水更深。',24,'全唐诗/poet.song.73000.json','["五葉花開後，山長水更深。", "亂雲橫谷口，游子謾追尋。"]'),
