('e239803d-72e8-40e9-9a7a-a608bdf5c825','師常以六隻骰子示禪人六面皆六點復作三頌  其二','釋清遠','宋','宋诗','song-poetry','','[]','六隻骰子滿盆紅，塵墨河沙用莫窮。',32,'全唐诗/poet.song.73000.json','["六隻骰子滿盆紅，塵墨河沙用莫窮。", "誰能解展金剛手，祖佛親來亦掃脩。"]'),
('c0ec0af0-f915-4dd4-be70-e0d8a7110155','師常以六隻骰子示禪人六面皆六點復作三頌  其三','釋清遠','宋','宋诗','song-poetry','','[]','六隻骰子滿盆紅，馬載馿駝一擲空。',32,'全唐诗/poet.song.73000.json','["六隻骰子滿盆紅，馬載馿駝一擲空。", "赫赤窮來無可賽，請君從此現神通。"]'),
('67c08b7e-8a92-413e-a9b5-8c1286f290e7','迷逢達磨','釋清遠','宋','宋诗','song-poetry','','[]','信步遊梁魏，乘時別少林。',24,'全唐诗/poet.song.73000.json','["信步遊梁魏，乘時別少林。", "長安車馬客，無限利名心。"]'),
('0adbe2dc-e68a-422a-abb6-68a7eeb79f62','因法眼頌','釋清遠','宋','宋诗','song-poetry','','[]','呪咀毒藥，形聲之逆。',52,'全唐诗/poet.song.73000.json','["呪咀毒藥，形聲之逆。", "眼耳若通，本人何適。", "根問本人何所適，塗割等平忘順逆。", "有爲雖僞性常真，法法無依稱善吉。"]'),
('cdd68122-6d07-4c38-9883-a7797c577f17','無情說法','釋清遠','宋','宋诗','song-poetry','','[]','無情說法異盲聾，聽得之人眼耳通。',32,'全唐诗/poet.song.73000.json','["無情說法異盲聾，聽得之人眼耳通。", "不但近塵并遠剎，十方度盡顯全功。"]'),
('60459437-56aa-4a50-bc52-b2eb7e1abbda','寒食禮先師真五首  其一','釋清遠','宋','宋诗','song-poetry','','[]','雲水參尋訪此宗，十年磨刮太虛空。',32,'全唐诗/poet.song.73000.json','["雲水參尋訪此宗，十年磨刮太虛空。", "區區力盡還依舊，方知萬法本來同。"]'),
('f0e1af99-e0be-4dbc-8ff7-264769f2cd28','寒食禮先師真五首  其二','釋清遠','宋','宋诗','song-poetry','','[]','一悟吾師心便息，信門入處還無入。',32,'全唐诗/poet.song.73000.json','["一悟吾師心便息，信門入處還無入。", "二十年中事密如，向人殊不勞心力。"]'),
('459ea6e4-346e-493b-a4bf-f182964e317d','寒食禮先師真五首  其三','釋清遠','宋','宋诗','song-poetry','','[]','前人說法後人聽，由來兩箇總無情。',32,'全唐诗/poet.song.73000.json','["前人說法後人聽，由來兩箇總無情。", "祇緣口耳都相似，所以流通道自成。"]'),
('dedff5a0-4332-4f8d-90cd-d6e685f9ce48','寒食禮先師真五首  其四','釋清遠','宋','宋诗','song-poetry','','[]','去人去矣叮嚀囑，住者相承無斷續。',32,'全唐诗/poet.song.73000.json','["去人去矣叮嚀囑，住者相承無斷續。", "若遇知音一和時，乃知去住常充足。"]'),
('d9e54d52-224e-48f8-933d-984e16d72697','寒食禮先師真五首  其五','釋清遠','宋','宋诗','song-poetry','','[]','清明寒食與諸人，共禮先師不動身。',32,'全唐诗/poet.song.73000.json','["清明寒食與諸人，共禮先師不動身。", "萬法本閑心亦爾，將來誰是得吾真。"]'),
('3f37496e-d033-479b-bfbd-4f77854c2cad','和珪首座二頌  其一','釋清遠','宋','宋诗','song-poetry','','[]','祇論親切不論時，回笑諸方陷虎機。',64,'全唐诗/poet.song.73000.json','["祇論親切不論時，回笑諸方陷虎機。", "一句未容開口對，片帆先逐便風歸。", "頭頭有路堪行履，物物無差莫棄違。", "不見黄梅足奇士，盧公却得祖師衣。"]'),
('55920928-76c6-4e6d-9183-4f9b0adfd68a','和珪首座二頌  其二','釋清遠','宋','宋诗','song-poetry','','[]','媿爾相求識歲寒，不嫌危磴路千盤。',64,'全唐诗/poet.song.73000.json','["媿爾相求識歲寒，不嫌危磴路千盤。", "歸堂一剳曾親訪，閉戶深山肯自瞞。", "月下篇章應獨和，壺中天地共誰看。", "臨機大用全收放，何必區區握雪團。"]'),
('f48631a2-82ad-42a0-8350-09a703d49526','送郭大夫知鉅野','釋清遠','宋','宋诗','song-poetry','','[]','東歸半載漁樵樂，北去三年父母來。',32,'全唐诗/poet.song.73000.json','["東歸半載漁樵樂，北去三年父母來。", "金馬玉堂彈指入，寶樓香閣一時開。"]'),
('ed8626ff-2fd7-4d6f-856e-c3f9a1666769','題陳子美息陰堂','釋清遠','宋','宋诗','song-poetry','','[]','湛湛寒溪疊疊山，息陰投老得身閑。',64,'全唐诗/poet.song.73000.json','["湛湛寒溪疊疊山，息陰投老得身閑。", "武陵花好春常在，漁棹歌清事不關。", "眼底兒孫從富貴，罇前鬢髮任斕斑。", "天機日有真消息，頻許禪僧共往還。"]'),
('1db30cc4-d8fe-4907-8be7-b1317eeaffd6','題孫欽之養素軒','釋清遠','宋','宋诗','song-poetry','','[]','善養不教聲色亂，素絲無染是天真。',32,'全唐诗/poet.song.73000.json','["善養不教聲色亂，素絲無染是天真。", "有時來此軒中坐，作箇忘機混沌人。"]'),
('58d1fdc9-8dae-4b79-970a-2c253619f5ca','智海化士乞頌','釋清遠','宋','宋诗','song-poetry','','[]','乞食山城歸帝里，毗耶鉢飯香而美。',32,'全唐诗/poet.song.73000.json','["乞食山城歸帝里，毗耶鉢飯香而美。", "莫念故園桃李春，更參上國西來旨。"]'),
('3945b3e4-fcf8-42de-b11a-c5332d590793','示圍爐僧','釋清遠','宋','宋诗','song-poetry','','[]','爐邊靜坐默無言，勿論麤疏若市廛。',32,'全唐诗/poet.song.73000.json','["爐邊靜坐默無言，勿論麤疏若市廛。", "冷暖此中看火色，祖師心印爲親傳。"]'),
('51858360-092d-4b5b-9826-afd7a9012362','題徐四翁壁','釋清遠','宋','宋诗','song-poetry','','[]','徐翁活計天真，年老無喜無嗔。',28,'全唐诗/poet.song.73000.json','["徐翁活計天真，年老無喜無嗔。", "參取面前桑樹，乾坤不出一塵。"]'),
('1d09f21f-85f1-4d9a-a955-0d9fa42ccad6','題祇園庵','釋清遠','宋','宋诗','song-poetry','','[]','祇園誰住此，謂是钁頭通。',48,'全唐诗/poet.song.73000.json','["祇園誰住此，謂是钁頭通。", "物外庵邊竹，人間耳畔風。", "露畦青戢戢，烟浦綠濛濛。", "祇箇潜心處，分明古者同。"]'),
('cd5d88d2-2282-4ee6-b8a9-c7621bbbb0cb','夏散輒病既病且惱因書山偈示一一禪者','釋清遠','宋','宋诗','song-poetry','','[]','萬劫一瞬視，塵沙不動移。',48,'全唐诗/poet.song.73000.json','["萬劫一瞬視，塵沙不動移。", "若爲論過未，併總入無時。", "海闊波仍匝，心通佛可齊。", "床頭木枕子，推出恐人迷。"]'),
('9547bceb-0d7a-4268-a104-4ca601a878aa','題侍者寮香林閣','釋清遠','宋','宋诗','song-poetry','','[]','葛厨松枕午窗凉，卧看風雲草木香。',32,'全唐诗/poet.song.73000.json','["葛厨松枕午窗凉，卧看風雲草木香。", "彈指徧遊塵剎盡，故山歸路笑羊腸。"]'),
('3b4bbacd-4a56-425e-86c4-780461701a1d','送常侍者西歸省親','釋清遠','宋','宋诗','song-poetry','','[]','本從綿竹過南方，依前歸入綿竹去。',64,'全唐诗/poet.song.73000.json','["本從綿竹過南方，依前歸入綿竹去。", "井舍猶爲舊日居，山川不改當時處。", "鄰人見之莫驚愕，親里歡迎斷思慮。", "有問南方所得時，瘦藤爲我聊輕據。"]'),
('dac6dabe-7a40-41aa-b52e-b62982f33ab5','小師崇堅乞偈','釋清遠','宋','宋诗','song-poetry','','[]','事辦須尋道，方明爾本來。',24,'全唐诗/poet.song.73000.json','["事辦須尋道，方明爾本來。", "禪關無鎖鑰，祇要用心開。"]'),
('62e83d6d-a034-46bd-8002-c97125882f0e','龍門偶作五首  其一','釋清遠','宋','宋诗','song-poetry','','[]','明月何皎皎，永夜入我室。',48,'全唐诗/poet.song.73000.json','["明月何皎皎，永夜入我室。", "照出萬古心，念此百年質。", "隔窗風露泫，擁毳衣衾密。", "遲遲不能寐，餘光在東壁。"]'),
('ae347bac-08b6-45e3-80cc-8055286eba8f','龍門偶作五首  其二','釋清遠','宋','宋诗','song-poetry','','[]','叨叨林鳥啼，披衣中夜坐。',48,'全唐诗/poet.song.73000.json','["叨叨林鳥啼，披衣中夜坐。", "撥火悟平生，窮神歸破墮。", "事皎人自迷，曲淡誰能和。", "念之永不忘，門開少來過。"]'),
('22d71255-4644-4fa6-a5da-7c6b7c6ca5bb','龍門偶作五首  其三','釋清遠','宋','宋诗','song-poetry','','[]','嗚嗚鼯鼠啼，時人皆不喜。',48,'全唐诗/poet.song.73000.json','["嗚嗚鼯鼠啼，時人皆不喜。", "得意即相呼，意去當自止。", "吉凶由之生，吾未見其理。", "此言如未聞，大梅有宗旨。"]'),
('59b3604a-4093-4447-b7a1-19987517db0b','龍門偶作五首  其四','釋清遠','宋','宋诗','song-poetry','','[]','初夜凉生早，微雲卷太空。',48,'全唐诗/poet.song.73000.json','["初夜凉生早，微雲卷太空。", "燈懸松竹露，簾捲薜蘿風。", "可笑千年事，能將一念通。", "相逢禪客間，細細話吾宗。"]'),
('6760f740-1a6d-43d3-8d68-cadf1a991297','龍門偶作五首  其五','釋清遠','宋','宋诗','song-poetry','','[]','每念心中事，頻開掌內珠。',48,'全唐诗/poet.song.73000.json','["每念心中事，頻開掌內珠。", "欲憑天上雁，待寄水中魚。", "此意終難寫，斯言不可書。", "含毫竟寂寞，遶屋樹扶疏。"]'),
('81a41dec-b90f-4357-a344-662641ffa84d','題靈光臺壁  其一','釋清遠','宋','宋诗','song-poetry','','[]','吾初欲作真常語，更恐真常暗流注。',64,'全唐诗/poet.song.73000.json','["吾初欲作真常語，更恐真常暗流注。", "不如不語人共知，人欲知之反勞慮。", "崖頭浮圖示其相，臺上野雲飛不住。", "周遊獨步或可追，錦繡谷中歸舍去。"]'),
('490e4b7e-41e3-4bb1-a559-e3e4cee5fe2d','題靈光臺壁  其二','釋清遠','宋','宋诗','song-poetry','','[]','百骸潰散此日言，一物長靈異時語。',64,'全唐诗/poet.song.73000.json','["百骸潰散此日言，一物長靈異時語。", "此日長靈猶可知，異時潰散憑誰舉。", "可知所以有生滅，解舉方能忘取與。", "光明寂照徧河沙，慎勿於中論爾汝。"]'),
('1ba0d87c-9838-48a8-b169-6ba1b45544ed','花山','釋清遠','宋','宋诗','song-poetry','','[]','石龜不念歲月古，舊記已滅名尚留。',64,'全唐诗/poet.song.73000.json','["石龜不念歲月古，舊記已滅名尚留。", "道傍蒼木老霜雪，澗畔野草隨春秋。", "訛傳細讀華陽傳，靈跡獨聞姚比丘。", "可憑定力驗今昔，人間萬事徒悠悠。"]'),
('768bf4ca-ef58-4813-b358-91aabcfd441e','木魚','釋清遠','宋','宋诗','song-poetry','','[]','無端擊此溝中斷，鐘鼓相參無雜亂。',64,'全唐诗/poet.song.73000.json','["無端擊此溝中斷，鐘鼓相參無雜亂。", "能聞所聞非二緣，以此及此通回換。", "凡夫何故作追攀，達士若爲成智觀。", "可憐流入薩婆若，醉眠尚爾排魚貫。"]'),
('4d7c4887-0bc4-4c72-8e98-8a13b2c2a3dc','讀經','釋清遠','宋','宋诗','song-poetry','','[]','不染而染妄本虛，染而不染悉無餘。',64,'全唐诗/poet.song.73000.json','["不染而染妄本虛，染而不染悉無餘。", "本虛自是能成事，體浄何妨應萬殊。", "斷妄證真心豈息，非真非妄智還迂。", "了真了妄如無礙，自在圓明始是珠。"]'),
('2d1647ff-3c3a-4199-b668-246126c16e57','不寐','釋清遠','宋','宋诗','song-poetry','','[]','毗耶離城居士家，環堵十笏容河沙。',64,'全唐诗/poet.song.73000.json','["毗耶離城居士家，環堵十笏容河沙。", "八萬四千高座衆，咄嗟已辦熏天花。", "迢迢不到迷是障，念念常入心無差。", "須彌盧山四大海，我見如一粟與麻。"]'),
('f7d3a232-c607-4393-8739-5ab65f18e0ae','早起','釋清遠','宋','宋诗','song-poetry','','[]','老來愈見心無事，夜永偏知膽更凉。',64,'全唐诗/poet.song.73000.json','["老來愈見心無事，夜永偏知膽更凉。", "淺淺地爐猶有火，依依山月尚臨牆。", "試將寂滅那伽定，暗寫雕蟲篆刻章。", "剛被啼鷄忽驚斷，一時歸入正思量。"]'),
('22dc4b92-2d6b-4b49-8ea1-7d3e91ba3d40','起晚','釋清遠','宋','宋诗','song-poetry','','[]','展脚縮脚饑鼠啼，合眼開眼重露晞。',64,'全唐诗/poet.song.73000.json','["展脚縮脚饑鼠啼，合眼開眼重露晞。", "覺來始了夢時事，夢處寧容覺後知。", "瞬息黄粱猶未熟，翩翻蝴蝶正狂飛。", "披衣獨坐日正午，試問何如半夜時。"]'),
('1727e7ed-e534-4501-83a0-93292c1bfd24','遊定明塔院作二頌  其一','釋清遠','宋','宋诗','song-poetry','','[]','大士安禪地，千松塔院春。',48,'全唐诗/poet.song.73000.json','["大士安禪地，千松塔院春。", "門深松檜老，事古歲時新。", "人禮香燈夜，鳥啼花雨晨。", "祇應禪石上，去住亦通神。"]'),
('28a741ea-a61e-4f6f-8aee-899c9853577f','遊定明塔院作二頌  其二','釋清遠','宋','宋诗','song-poetry','','[]','白塔雲中路，晴空鳥外簷。',48,'全唐诗/poet.song.73000.json','["白塔雲中路，晴空鳥外簷。", "好山長入望，終日坐無厭。", "幾箇竹生石，數枝花映簾。", "長安曾未到，神力動飛潜。"]'),
('2fa2e538-7652-4abf-84e2-02f3c4ec9cbf','因舉楞嚴經七處徵心成頌','釋清遠','宋','宋诗','song-poetry','','[]','善逝明知直不邪，要窮妄識是空花。',112,'全唐诗/poet.song.73000.json','["善逝明知直不邪，要窮妄識是空花。", "故令慶喜推心目，勝相初觀始出家。", "在內何緣昧肝胃，相知在外又成差。", "琉璃比眼還同境，閉障開明未有涯。", "合處隨生難定體，根塵兼带轉蓬麻。", "世間一切都無著，水陸空行作翳瑕。", "七處無歸全失措，從茲始得徧河沙。"]'),
('ff4c7198-dbce-4b4a-b697-5913b0c75850','述懷示學者','釋清遠','宋','宋诗','song-poetry','','[]','細思五十三年事，併入初中後夜心。',64,'全唐诗/poet.song.73000.json','["細思五十三年事，併入初中後夜心。", "須信剎那通過未，更無毫髮作追尋。", "隨消舊業根先斷，永絕新殃道已深。", "此是安身立命處，故吹一曲報知音。"]'),
('9a77e152-b6ed-4878-8eb3-b3d1f2604758','病中示光道者','釋清遠','宋','宋诗','song-poetry','','[]','我病無形不可見，曼殊室利得深知。',32,'全唐诗/poet.song.73000.json','["我病無形不可見，曼殊室利得深知。", "再三若欲通消息，推出床頭木枕兒。"]'),
('a50ca8dd-b53d-4be0-8e34-348573728bc9','蔣山送無著道人歸舒州','釋清遠','宋','宋诗','song-poetry','','[]','已禮雲中塔，更瞻堂上師。',48,'全唐诗/poet.song.73000.json','["已禮雲中塔，更瞻堂上師。", "方思江水北，共集定林西。", "一句無多子，千差永不疑。", "到家勤愛護，此道少人知。"]'),
('cd330824-a4b6-4530-9ab3-d974bc62e5be','送禪人入京','釋清遠','宋','宋诗','song-poetry','','[]','千人叢與萬人叢，無喜無嗔耳目通。',32,'全唐诗/poet.song.73000.json','["千人叢與萬人叢，無喜無嗔耳目通。", "要識太原孚上座，六街鐘鼓鬧鼕鼕。"]'),
('6a44a6b7-d804-4331-925f-ca450150b4d2','再得旨退褒山成三偈代違和守錢公  其一','釋清遠','宋','宋诗','song-poetry','','[]','住山久有烟霞疾，得請放還麋鹿羣。',32,'全唐诗/poet.song.73000.json','["住山久有烟霞疾，得請放還麋鹿羣。", "厚意於公殊未報，深禪聊復對爐薰。"]'),
('78521ead-288b-479c-afdb-909017d21881','再得旨退褒山成三偈代違和守錢公  其二','釋清遠','宋','宋诗','song-poetry','','[]','公家忠靖有遺德，乃與定明開道緣。',32,'全唐诗/poet.song.73000.json','["公家忠靖有遺德，乃與定明開道緣。", "異世今時豈人意，一麾千里是家傳。"]'),
('84729c37-38ce-44c3-9606-f99be19ab2a9','再得旨退褒山成三偈代違和守錢公  其三','釋清遠','宋','宋诗','song-poetry','','[]','出岫油然亦乘興，倦飛隨意即知還。',32,'全唐诗/poet.song.73000.json','["出岫油然亦乘興，倦飛隨意即知還。", "有心知到無心域，鳥戀故林雲在山。"]'),
('ba8606a2-d59c-4f81-ac54-67cbecf426ce','釋迦如來出山像贊','釋清遠','宋','宋诗','song-poetry','','[]','妙色非身，形容乃普。',120,'全唐诗/poet.song.73000.json','["妙色非身，形容乃普。", "閻浮未下，雙林已睹。", "曠濟功深，六年行苦。", "塵沙相好，萬億剎土。", "衆生心浄，佛日常午。", "正念蒙光，迷人外取。", "雕檀寫㲲，像未孩乳。", "今茲範模，傳從乃古。", "象步出山，智珠河吐。", "水月頓澄，豁開覺戶。", "瞻之仰之，豈敢自侮。", "常在不滅，此言手舞。"]'),
('fc0d7d77-cbf4-4652-b4a2-f1765907bae3','觀音像贊二首  其一','釋清遠','宋','宋诗','song-poetry','','[]','曠大劫來離衆苦，心心永斷諸分別。',64,'全唐诗/poet.song.73000.json','["曠大劫來離衆苦，心心永斷諸分別。", "聞處真聞實不聞，說時雖說常無說。", "法身普現凡聖等，耳根采聽音聲絕。", "娑婆最有大因緣，一念清凉除惱熱。"]'),
('2eeea8bf-be8b-4ffb-a85e-578c448535e7','觀音像贊二首  其二','釋清遠','宋','宋诗','song-poetry','','[]','曠大劫來不虛妄，言言故得皆真實。',64,'全唐诗/poet.song.73000.json','["曠大劫來不虛妄，言言故得皆真實。", "應念蒙光迅電飛，尋聲救苦奔風疾。", "千章萬句離文字，異韵殊音垂祕密。", "現相宣揚遇此時，見聞穎脫欣今日。"]'),
('63e628a3-203b-4067-8919-7934fe731fa8','天台三大士像贊','釋清遠','宋','宋诗','song-poetry','','[]','岩岩天台，曠闊寰宇。',60,'全唐诗/poet.song.73000.json','["岩岩天台，曠闊寰宇。", "大士不我，毫端莫取。", "蜀客心狂，纖塵一縷。", "屈指拊掌，松石猛虎。", "生涯何有，流傳今古。", "靜對虛堂，非謂無補。"]'),
('e30ba269-086e-4d7b-8ce7-2f68e7db68db','達磨大師贊','釋清遠','宋','宋诗','song-poetry','','[]','振摇梁魏，斟酌皮髓。',30,'全唐诗/poet.song.73000.json','["振摇梁魏，斟酌皮髓。", "孰云西來，空槨而已。", "素壁虛堂，少林熊耳。"]'),
('9561c1c8-78b5-4377-875a-87d583c321a5','百丈大師贊','釋清遠','宋','宋诗','song-poetry','','[]','慧燈續傳，福庭宜敞。',30,'全唐诗/poet.song.73000.json','["慧燈續傳，福庭宜敞。", "常住世間，水月鏡像。", "是謂叢林，大智百丈。"]'),
('cd98a3bd-f2a1-470e-8fb2-7f858e873c01','楊岐和尚贊','釋清遠','宋','宋诗','song-poetry','','[]','鬧市竿頭呈戲，衆眼曾驚。',44,'全唐诗/poet.song.73000.json','["鬧市竿頭呈戲，衆眼曾驚。", "栗棘蒲上橫吞，諸方盡畏。", "宜陽秀水，萍實楊岐。", "雨過雲橫，天高地下。"]'),
('a5846901-4f4c-4597-9a6d-b84f18f99aff','白雲端和尚贊','釋清遠','宋','宋诗','song-poetry','','[]','綱紀著明，不忘付授。',30,'全唐诗/poet.song.73000.json','["綱紀著明，不忘付授。", "浄空無際，如日處晝。", "欲究根源，瞻之龍岫。"]'),
('06326e3a-9656-43fc-8b37-60e749c14f96','五祖演和尚贊','釋清遠','宋','宋诗','song-poetry','','[]','遇冤則親，傳虛果當。',40,'全唐诗/poet.song.73000.json','["遇冤則親，傳虛果當。", "剛硬齒牙，生鐵腸臟。", "風清淮楚，道實宗匠。", "不有智悲，子孫安嚮。"]'),
('4e12179b-a575-4e98-9501-3c66330cdfaf','浮山圓鑒和尚贊','釋清遠','宋','宋诗','song-poetry','','[]','并汾鐵騎，老息荒丘。',20,'全唐诗/poet.song.73000.json','["并汾鐵騎，老息荒丘。", "雲施雨罷，花落水流。"]'),
('986a9524-42e0-4718-8d15-0343cb868f1b','褒山定明禪師贊','釋清遠','宋','宋诗','song-poetry','','[]','四海稱唐，師出華陽。',60,'全唐诗/poet.song.73000.json','["四海稱唐，師出華陽。", "不起燕坐，翱翔帝鄉。", "名與山俱，道逐時芳。", "濟民助國，能雨能暘。", "貧者獲富，熱者得凉。", "羣蒙所歸，實在不亡。"]'),
('337d399e-9c9c-4003-8ebd-3defc72ab789','悟首座圖余幻質復求爲贊','釋清遠','宋','宋诗','song-poetry','','[]','廓然無聖，儼爾有容。',80,'全唐诗/poet.song.73000.json','["廓然無聖，儼爾有容。", "明明絕眹，密密垂蹤。", "昔也懷寶，枯木藏龍。", "今其示人，巨嶽喬松。", "龍吞萬類，松茂三冬。", "神而不改，風雲必從。", "吾形既得，爾道自鍾。", "褒斜路險，漢水朝宗。"]'),
('756a1eac-fa30-4f82-8006-00f1dc06ed8e','珪首座求贊','釋清遠','宋','宋诗','song-poetry','','[]','如珪如璋，惟子非我。',80,'全唐诗/poet.song.73000.json','["如珪如璋，惟子非我。", "且陋且拙，在余是可。", "子今傳余，拙則成奇。", "物感神會，形動心隨。", "凝雲不飛，寒月下映。", "孰謂之凡，孰謂之聖。", "余猶爾也，奇拙同貫。", "嘻嘻期文，大朴未散。"]'),
('0710d3b6-c0d1-425f-953e-ca7d9e974a4f','順知藏求贊','釋清遠','宋','宋诗','song-poetry','','[]','色裏膠青不見形，影中所以邈吾真。',48,'全唐诗/poet.song.73000.json','["色裏膠青不見形，影中所以邈吾真。", "吾真定有非形礙，爲對凡夫顯幻塵。", "塵既顯，道彌新，不貴西來彼上人。"]'),
('5b8970d4-bf4a-40e7-89d9-3436c6d384a6','淵禪人求贊','釋清遠','宋','宋诗','song-poetry','','[]','似余似余，類我類我。',40,'全唐诗/poet.song.73000.json','["似余似余，類我類我。", "我復謂誰，如火與火。", "描邈不就，迎隨不果。", "寫出龍門，衲僧災禍。"]'),
('d9b250f8-d465-4bdd-aaa2-9f855c76c187','如大師求贊','釋清遠','宋','宋诗','song-poetry','','[]','比類則疏，現形仍普。',40,'全唐诗/poet.song.73000.json','["比類則疏，現形仍普。", "得在一瞬，照窮千古。", "雲起吟龍，風生嘯虎。", "贊之絕辭，瞻焉奚睹。"]'),
('71e12b3d-f92c-4981-8949-de2b5761605e','賢監院求贊','釋清遠','宋','宋诗','song-poetry','','[]','徧界不藏，毫端獨妙。',40,'全唐诗/poet.song.73000.json','["徧界不藏，毫端獨妙。", "縱未嚬呻，已先微笑。", "吾子識也，水月斯照。", "纖塵不遺，是爲宗要。"]'),
('b89182ba-9185-4bea-b31e-6cea6c77a524','肱維那求贊','釋清遠','宋','宋诗','song-poetry','','[]','識余者誰，請觀端的。',40,'全唐诗/poet.song.73000.json','["識余者誰，請觀端的。", "孰云丹青，謾勞尋覓。", "斷雲架巘，皎月在壁。", "昭爾惺惺，悟茲寂寂。"]'),
('ffd39741-1d1a-4d38-b902-3be04dd7b5c5','勤禪人求贊','釋清遠','宋','宋诗','song-poetry','','[]','滄溟一滴鹹無際，厚地纖塵廣有餘。',32,'全唐诗/poet.song.73000.json','["滄溟一滴鹹無際，厚地纖塵廣有餘。", "何事陋容人寫得，祇緣蹤跡在龍舒。"]'),
('2eb2b3bf-443c-4f42-a07f-aff253a03ead','昕侍者求贊','釋清遠','宋','宋诗','song-poetry','','[]','吾行爾隨，吾喚爾應。',40,'全唐诗/poet.song.73000.json','["吾行爾隨，吾喚爾應。", "唯隨與應，不欠不剩。", "因吾識爾，此像果親。", "靜而瞻之，道實絕倫。"]'),
('37b6db88-7381-41bb-b830-a5d9be804429','元侍者求贊','釋清遠','宋','宋诗','song-poetry','','[]','道雖光明，形則山野。',40,'全唐诗/poet.song.73000.json','["道雖光明，形則山野。", "提折脚鐺，住深蘭若。", "拙韵無取，陋容誰寫。", "常在左右，覺元侍者。"]'),
('c5190e9f-35ee-4191-8452-d76792e16c92','小師崇戒求贊','釋清遠','宋','宋诗','song-poetry','','[]','似即疏，比仍失。',32,'全唐诗/poet.song.73000.json','["似即疏，比仍失。", "廓爾空，皎然日。", "顧丹青，寫容質。", "誰使之，省尋覓。"]'),
('0a08c77a-baed-4f17-bb64-247b0cd6cf05','無著道人求贊','釋清遠','宋','宋诗','song-poetry','','[]','植杖望雲何處，空山獨立凝情。',28,'全唐诗/poet.song.73000.json','["植杖望雲何處，空山獨立凝情。", "媿我蕭然無物，謝伊裝點相成。"]'),
('3a799e92-a195-42c9-a65e-c8bbaf4165cc','馮濟川教授求贊','釋清遠','宋','宋诗','song-poetry','','[]','天地無物我無物，隠顯空雲隨出沒。',32,'全唐诗/poet.song.73000.json','["天地無物我無物，隠顯空雲隨出沒。", "此間誰是悟玄人，霹靂光中轟一咄。"]'),
('21db4b2a-6e21-4007-8fe8-d393b0b5d4c2','吳公明求贊','釋清遠','宋','宋诗','song-poetry','','[]','欲識坦然老，乃是龍門人。',48,'全唐诗/poet.song.73000.json','["欲識坦然老，乃是龍門人。", "聲名落四方，坐卧今十春。", "會見移庵去，何妨邈形真。", "平生香火緣，對比即神通。"]'),
('f2d055dc-c0ad-4c34-9296-87886cead441','張公壽求贊','釋清遠','宋','宋诗','song-poetry','','[]','首到東山，晚親龍岫。',40,'全唐诗/poet.song.73000.json','["首到東山，晚親龍岫。", "歲經寒暑，人非新舊。", "塗毒長鳴，優曇勿嗅。", "靜對終日，弟子公壽。"]'),
('35e81f12-5c9f-4c5a-8fb2-483e9923c31d','戴巨濟求贊','釋清遠','宋','宋诗','song-poetry','','[]','畫出人皆識，相逢道更親。',24,'全唐诗/poet.song.73000.json','["畫出人皆識，相逢道更親。", "起雲峰後路，記得往來頻。"]'),
('a1782b8c-ae21-4847-9a7f-a84fa7c08ebd','龍門常住圖師真知事求贊','釋清遠','宋','宋诗','song-poetry','','[]','寥廓無狀，孰爲龍門。',40,'全唐诗/poet.song.73000.json','["寥廓無狀，孰爲龍門。", "有指南路，絕刀斧痕。", "因緣去住，任物所論。", "黄竹寒湫，曉而復昏。"]'),
('d5f38057-0071-488b-8ee2-a42ad6cf9831','頌古六十二首  其一','釋清遠','宋','宋诗','song-poetry','','[]','杲日連天照有無，孰云善逝坐跏趺。',32,'全唐诗/poet.song.73000.json','["杲日連天照有無，孰云善逝坐跏趺。", "如今要見當年事，邪正猶來在半途。"]'),
('5c1d0682-e74b-49a0-9424-74a9a30ece94','頌古六十二首  其二','釋清遠','宋','宋诗','song-poetry','','[]','法王法令若爲酬，潦倒文殊强出頭。',32,'全唐诗/poet.song.73000.json','["法王法令若爲酬，潦倒文殊强出頭。", "負累釋迦猶可事，至今千古鬧啾啾。"]'),
('a7f0862a-de0b-4439-a96c-30ea5341f605','頌古六十二首  其三','釋清遠','宋','宋诗','song-poetry','','[]','百萬人天望舉揚，拈花微笑大乖張。',32,'全唐诗/poet.song.73000.json','["百萬人天望舉揚，拈花微笑大乖張。", "幾多業識茫茫者，問著勞生沸似湯。"]'),
('99ed19cb-597d-413d-a6c7-d70ee59b87bb','頌古六十二首  其四','釋清遠','宋','宋诗','song-poetry','','[]','若有絲毫付與人，可師何得更全身。',32,'全唐诗/poet.song.73000.json','["若有絲毫付與人，可師何得更全身。", "人間天上迷逢處，八兩元來是半斤。"]'),
('5bb41271-f907-48c8-8efe-0c49e14432a1','頌古六十二首  其五','釋清遠','宋','宋诗','song-poetry','','[]','非風幡動唯心動，大海波瀾常洶湧。',48,'全唐诗/poet.song.73000.json','["非風幡動唯心動，大海波瀾常洶湧。", "魚龍出沒任昇沉，生死聖凡無別共。", "無別共底怎麽樣，祖佛傍觀空合掌。"]'),
('7f12acb6-84fe-45b1-9d7b-68005d10ab91','頌古六十二首  其六','釋清遠','宋','宋诗','song-poetry','','[]','潦倒江湖上，竿頭事可咍。',24,'全唐诗/poet.song.73000.json','["潦倒江湖上，竿頭事可咍。", "一回浮子動，又是上鈎來。"]'),
('e1d30930-e698-4c6c-a10d-9ae1b702e464','頌古六十二首  其七','釋清遠','宋','宋诗','song-poetry','','[]','草裏尋常萬萬千，報云飛去豈徒然。',32,'全唐诗/poet.song.73000.json','["草裏尋常萬萬千，報云飛去豈徒然。", "鼻頭是甚閑皮草，十字縱橫一任穿。"]'),
('73cf3398-c384-4ad9-888b-4b7025d33550','頌古六十二首  其八','釋清遠','宋','宋诗','song-poetry','','[]','一回思想一傷神，不覺翻然笑轉新。',32,'全唐诗/poet.song.73000.json','["一回思想一傷神，不覺翻然笑轉新。", "雲在嶺頭閑不徹，水流澗下太忙生。"]'),
('4ee65087-7c1c-4e75-aa53-954cd2ca8b98','頌古六十二首  其九','釋清遠','宋','宋诗','song-poetry','','[]','挂得帆來遇便風，須臾千里到家鄉。',32,'全唐诗/poet.song.73000.json','["挂得帆來遇便風，須臾千里到家鄉。", "臨門上岸逢妻子，歡喜情懷不可當。"]'),
('c82e00bb-8c03-4675-b3c5-e68dcb26acd8','頌古六十二首  其一○','釋清遠','宋','宋诗','song-poetry','','[]','挂拂遭呵耳便聾，衲僧奚若驗宗風。',32,'全唐诗/poet.song.73000.json','["挂拂遭呵耳便聾，衲僧奚若驗宗風。", "金剛腦後抽生鐵，華岳三峰倒卓空。"]'),
('33e459c2-5d63-45d9-9b46-ec8bbdf80c8f','頌古六十二首  其一一','釋清遠','宋','宋诗','song-poetry','','[]','家肥生孝子，國霸有謀臣。',24,'全唐诗/poet.song.73000.json','["家肥生孝子，國霸有謀臣。", "拳頭劈口槌，未到無兒孫。"]'),
