('abf28569-17cb-4e46-9008-44b287584123','頌古六十二首  其五六','釋清遠','宋','宋诗','song-poetry','','[]','出得出不得，初不離是定。',52,'全唐诗/poet.song.73000.json','["出得出不得，初不離是定。", "聖者起凡情，凡人而乃聖。", "倒用與橫拈，扶邪及顯正。", "春雨春風竹戶凉，落花啼鳥千峰靜。"]'),
('2dfc864e-5fca-456f-b7e3-1f544445c3e1','頌古六十二首  其五七','釋清遠','宋','宋诗','song-poetry','','[]','平生心膽向人傾，到此門中有幾人。',32,'全唐诗/poet.song.73000.json','["平生心膽向人傾，到此門中有幾人。", "別後都城舊知己，暖烟斜日又黄昏。"]'),
('f5b3e1fb-0d3e-47c7-9e80-fd6c4214f9d0','頌古六十二首  其五八','釋清遠','宋','宋诗','song-poetry','','[]','佛手馿脚生緣，黄龍元無此語。',42,'全唐诗/poet.song.73000.json','["佛手馿脚生緣，黄龍元無此語。", "直饒恁麽知之，我儂亦未相許。", "奉報四海禪人，第一不得錯舉。"]'),
('dbe90d2d-58e4-47e2-b1d5-eaaf2fd45868','頌古六十二首  其五九','釋清遠','宋','宋诗','song-poetry','','[]','著眼看來寧免瞎，全身何用佩金魚。',32,'全唐诗/poet.song.73000.json','["著眼看來寧免瞎，全身何用佩金魚。", "黄龍意氣雄豪甚，祇爲他家不識書。"]'),
('ef0b1241-8f9b-4a38-a18f-b6f3b9d46fce','頌古六十二首  其六○','釋清遠','宋','宋诗','song-poetry','','[]','盡力不柰何，按牛頭喫草。',24,'全唐诗/poet.song.73000.json','["盡力不柰何，按牛頭喫草。", "若無錦繡文，難以論嘉藻。"]'),
('d7a4d298-e67f-4714-a8df-f302edd21094','頌古六十二首  其六一','釋清遠','宋','宋诗','song-poetry','','[]','何故喚作手，衲僧難開口。',24,'全唐诗/poet.song.73000.json','["何故喚作手，衲僧難開口。", "擬議自顢頇，可憐大蒙斗。"]'),
('5ecb1ad0-1d5e-4bbd-aaa2-a21144c95ab0','頌古六十二首  其六二','釋清遠','宋','宋诗','song-poetry','','[]','彼此且無相負累，行人無不失鈎錐。',32,'全唐诗/poet.song.73000.json','["彼此且無相負累，行人無不失鈎錐。", "雖然不瞎衆生眼，也好拳頭劈口槌。"]'),
('8e3de578-ac07-40bd-a665-1979d86c211f','偈頌一一二首  其一','釋清遠','宋','宋诗','song-poetry','','[]','世尊拈花，迦葉微笑。',40,'全唐诗/poet.song.73000.json','["世尊拈花，迦葉微笑。", "親切親切，省要省要。", "眼目定動，料料掉掉。", "爲報先生，莫打之遶。"]'),
('d6494092-f073-462e-b57f-43beba1f8187','偈頌一一二首  其二','釋清遠','宋','宋诗','song-poetry','','[]','兩岸蘆花一葉舟，凉風深夜月如鈎。',32,'全唐诗/poet.song.73000.json','["兩岸蘆花一葉舟，凉風深夜月如鈎。", "絲綸千尺慵拋放，歸到家山即便休。"]'),
('7e49a0b2-ee19-443a-b167-1d458e18473e','偈頌一一二首  其三','釋清遠','宋','宋诗','song-poetry','','[]','揮戈佛日不西流，照徹人間洞九幽。',32,'全唐诗/poet.song.73000.json','["揮戈佛日不西流，照徹人間洞九幽。", "從此安居無一事，休將玄妙挂心頭。"]'),
('468a17f3-6865-4031-a448-98da12b87848','偈頌一一二首  其四','釋清遠','宋','宋诗','song-poetry','','[]','昨朝六月二十六，無角鐵牛生四足。',60,'全唐诗/poet.song.73000.json','["昨朝六月二十六，無角鐵牛生四足。", "哮吼一聲人未知，撼動天關并地軸。", "隻履又西歸，唱罷胡家曲。", "可憐末後太分明，無限清聲徧溪谷。"]'),
('84872b9d-9738-4d87-81ba-2785c4867759','偈頌一一二首  其五','釋清遠','宋','宋诗','song-poetry','','[]','棒喝齊施古佛宗，三玄三要絕狐蹤。',32,'全唐诗/poet.song.73000.json','["棒喝齊施古佛宗，三玄三要絕狐蹤。", "白雲消散青山在，明月蘆花對蓼紅。"]'),
('fd8415c0-67d0-49a2-90ec-65d87c4ce070','偈頌一一二首  其六','釋清遠','宋','宋诗','song-poetry','','[]','浄名居士在家人，不二門深入者親。',32,'全唐诗/poet.song.73000.json','["浄名居士在家人，不二門深入者親。", "一鉢上方香積飯，寥寥千古轉通津。"]'),
('3d771915-1bc0-4cae-a851-a616ee6d534f','偈頌一一二首  其七','釋清遠','宋','宋诗','song-poetry','','[]','一與山門作境致，見者頓超無學地。',48,'全唐诗/poet.song.73000.json','["一與山門作境致，見者頓超無學地。", "二與後人作標牓，凡聖悟迷皆一樣。", "若是叢林向上關，有人踏著喜無量。"]'),
('96619bed-3868-40b3-9607-52906dc95e1f','偈頌一一二首  其八','釋清遠','宋','宋诗','song-poetry','','[]','少室無言語，曹溪有消息。',48,'全唐诗/poet.song.73000.json','["少室無言語，曹溪有消息。", "可憐門大開，而人不能入。", "蒼龍得雲雨，猛虎生羽翼。", "但解自承當，何勞問知識。"]'),
('6d7f2673-5ba5-40c2-8724-19c91cc8b31e','偈頌一一二首  其九','釋清遠','宋','宋诗','song-poetry','','[]','總記不得，天花滿裓。',20,'全唐诗/poet.song.73000.json','["總記不得，天花滿裓。", "縱有千言，不如一默。"]'),
('ab1fa6cf-61fc-4cf0-8a66-c30939e39494','偈頌一一二首  其一○','釋清遠','宋','宋诗','song-poetry','','[]','木伎機，石女兒。',60,'全唐诗/poet.song.73000.json','["木伎機，石女兒。", "三冬陽氣盛，六月降霜時。", "有語非干舌，無言切要詞。", "會我最後句，出世少人知。", "午齋晨粥無餘事，箋茗爐香話道奇。"]'),
('53ed370d-af43-4801-b932-109cbdf61b05','偈頌一一二首  其一一','釋清遠','宋','宋诗','song-poetry','','[]','普光明殿在人間，凡聖交羅絕往還。',32,'全唐诗/poet.song.73000.json','["普光明殿在人間，凡聖交羅絕往還。", "若向一塵親得見，毫光照處奉慈顔。"]'),
('f242a957-67c1-476b-822c-206d1b2a2016','偈頌一一二首  其一二','釋清遠','宋','宋诗','song-poetry','','[]','大衆盡皆雲集，僧堂橫吞佛殿。',73,'全唐诗/poet.song.73000.json','["大衆盡皆雲集，僧堂橫吞佛殿。", "露柱倒掛燈籠，天高地厚，月白風清。", "雨順風調，河清海晏。", "饑則共君餐苦菜，渴則與子飲寒泉。", "直饒天外雨花飛，爭似歸堂喫茶去。"]'),
('8b971886-dd88-456d-8b2e-1fc37a9e4e77','偈頌一一二首  其一三','釋清遠','宋','宋诗','song-poetry','','[]','臺山路上，過客全稀。',46,'全唐诗/poet.song.73000.json','["臺山路上，過客全稀。", "破竈堂前，感恩無地。", "雪埋庭柏，冰鎖偃溪。", "雖在南方火爐頭，不入他家虀甕裏。"]'),
('fc35a940-f9ec-4b49-906f-a09e5dc7b094','偈頌一一二首  其一四','釋清遠','宋','宋诗','song-poetry','','[]','露柱多年出家，燈籠久已落髮。',55,'全唐诗/poet.song.73000.json','["露柱多年出家，燈籠久已落髮。", "佛殿堅持禁戒，三門近得休歇。", "大事本來平等無著，清凉滿月度盡草木，叢林一似陽和齊發。"]'),
('b34a238a-8e48-4ede-938d-f0e3a811e979','偈頌一一二首  其一五','釋清遠','宋','宋诗','song-poetry','','[]','萬物咸新論故鄉，擡眸元是舊爺娘。',32,'全唐诗/poet.song.73000.json','["萬物咸新論故鄉，擡眸元是舊爺娘。", "先春花發馨香遠，物外山河日月長。"]'),
('125a5beb-58b0-45b1-a928-54a7638a5f78','偈頌一一二首  其一六','釋清遠','宋','宋诗','song-poetry','','[]','悟時此事元來易，迷後斯門實大難。',32,'全唐诗/poet.song.73000.json','["悟時此事元來易，迷後斯門實大難。", "處處綠楊堪繫馬，家家門口透長安。"]'),
('189d1117-247e-493d-a464-f6b7fdf68d4d','偈頌一一二首  其一七','釋清遠','宋','宋诗','song-poetry','','[]','三月初三二月二，不壞假名談大義。',64,'全唐诗/poet.song.73000.json','["三月初三二月二，不壞假名談大義。", "衆生役役趁光陰，道流所以爲虛棄。", "二月念九三月一，摩訶般若波羅蜜。", "假使多聞達古今，歷劫何曾異今日。"]'),
('61d1bef2-bfca-4c5a-aa52-ead2d8b8e873','偈頌一一二首  其一八','釋清遠','宋','宋诗','song-poetry','','[]','如來妙色身，真實難藏覆。',52,'全唐诗/poet.song.73000.json','["如來妙色身，真實難藏覆。", "不掛本來衣，豈著娘生袴。", "無憂樹下降生時，南北東西行七步。", "行七步，度盡衆生無所度。"]'),
('ef3c0ed0-e97e-4ca9-8659-118d4e79893e','偈頌一一二首  其一九','釋清遠','宋','宋诗','song-poetry','','[]','昨日如來垂法雨，今朝法雨洗如來。',46,'全唐诗/poet.song.73000.json','["昨日如來垂法雨，今朝法雨洗如來。", "了然一味無差別，雲外青山朵朵開。", "欲報如來深恩，殿上重新浴過。"]'),
('755e00e4-f39c-47ea-bcf4-3be6354467e4','偈頌一一二首  其二○','釋清遠','宋','宋诗','song-poetry','','[]','龍門結夏勝諸方，大地山河爲舉揚。',32,'全唐诗/poet.song.73000.json','["龍門結夏勝諸方，大地山河爲舉揚。", "若向九旬參得透，更無佛法可商量。"]'),
('9f226e52-e82a-4b79-8693-4d44eadde129','偈頌一一二首  其二一','釋清遠','宋','宋诗','song-poetry','','[]','了知一，萬事畢，釋迦彌勒欣今日。',46,'全唐诗/poet.song.73000.json','["了知一，萬事畢，釋迦彌勒欣今日。", "但得心安是處安，無災無難無今昔。", "要知佛法根源，記取五月初一。"]'),
('5d456e50-a770-4243-804e-ee5c40a1adb0','偈頌一一二首  其二二','釋清遠','宋','宋诗','song-poetry','','[]','入得龍門事事奇，聞聲見色不思議。',32,'全唐诗/poet.song.73000.json','["入得龍門事事奇，聞聲見色不思議。", "山青水綠緣何事，盡是諸人力使之。"]'),
('06491be3-b630-40aa-a3d3-45b1624b4dbd','偈頌一一二首  其二三','釋清遠','宋','宋诗','song-poetry','','[]','先師當年末後句，與人皮下挑出刺。',64,'全唐诗/poet.song.73000.json','["先師當年末後句，與人皮下挑出刺。", "譬如六月日中冰，銷鎔處處皆相似。", "後來聽響各流傳，更加一二與三四。", "箇中孰是無耳人，明見去來不生死。"]'),
('d3bcbacf-950f-42e8-a0d5-7d1d6572624d','偈頌一一二首  其二四','釋清遠','宋','宋诗','song-poetry','','[]','世人盡道路行難，本分真金入火看。',32,'全唐诗/poet.song.73000.json','["世人盡道路行難，本分真金入火看。", "煉去煉來金體浄，一槌打作玉欄干。"]'),
('e9b9a009-390c-43ae-a9df-855676b92cc0','偈頌一一二首  其二五','釋清遠','宋','宋诗','song-poetry','','[]','一竿一笠一蓑衣，急水灘頭下釣絲。',32,'全唐诗/poet.song.73000.json','["一竿一笠一蓑衣，急水灘頭下釣絲。", "鈎上錦鱗容易得，蘆花深處月明歸。"]'),
('62660219-cc97-4cdc-8e1e-de044d9f6b86','偈頌一一二首  其二六','釋清遠','宋','宋诗','song-poetry','','[]','打動龍門鼓，喚起鐵餕餡。',48,'全唐诗/poet.song.73000.json','["打動龍門鼓，喚起鐵餕餡。", "請君一咬破，山僧豈相賺。", "先師曾得力，滋味今不減。", "若也不柰何，好箇鐵餕餡。"]'),
('0a4f50dc-8612-45f8-bac7-2daea38c5a6f','偈頌一一二首  其二七','釋清遠','宋','宋诗','song-poetry','','[]','親從家裏來，家中何所有。',48,'全唐诗/poet.song.73000.json','["親從家裏來，家中何所有。", "持此一片石，廣大堅且久。", "靈山曾獻佛，帝釋聊舉手。", "心中出何物，安樂并長壽。"]'),
('7541ee2b-aa8d-4bf5-86da-3b2ac4da9d75','偈頌一一二首  其二八','釋清遠','宋','宋诗','song-poetry','','[]','圓明了知，不由心念。',20,'全唐诗/poet.song.73000.json','["圓明了知，不由心念。", "抵死要道，墮坑落塹。"]'),
('ed69b24e-7282-4cb7-b835-92463946f44d','偈頌一一二首  其二九','釋清遠','宋','宋诗','song-poetry','','[]','容顔甚奇妙，光明照十方。',24,'全唐诗/poet.song.73000.json','["容顔甚奇妙，光明照十方。", "我適曾供養，今復還親覲。"]'),
('d3293aa2-6a64-41b8-b76d-89f4adf6d198','偈頌一一二首  其三○','釋清遠','宋','宋诗','song-poetry','','[]','擬思量，何劫悟。',44,'全唐诗/poet.song.73000.json','["擬思量，何劫悟。", "不思量，終莽鹵。", "欲思不思踏破時，萬里無雲常顯露。", "常顯露，妙用恒沙非旦暮。"]'),
('a7cc373c-bc1f-41a6-b2cf-1b6263406fb3','偈頌一一二首  其三一','釋清遠','宋','宋诗','song-poetry','','[]','來來去去去來時，去去來來離覺知。',32,'全唐诗/poet.song.73000.json','["來來去去去來時，去去來來離覺知。", "了得去來無罣礙，方知塵劫不思議。"]'),
('dd9d9830-e510-4ee0-a9c4-5c706e603736','偈頌一一二首  其三二','釋清遠','宋','宋诗','song-poetry','','[]','徧界不藏全體露，絲毫有見事還差。',32,'全唐诗/poet.song.73000.json','["徧界不藏全體露，絲毫有見事還差。", "會中誰是先陀客，不動纖塵便到家。"]'),
('ef1f8f4a-10a5-45db-ac4e-7bf80d17ebdd','偈頌一一二首  其三三','釋清遠','宋','宋诗','song-poetry','','[]','獨自坐方信，西來有達磨。',64,'全唐诗/poet.song.73000.json','["獨自坐方信，西來有達磨。", "獨自行不用，紅蓮足下生。", "獨自語分明，向誰誰肯許。", "獨自參剎剎，塵塵示指南。", "相逢相問窮端的，莫道山僧解放憨。"]'),
('4d149f88-2be0-40ec-81a0-f7b2bb193da9','偈頌一一二首  其三四','釋清遠','宋','宋诗','song-poetry','','[]','昔人已乘白雲去，此地空餘綠水流。',80,'全唐诗/poet.song.73000.json','["昔人已乘白雲去，此地空餘綠水流。", "綠水一去不復返，白雲千載空悠悠。", "湖南舊說老楊岐，失却金毛師子兒。", "江南江北無覓處，龍門今日順風吹。", "順風吹，囉囉哩，水急風高下釣磯。"]'),
('c0a23bd2-5261-4b82-bea8-dad70e96639a','偈頌一一二首  其三五','釋清遠','宋','宋诗','song-poetry','','[]','鳥從空裏飛，人向心中住。',48,'全唐诗/poet.song.73000.json','["鳥從空裏飛，人向心中住。", "人死心宛然，鳥沒空何預。", "人生一過鳥，此心實可據。", "但自了其心，無勞問來去。"]'),
('300659fb-7499-4d75-a0d9-bc21fd5dd304','偈頌一一二首  其三六','釋清遠','宋','宋诗','song-poetry','','[]','龍門別無奇妙，剛謂單傳心要。',56,'全唐诗/poet.song.73000.json','["龍門別無奇妙，剛謂單傳心要。", "豈惟淺水無魚，撥剔全無孔竅。", "二時展鉢開單，逐日屙屎送尿。", "萬事與人一般，子細看來好笑。"]'),
('4acdb8b3-3162-42a6-b7af-baf39fc7e725','偈頌一一二首  其三七','釋清遠','宋','宋诗','song-poetry','','[]','會既少，舉尤難，叢林雖有日凋殘。',40,'全唐诗/poet.song.73000.json','["會既少，舉尤難，叢林雖有日凋殘。", "若欲明斯旨，應須離念看。", "一人如領解，大衆盡心安。"]'),
('47259262-09bf-4811-82a5-8a6b0053ec2d','偈頌一一二首  其三八','釋清遠','宋','宋诗','song-poetry','','[]','狸奴白牯念摩訶，貓兒狗子長相見。',40,'全唐诗/poet.song.73000.json','["狸奴白牯念摩訶，貓兒狗子長相見。", "諸禪客，薦不薦。", "若言自性本圓明，大似捫空追閃電。"]'),
('6bacae1d-1e97-4d68-978b-2f0a74b93021','偈頌一一二首  其三九','釋清遠','宋','宋诗','song-poetry','','[]','不動龍門內，行參古佛機。',48,'全唐诗/poet.song.73000.json','["不動龍門內，行參古佛機。", "親逢渠面目，肯話自容儀。", "凡聖心平等，高低路坦夷。", "丹霞燒木佛，院主落鬚眉。"]'),
('d4933803-5a51-48a0-be81-631311ea399d','偈頌一一二首  其四○','釋清遠','宋','宋诗','song-poetry','','[]','正當恁麽時，歷劫不曾迷。',24,'全唐诗/poet.song.73000.json','["正當恁麽時，歷劫不曾迷。", "步步超三界，歸家頓絕疑。"]'),
('0be49b50-206c-4ad2-a072-7908175562e2','偈頌一一二首  其四一','釋清遠','宋','宋诗','song-poetry','','[]','幾回生，幾回死，生死悠悠無定止。',32,'全唐诗/poet.song.73000.json','["幾回生，幾回死，生死悠悠無定止。", "自從頓悟了無生，於諸榮辱何憂喜。"]'),
('c2b8439e-7967-4fe3-8bf1-32ddc503b88d','偈頌一一二首  其四二','釋清遠','宋','宋诗','song-poetry','','[]','五色燈光眚所成，但除其眚莫除塵。',32,'全唐诗/poet.song.73000.json','["五色燈光眚所成，但除其眚莫除塵。", "若言本眼何曾眚，乃是臨河渴死人。"]'),
('8e5abc37-5b0b-4972-b875-b2b4dacbc555','偈頌一一二首  其四三','釋清遠','宋','宋诗','song-poetry','','[]','劫火威音前，雖有一壺天。',24,'全唐诗/poet.song.73000.json','["劫火威音前，雖有一壺天。", "御樓看射獵，不是刈茅田。"]'),
('e0971fa3-339b-40cb-8256-321c790297bf','偈頌一一二首  其四四','釋清遠','宋','宋诗','song-poetry','','[]','臘月扇子功勳絕，浩浩凉風動寥泬。',32,'全唐诗/poet.song.73000.json','["臘月扇子功勳絕，浩浩凉風動寥泬。", "豈止炎蒸六月天，暫時與君解煩熱。"]'),
('42de3a0f-7720-4cb2-8b16-09285e7dcc00','偈頌一一二首  其四五','釋清遠','宋','宋诗','song-poetry','','[]','泡幻同無礙，如何不了悟。',40,'全唐诗/poet.song.73000.json','["泡幻同無礙，如何不了悟。", "眼裏瞳人吹叫子，達法在其中。", "非今亦非古，六隻骰子滿盆紅。"]'),
('35e66570-9ba5-4be4-a54e-69f34c7ed1f2','偈頌一一二首  其四六','釋清遠','宋','宋诗','song-poetry','','[]','諸人未到龍門山，將道龍門在世間。',32,'全唐诗/poet.song.73000.json','["諸人未到龍門山，將道龍門在世間。", "既到龍門心自在，杉松拂拂水潺潺。"]'),
('3572e2e9-dc2d-4998-b1e0-808a12a707e7','偈頌一一二首  其四七','釋清遠','宋','宋诗','song-poetry','','[]','龍門三月半，大鼓聲聲喚。',24,'全唐诗/poet.song.73000.json','["龍門三月半，大鼓聲聲喚。", "喚得一時來，特地生迷亂。"]'),
('13844280-43ba-4504-a58b-01aa59116068','偈頌一一二首  其四八','釋清遠','宋','宋诗','song-poetry','','[]','收得本名度牒，踏遍自己山川。',56,'全唐诗/poet.song.73000.json','["收得本名度牒，踏遍自己山川。", "聞有龍門長老，走來學道參禪。", "恁麽惺惺漢子，如何立地瞌眠。", "忽然睡醒眼開，元來天生自然。"]'),
('8145cc0d-7be0-446c-918b-f76c9a2cda14','偈頌一一二首  其四九','釋清遠','宋','宋诗','song-poetry','','[]','思無思思，萬邪一正。',20,'全唐诗/poet.song.73000.json','["思無思思，萬邪一正。", "不識玄旨，徒勞念靜。"]'),
('6bb5464b-71c2-4792-bd41-1ee1e47df885','偈頌一一二首  其五○','釋清遠','宋','宋诗','song-poetry','','[]','作無作作，貫色通聲。',20,'全唐诗/poet.song.73000.json','["作無作作，貫色通聲。", "水中鹽味，不見其形。"]'),
('e544ae7d-0b49-4d6e-a556-360fd833864d','偈頌一一二首  其五一','釋清遠','宋','宋诗','song-poetry','','[]','言無言言，不費脣舌。',20,'全唐诗/poet.song.73000.json','["言無言言，不費脣舌。", "未說之法，林中之葉。"]'),
('663c5590-667b-4fe4-8697-8d5093caa25e','偈頌一一二首  其五二','釋清遠','宋','宋诗','song-poetry','','[]','龍門潦倒，告報諸人。',20,'全唐诗/poet.song.73000.json','["龍門潦倒，告報諸人。", "既然如是，何故因循。"]'),
('34d7b783-ac97-47e8-9f0e-031df29ad908','偈頌一一二首  其五三','釋清遠','宋','宋诗','song-poetry','','[]','一葉飄瓢水上歸，姑蘇春色照岩扉。',32,'全唐诗/poet.song.73000.json','["一葉飄瓢水上歸，姑蘇春色照岩扉。", "坐禪片石重來看，却笑山雲拂蘚衣。"]'),
('1d591736-ba16-4720-a752-a49ce08c6239','偈頌一一二首  其五四','釋清遠','宋','宋诗','song-poetry','','[]','杜順文殊事可知，定光如來老大隋。',64,'全唐诗/poet.song.73000.json','["杜順文殊事可知，定光如來老大隋。", "張三李四何王趙，問你渠今是阿誰。", "廛市賣魚忘進趣，案頭分肉露全機。", "男兒鎖子黄金骨，苦痛無明墮汙泥。"]'),
('e3d927bf-36a0-47f7-a0a3-2d2331f64cdb','偈頌一一二首  其五五','釋清遠','宋','宋诗','song-poetry','','[]','登龍門下無凡客，不假風雷自有奇。',32,'全唐诗/poet.song.73000.json','["登龍門下無凡客，不假風雷自有奇。", "三月進修從此始，經行宴坐可思議。"]'),
('ee2b180d-63c5-4c28-9609-1f46e4eec89d','偈頌一一二首  其五六','釋清遠','宋','宋诗','song-poetry','','[]','十方世界龍門寺，大地山河是學徒。',32,'全唐诗/poet.song.73000.json','["十方世界龍門寺，大地山河是學徒。", "隨順衆緣成解脫，算來全不費工夫。"]'),
('e23cd7e4-fda9-4808-987f-a0ce9f51c3ae','偈頌一一二首  其五七','釋清遠','宋','宋诗','song-poetry','','[]','豈可喚鍾作甕，終不指鹿爲馬。',38,'全唐诗/poet.song.73000.json','["豈可喚鍾作甕，終不指鹿爲馬。", "善人難犯，水銀無假。", "冷地忽然覷破，管取一時放下。"]'),
('dd26f03d-8378-4bfd-8289-bf1c0d11e656','偈頌一一二首  其五八','釋清遠','宋','宋诗','song-poetry','','[]','龍門若爲作端午，打動衆人塗毒鼓。',64,'全唐诗/poet.song.73000.json','["龍門若爲作端午，打動衆人塗毒鼓。", "髑髏破後遣誰聞，鑒覺盡時敢言普。", "是謂南山鼈鼻蛇，好箇大雄白額虎。", "可憐開眼覓眼人，嚇日光中尋入路。"]'),
('819a84ea-1937-465a-8268-4bd94e43c21b','偈頌一一二首  其五九','釋清遠','宋','宋诗','song-poetry','','[]','飄飄颻颻楊柳花，紅紅赤赤遠天霞。',64,'全唐诗/poet.song.73000.json','["飄飄颻颻楊柳花，紅紅赤赤遠天霞。", "屈屈曲曲龍門路，僻僻靜靜野僧家。", "尚不心頭懷勝解，誰能劫外筭河沙。", "休糧方子齋兼粥，任運還鄉苦澀茶。"]'),
('909e049b-d477-4fc6-9881-0688646b2cba','偈頌一一二首  其六○','釋清遠','宋','宋诗','song-poetry','','[]','七七四十九，面南看北斗。',24,'全唐诗/poet.song.73000.json','["七七四十九，面南看北斗。", "死去與生來，泥牛大哮吼。"]'),
('82d0b57f-01c7-4347-a6cd-b484c7783aec','偈頌一一二首  其六一','釋清遠','宋','宋诗','song-poetry','','[]','骨還父，肉還母。',50,'全唐诗/poet.song.73000.json','["骨還父，肉還母。", "何者是身，分明聽取。", "山河國土現全軀，十方世界在裏許。", "萬劫千生絕去來，山僧此說非言語。"]'),
('a0edcb98-8bed-42c9-8cf2-9e8ded61a73c','偈頌一一二首  其六二','釋清遠','宋','宋诗','song-poetry','','[]','總別同異兼成壞，祇是山僧與衆人。',64,'全唐诗/poet.song.73000.json','["總別同異兼成壞，祇是山僧與衆人。", "高廣須彌入芥子，無邊剎海在微塵。", "晝復夜，秋復春，境寂心融事事真。", "七寶大車既如此，去來語默莫因循。"]'),
('d97c0d43-2d2a-4871-a9e5-e5d787697d8b','偈頌一一二首  其六三','釋清遠','宋','宋诗','song-poetry','','[]','𮭗𮭗鳥，守空池。',20,'全唐诗/poet.song.73000.json','["𮭗𮭗鳥，守空池。", "魚從脚下過，𮭗𮭗總不知。"]'),
('cfbfb1e2-3041-4fce-8821-74634dfaa028','偈頌一一二首  其六四','釋清遠','宋','宋诗','song-poetry','','[]','趙州不見南泉，山僧不識五祖。',28,'全唐诗/poet.song.73000.json','["趙州不見南泉，山僧不識五祖。", "甜瓜徹蒂自甜，苦瓠連根自苦。"]'),
('8bbd6301-3a0a-4eaf-ba9e-ae89e244372c','偈頌一一二首  其六五','釋清遠','宋','宋诗','song-poetry','','[]','尊者憍陳如，九旬最親切。',48,'全唐诗/poet.song.73000.json','["尊者憍陳如，九旬最親切。", "老少幸相依，上下皆歡悅。", "瞻聽離聞見，承覽亦超絕。", "四海五湖人，勿謂真機泄。"]'),
('60198362-7dfd-4d11-8022-30de36cb893d','偈頌一一二首  其六六','釋清遠','宋','宋诗','song-poetry','','[]','開一片田，密密綿綿。',57,'全唐诗/poet.song.73000.json','["開一片田，密密綿綿。", "兩頓粥飯，其道自辦。", "山僧一夏，與諸人相見。", "自是諸人不薦，若或薦成一片。", "是什麽一片，看取當門箭。"]'),
('7410a97e-1d4b-4bae-94dc-230cff9a9b3e','偈頌一一二首  其六七','釋清遠','宋','宋诗','song-poetry','','[]','一漏逗，二漏逗，三漏逗，用意攙前先在後。',68,'全唐诗/poet.song.73000.json','["一漏逗，二漏逗，三漏逗，用意攙前先在後。", "莫於佛祖結冤親，好看衣珠常離垢。", "家中人，鬭頭走，淮南笑殺龍門叟。", "有人若會笑因由，眼似銅鈴大如斗。"]'),
('dcd14233-9e59-4b40-a836-fd7b12801f2d','偈頌一一二首  其六八','釋清遠','宋','宋诗','song-poetry','','[]','木平山裏人，貌古言復少。',48,'全唐诗/poet.song.73000.json','["木平山裏人，貌古言復少。", "相看陌路同，論心秋月皎。", "壞衲線非蠶，助歌聲有鳥。", "城郭今日來，一漚曾已曉。"]'),
('bea7f9a2-b2c4-49ec-ac5c-fea97bb8b928','偈頌一一二首  其六九','釋清遠','宋','宋诗','song-poetry','','[]','一漚未發時，寶蓋向空垂。',48,'全唐诗/poet.song.73000.json','["一漚未發時，寶蓋向空垂。", "瑞色飄飄起，香風拂拂吹。", "何勞輕舉拂，不假略揚眉。", "五百曾親獻，如來印可之。"]'),
('daf7066d-366f-4f84-a86f-e5ffe1a889ba','偈頌一一二首  其七○','釋清遠','宋','宋诗','song-poetry','','[]','百丈說大義，辛勤事可知。',48,'全唐诗/poet.song.73000.json','["百丈說大義，辛勤事可知。", "龍門無道理，大衆絕狐疑。", "帝力乾坤重，君恩雨露垂。", "有人相借問，雲外略揚眉。"]'),
('2c6d1445-4c64-40d5-8291-4edbcb82402d','偈頌一一二首  其七一','釋清遠','宋','宋诗','song-poetry','','[]','鼓聲纔動，法義已周。',48,'全唐诗/poet.song.73000.json','["鼓聲纔動，法義已周。", "大衆上來，尋光而至。", "山野高提祖印，諸人共息狐疑。", "直須倒岳傾湫，切莫尋枝摘葉。"]'),
('5b653a92-18dd-4550-a672-64b51be4fe0f','偈頌一一二首  其七二','釋清遠','宋','宋诗','song-poetry','','[]','南閻浮提人，就中多鬧亂。',83,'全唐诗/poet.song.73000.json','["南閻浮提人，就中多鬧亂。", "無想四禪天，根性最遲緩。", "遲速不同倫，染浄難回換。", "兩箇五伯文，元來是一貫。", "貫貫，啞子拍手高聲喚，聾人聽得佯不管。", "天明日出是夜半，智者大師譚止觀。"]'),
('89ec9c2d-e6e4-4ca1-b4b5-5cf5ebe1c463','偈頌一一二首  其七三','釋清遠','宋','宋诗','song-poetry','','[]','死心心已死，心死死由生。',24,'全唐诗/poet.song.73000.json','["死心心已死，心死死由生。", "拗折黄龍角，翻身卧地行。"]'),
('d30123a7-3a00-49a5-a860-5520681707ba','偈頌一一二首  其七四','釋清遠','宋','宋诗','song-poetry','','[]','虛名虛相，谷音鑑像。',40,'全唐诗/poet.song.73000.json','["虛名虛相，谷音鑑像。", "棄而不修，豈明幻妄。", "少不努力，老矣惆悵。", "靜以思之，隨機稱量。"]'),
('ed1d963d-be8e-4898-8196-f47887271aae','偈頌一一二首  其七五','釋清遠','宋','宋诗','song-poetry','','[]','一葉落，天下春。',64,'全唐诗/poet.song.73000.json','["一葉落，天下春。", "無路尋思笑殺人。", "下是天，上是地，此言不入時流意。", "南作北，東作西，動而止，喜而悲。", "蛇頭蝎尾一試之，猛虎口裏活雀兒。"]'),
('03f824ad-6684-4a88-ad1e-0d8197a8e741','偈頌一一二首  其七六','釋清遠','宋','宋诗','song-poetry','','[]','眉毛眼睫最相親，鼻孔脣皮作近鄰。',32,'全唐诗/poet.song.73000.json','["眉毛眼睫最相親，鼻孔脣皮作近鄰。", "至近因何不相見，都緣一體是全身。"]'),
('6437e9fa-7e63-43a1-9deb-38019d515e89','偈頌一一二首  其七七','釋清遠','宋','宋诗','song-poetry','','[]','昔開正續銘，今示真歸告。',48,'全唐诗/poet.song.73000.json','["昔開正續銘，今示真歸告。", "一路涅槃門，行說皆親到。", "明然臨濟燈，妙唱黄龍道。", "空海久澄虛，雲濤方浩浩。"]'),
('14e5d36b-1d66-46fa-9326-1b219af03819','偈頌一一二首  其七八','釋清遠','宋','宋诗','song-poetry','','[]','西瞿耶尼打鼓，南瞻部州上堂。',56,'全唐诗/poet.song.73000.json','["西瞿耶尼打鼓，南瞻部州上堂。", "大衆十方齊至，等閒野客稱揚。", "此聲徧滿十方，照破聞見色香。", "堪笑釋迦老子，等閒動地放光。"]'),
('788163c8-e7af-428d-a3cf-499c603f3b6e','偈頌一一二首  其七九','釋清遠','宋','宋诗','song-poetry','','[]','何處求通達，疑根自不凡。',48,'全唐诗/poet.song.73000.json','["何處求通達，疑根自不凡。", "頓明心即佛，徒覺海非鹹。", "善財樓閣路，日進丹霄步。", "凡夫云未然，我道常披露。"]'),
('4ae5612a-8e8c-4017-a57f-9d5ded05b53c','偈頌一一二首  其八○','釋清遠','宋','宋诗','song-poetry','','[]','大丈夫，秉慧劍，般若鋒兮金剛焰。',32,'全唐诗/poet.song.73000.json','["大丈夫，秉慧劍，般若鋒兮金剛焰。", "非道能摧外道心，早曾落却天魔膽。"]'),
('34b0e209-45e4-402f-8d99-165164b1bd48','偈頌一一二首  其八一','釋清遠','宋','宋诗','song-poetry','','[]','慮而解，思而知，孤燈難並太陽輝。',48,'全唐诗/poet.song.73000.json','["慮而解，思而知，孤燈難並太陽輝。", "不是心，不是佛，爲君掃蕩精靈窟。", "摩天鷂子入雲飛，千里萬里祇一突。"]'),
('298eb941-40b1-407d-aacb-b2e46a5c987a','偈頌一一二首  其八二','釋清遠','宋','宋诗','song-poetry','','[]','不起疏慵不進修，實無言說實無求。',56,'全唐诗/poet.song.73000.json','["不起疏慵不進修，實無言說實無求。", "奪饑人口中之食，驅耕者手裏之牛。", "真快活，百無憂。", "自是不歸歸便得，五湖風流拍天流。"]'),
('83520d67-9abb-44ec-8894-a40fe0998cea','偈頌一一二首  其八三','釋清遠','宋','宋诗','song-poetry','','[]','若論佛，祇是當人更無物。',112,'全唐诗/poet.song.73000.json','["若論佛，祇是當人更無物。", "若論頂，晝夜舒光照前境。", "若論心，看時無相用時深。", "若論經，解語能言不是聲。", "若論齋，所爲所作盡和諧。", "若論願，猶如身在龍門院。", "若論了，無慮無疑心皎皎。", "心皎皎，增添福壽災殃少。", "論量功德廣難思，須彌未大滄溟小。"]'),
('5d1b4bc7-457c-4a17-acf2-4b12d315b3d5','偈頌一一二首  其八四','釋清遠','宋','宋诗','song-poetry','','[]','一二三四五六七，諷誦受持皆祕密。',32,'全唐诗/poet.song.73000.json','["一二三四五六七，諷誦受持皆祕密。", "如人親入寶山中，一切珍奇從此出。"]'),
('4b880620-87f0-49ae-a458-ded40263adfe','偈頌一一二首  其八五','釋清遠','宋','宋诗','song-poetry','','[]','道可學耶實不可學，心可悟耶實不可悟。',54,'全唐诗/poet.song.73000.json','["道可學耶實不可學，心可悟耶實不可悟。", "不學不悟，真機全露。", "明月娑婆，浮生旦暮。", "眼若不睡諸夢除，古今出入無門戶。"]'),
('7be5b0dd-72cc-4254-a377-809b584c6efe','偈頌一一二首  其八六','釋清遠','宋','宋诗','song-poetry','','[]','山僧略陞此座，大衆永息狐疑。',56,'全唐诗/poet.song.73000.json','["山僧略陞此座，大衆永息狐疑。", "各各金毛師子，去來哮吼全威。", "臨濟高聲連喝，德山拈棒痛槌。", "縱有一言半句，終不別作路歧。"]'),
('94759b27-7381-46d7-803e-58c37b2a1ded','偈頌一一二首  其八七','釋清遠','宋','宋诗','song-poetry','','[]','出門便是草，閑殺龍門老。',58,'全唐诗/poet.song.73000.json','["出門便是草，閑殺龍門老。", "北去禮文殊，南來登五老。", "鬢髮已蒼浪，言歸恨不早。", "獨立秋風前，相思望江島。", "好，好，不用更尋討。"]'),
('8240ed29-718a-409c-8350-3238e4b8a533','偈頌一一二首  其八八','釋清遠','宋','宋诗','song-poetry','','[]','什麽物，恁麽來，休將明鏡挂高臺。',64,'全唐诗/poet.song.73000.json','["什麽物，恁麽來，休將明鏡挂高臺。", "什麽物，恁麽去，分明不用當頭舉。", "舉得分明得更難，澄潭不許蒼龍盤。", "便恁會，太無端，華藏毗盧世界寬。"]'),
('b149b6da-0179-498d-9fad-a3e031c75c58','偈頌一一二首  其八九','釋清遠','宋','宋诗','song-poetry','','[]','釋迦世尊已成正覺，彌勒大士當來下生。',100,'全唐诗/poet.song.73000.json','["釋迦世尊已成正覺，彌勒大士當來下生。", "老盧持過嶺南，達磨携來東土。", "各謂度生已畢，我願云周如何。", "六道四生猶在，土石諸山未殞。", "浄妙國土不逢，爲是願力未充。", "爲是業果難盡，爲復別有道理。", "若不同床睡，焉知被底穿。"]'),
('b6f328e3-33d3-4ce5-8264-3029c38d4c26','偈頌一一二首  其九○','釋清遠','宋','宋诗','song-poetry','','[]','空生不解巖中坐，春暖桃花樹樹紅。',68,'全唐诗/poet.song.73000.json','["空生不解巖中坐，春暖桃花樹樹紅。", "漏泄天機無覓處，都緣露柱挂燈籠。", "燈籠燈籠，却有古風。", "露柱露柱，善解提舉。", "一旦師姑是女兒，大悟堂中喫茶去。"]'),
('a29bf961-56c1-44e0-bf60-8bf8497165eb','偈頌一一二首  其九一','釋清遠','宋','宋诗','song-poetry','','[]','心是根，法是塵，兩種猶如鏡上痕。',68,'全唐诗/poet.song.73000.json','["心是根，法是塵，兩種猶如鏡上痕。", "痕垢盡時光始現，心法雙亡性即真。", "根塵既謝，鏡光現前。", "心法雙亡，如何則是。", "赤肐𩪸身無妄想，眼聞耳見離攀緣。"]'),
('8710b7e3-1e1d-4951-a2e0-3d46514212a1','偈頌一一二首  其九二','釋清遠','宋','宋诗','song-poetry','','[]','迎日出門去，已覺披烟霧。',72,'全唐诗/poet.song.73000.json','["迎日出門去，已覺披烟霧。", "冒月望山歸，重露濕禪衣。", "心悄悄，步遲遲。", "無孔笛，再三吹。", "哩哩邏，邏邏哩。", "遊子乍聞征袖濕，佳人猶唱翠眉低。", "君更聽，莫狐疑。"]'),
('30e6eb20-d12b-4a99-88b1-0bd5dc2c873f','偈頌一一二首  其九三','釋清遠','宋','宋诗','song-poetry','','[]','海門山，長安道，茫茫烟水連芳草。',56,'全唐诗/poet.song.73000.json','["海門山，長安道，茫茫烟水連芳草。", "樓頭客，馬上郎，一聽落梅悲故鄉。", "春風過眼花飛盡，蝴蝶翩翩過短牆。", "君更聽，是何章。"]'),
('795686d7-ce10-4d59-b110-b467dcf9df53','偈頌一一二首  其九四','釋清遠','宋','宋诗','song-poetry','','[]','帝力丘山重，君恩宇宙寬。',24,'全唐诗/poet.song.73000.json','["帝力丘山重，君恩宇宙寬。", "不才何以報，處處得心安。"]'),
('7145352a-cb5b-4760-9ca0-8321faf90785','偈頌一一二首  其九五','釋清遠','宋','宋诗','song-poetry','','[]','褒禪乍住太乾枯，月白風清入畫圖。',32,'全唐诗/poet.song.73000.json','["褒禪乍住太乾枯，月白風清入畫圖。", "人間縱有千般樂，不及今朝事事無。"]'),
('2d1ead66-17d6-4c8b-a9d9-8410e57716b9','偈頌一一二首  其九六','釋清遠','宋','宋诗','song-poetry','','[]','雲中石塔摩星斗，定明禪師大張口。',48,'全唐诗/poet.song.73000.json','["雲中石塔摩星斗，定明禪師大張口。", "是你之言若解參，不必腰包天下走。", "鳥對初陽自在啼，犬逢生漢連聲吼。"]'),
('c09f6de4-9011-4333-a002-96c8f607eeec','偈頌一一二首  其九七','釋清遠','宋','宋诗','song-poetry','','[]','祇知今日明朝，不覺今朝明日。',56,'全唐诗/poet.song.73000.json','["祇知今日明朝，不覺今朝明日。", "事事一似安排，箭箭自然中的。", "甜者甜於黄連，苦者苦過白蜜。", "喫得者般滋味，不妨邏邏哩哩。"]'),
('341b7735-cb2c-4f26-8888-00c018ada4c8','偈頌一一二首  其九八','釋清遠','宋','宋诗','song-poetry','','[]','天得一，斗牛女虛危室畢。',140,'全唐诗/poet.song.73000.json','["天得一，斗牛女虛危室畢。", "地得一，草木山河并土石。", "君得一，上下四維無等匹。", "萬象森羅影現中，一顆圓明光的歷。", "有歡榮，有愁戚。", "或冤親，或順逆。", "富且貴，貧且乞。", "萬樣千般誰運爲，空谷之聲隨應出。", "鴛鴦繡了任君看，不露金針太綿密。", "褒禪奉勸各回頭，莫待臨行却啾唧。", "識取摩訶般若光，萬古悠悠是今日。"]'),
('713a6086-b5af-425c-9b9e-49c66e91f1af','偈頌一一二首  其九九','釋清遠','宋','宋诗','song-poetry','','[]','東西南北四方人，地闊天遥最是親。',32,'全唐诗/poet.song.73000.json','["東西南北四方人，地闊天遥最是親。", "衡岳天台連魏闕，輕輕彈指不勞神。"]'),
('98042b2d-f4f4-4a9e-8c4e-b89177f0eb28','偈頌一一二首  其一○○','釋清遠','宋','宋诗','song-poetry','','[]','定明妙應禪師，說法如雲如雨。',56,'全唐诗/poet.song.73000.json','["定明妙應禪師，說法如雲如雨。", "不是時人不聞，又非不善其語。", "如斯一味靈通，過了幾多寒暑。", "縱逢敗種焦芽，方便一時救取。"]'),
('5ea08ba7-220e-449d-8cc3-d0990d5639d8','偈頌一一二首  其一○一','釋清遠','宋','宋诗','song-poetry','','[]','雨從何來，不須尋討。',49,'全唐诗/poet.song.73000.json','["雨從何來，不須尋討。", "徧滿虛空，拔濟枯槁。", "定明妙應靈通，知府舍人台造。", "真箇是爲雨爲霖，莫不爲忻爲好。"]'),
('573548b1-a133-4390-ae62-752eb51126c3','偈頌一一二首  其一○二','釋清遠','宋','宋诗','song-poetry','','[]','抵死要行雲水脚，剛然求悟本來心。',32,'全唐诗/poet.song.73000.json','["抵死要行雲水脚，剛然求悟本來心。", "爲蛇畫足勞筋骨，辜負青山綠水深。"]'),
('590aa97b-befd-44e2-a130-b23bea9258a0','偈頌一一二首  其一○三','釋清遠','宋','宋诗','song-poetry','','[]','一去一來松上鶴，半開半合嶺頭雲。',32,'全唐诗/poet.song.73000.json','["一去一來松上鶴，半開半合嶺頭雲。", "搘筇獨立千峰外，唯把南山祝聖君。"]'),
('a584bc2d-57c4-41fb-b18f-dabaf4f1b3e0','偈頌一一二首  其一○四','釋清遠','宋','宋诗','song-poetry','','[]','君命重宣降薜蘿，不容靜處薩婆訶。',61,'全唐诗/poet.song.73000.json','["君命重宣降薜蘿，不容靜處薩婆訶。", "襴衫席帽寒酸甚，又向人前唱哩囉。", "去年梅，今歲柳，顔色馨香依舊。", "人漸老，水長流，無心道合頭。"]'),
('e92592a1-87b7-42d1-915e-e1e7d28e3e78','偈頌一一二首  其一○五','釋清遠','宋','宋诗','song-poetry','','[]','盡力放不下，著力擔不起。',48,'全唐诗/poet.song.73000.json','["盡力放不下，著力擔不起。", "將謂一物無，元是自家底。", "見得自家底，心中大歡喜。", "自茲家業興，一舉九萬里。"]'),
('377ae7e0-b73e-45a5-be42-6f2d4a9b032b','偈頌一一二首  其一○六','釋清遠','宋','宋诗','song-poetry','','[]','未達境惟心，起種種分別。',36,'全唐诗/poet.song.73000.json','["未達境惟心，起種種分別。", "達境唯心已，分別即不生。", "分別既不生，便捨外塵相。"]'),
('ff0c9aef-8d43-4e21-9602-00edf809aa7f','偈頌一一二首  其一○七','釋清遠','宋','宋诗','song-poetry','','[]','放得下，好脫洒。',64,'全唐诗/poet.song.73000.json','["放得下，好脫洒。", "放不下，牛拽杷。", "堪笑諸方老古錐，打鼓說禪無尾欛。", "無尾欛，不驚怕。", "不驚怕，可嗟訝。", "解踏毗盧頂上行，不言亦自傳天下。"]'),
('bb060b92-e0c1-4fdd-aebb-fc6027e57904','偈頌一一二首  其一○八','釋清遠','宋','宋诗','song-poetry','','[]','歸根得旨復何論，洞口秦人半掩門。',32,'全唐诗/poet.song.73000.json','["歸根得旨復何論，洞口秦人半掩門。", "花落已隨流水遠，空留羃羃野雲屯。"]'),
('5ec96f83-d0c5-4e2b-9070-915273f63e0b','偈頌一一二首  其一○九','釋清遠','宋','宋诗','song-poetry','','[]','玄沙白紙費封題，一聽雷音萬仞低。',32,'全唐诗/poet.song.73000.json','["玄沙白紙費封題，一聽雷音萬仞低。", "慰釋私懷已無量，那堪更唱邏羅哩。"]'),
('8cc702a9-caa5-4ebc-ac90-223c1717a1a0','偈頌一一二首  其一一○','釋清遠','宋','宋诗','song-poetry','','[]','一手不獨拍，兩手鳴摑摑。',73,'全唐诗/poet.song.73000.json','["一手不獨拍，兩手鳴摑摑。", "舉意超情念，相看同路陌。", "摩雲鍾阜高，徧界烏輪赫。", "妙機速雷電，神珠不在額。", "珍重人天大導師，衲僧一見喪魂魄，何也誰敢正眼覷著。"]'),
('66dfb1df-eddf-4964-ad13-4c30bda35d37','偈頌一一二首  其一一一','釋清遠','宋','宋诗','song-poetry','','[]','暫下蓮峰輕屈指，光陰倏爾又三年。',32,'全唐诗/poet.song.73000.json','["暫下蓮峰輕屈指，光陰倏爾又三年。", "雖然不隔絲毫許，爭似躬親到座前。"]'),
('106f29f3-bf53-4585-a313-ddc9eb15e2f5','偈頌一一二首  其一一二','釋清遠','宋','宋诗','song-poetry','','[]','一二三，無言童子口喃喃。',40,'全唐诗/poet.song.73000.json','["一二三，無言童子口喃喃。", "三二一，上下四維無等匹。", "衲僧活計絕絲毫，萬古徽猷是今日。"]'),
('fd441044-48d0-41b7-a35d-36dc579c0a0a','以偈美世奇首座','釋清遠','宋','宋诗','song-poetry','','[]','有道只因頻退步，謙和元自慣回光。',32,'全唐诗/poet.song.73000.json','["有道只因頻退步，謙和元自慣回光。", "不知已在青雲上，尤更將身入衆藏。"]'),
('cf9a07d7-583a-48ee-b718-05940b5abf62','別僧演','釋清遠','宋','宋诗','song-poetry','','[]','西別岷峨路五千，幸携瓶錫禮高禪。',64,'全唐诗/poet.song.73000.json','["西別岷峨路五千，幸携瓶錫禮高禪。", "不材雖見頻揮斧，鈍足難諳再舉鞭。", "深咸恩光同日月，未能蹤跡上林泉。", "明朝且出山前去，他日重來會有緣。"]'),
('bb3ba1c9-3465-4311-81ee-c3ed405e11d8','以偈問清遠禪師','僧某','宋','宋诗','song-poetry','','[]','劫火威音前，別是一壺天。',24,'全唐诗/poet.song.73000.json','["劫火威音前，別是一壺天。", "御樓前射獵，不是刈荒田。"]'),
('a9452848-6499-4dc1-97ad-e6d4b44141cc','蒼梧即事','謝孚','宋','宋诗','song-poetry','','[]','近岸江聲急，孤舟下杳冥。',48,'全唐诗/poet.song.73000.json','["近岸江聲急，孤舟下杳冥。", "峽泉飛暴雨，灘石走羣星。", "水有瀟湘色，猿同巴蜀聽。", "令人思舜德，一望九疑青。"]'),
('e33c200b-26d2-4f92-831a-bebd5bae68fa','送宋朝請倅邢州','蔡薿','宋','宋诗','song-poetry','','[]','布衣初喜得相從，淡薄情懷老更同。',64,'全唐诗/poet.song.73000.json','["布衣初喜得相從，淡薄情懷老更同。", "春酒杯盤花爛漫，夜堂燈火雪冥濛。", "家傳辭藻喧時譽，地近鄉枌識土風。", "早晚漢庭褒一鶚，待看霜翮上秋空。"]'),
('cdf3998c-4e6b-4dd4-a51e-3ee67799a07e','句','蔡薿','宋','宋诗','song-poetry','','[]','雲藏北固山頭寺，烟鎖南徐水際樓。',16,'全唐诗/poet.song.73000.json','["雲藏北固山頭寺，烟鎖南徐水際樓。"]'),
('e6cdf72c-68b5-4c17-aade-05ec9e1833f8','至豬鈎沙','蔡萊','宋','宋诗','song-poetry','','[]','江樹棲烟暝色浮，波聲不動月華流。',32,'全唐诗/poet.song.73000.json','["江樹棲烟暝色浮，波聲不動月華流。", "浪花千頃潮平岸，興入春風萬斛舟。"]'),
('edcf2db3-a670-48ad-b0b4-dec5e684b257','西宮','蔡萊','宋','宋诗','song-poetry','','[]','雲興霞蔚控千山，勢壓江南廣殿寒。',32,'全唐诗/poet.song.73000.json','["雲興霞蔚控千山，勢壓江南廣殿寒。", "風偃萬松斜日晚，卧看風雨落人間。"]'),
('148d1ed4-be9f-4a5d-acae-40eb750a29b9','藏雲軒','蔡萊','宋','宋诗','song-poetry','','[]','山邊畏景欲流金，山下浮埃幾度深。',32,'全唐诗/poet.song.73000.json','["山邊畏景欲流金，山下浮埃幾度深。", "水宿岩栖得真樂，可無餘事到商林。"]'),
('2223ac2f-fcfd-460f-ab20-8e6bf4300649','贈孫至豐','黄葆光','宋','宋诗','song-poetry','','[]','勸農因到好溪頭，把酒相看憶舊遊。',32,'全唐诗/poet.song.73000.json','["勸農因到好溪頭，把酒相看憶舊遊。", "三十年來如一夢，可憐空負釣魚舟。"]'),
('457d175b-33dc-441d-8d52-d9c9c0bbb646','留題開善精舍','劉韐','宋','宋诗','song-poetry','','[]','琴書收拾去，回首謝禪關。',48,'全唐诗/poet.song.73000.json','["琴書收拾去，回首謝禪關。", "紫紹搜裼切，青雲咫尺間。", "子牟趨魏闕，文靖起東山。", "共約重遊日，春風晝錦還。"]'),
('3dba9abd-99e3-4cfe-8676-a195b43a86d9','紫雲巖','劉韐','宋','宋诗','song-poetry','','[]','萬疊青山入畫圖，最高高處著浮屠。',64,'全唐诗/poet.song.73000.json','["萬疊青山入畫圖，最高高處著浮屠。", "薄雲弄日明還暗，小雨飛空有却無。", "山鳥避人疑俗駕，道人好客點雲腴。", "我來一笑忘塵慮，倒載歸歟日欲晡。"]'),
('30ba0d33-3926-46ca-a118-d66c7dc93eab','夢野亭','唐恪','宋','宋诗','song-poetry','','[]','雲夢澤南古景陵，登臨聚景在幽亭。',32,'全唐诗/poet.song.73000.json','["雲夢澤南古景陵，登臨聚景在幽亭。", "幾重湛湛陂湖綠，萬疊陰陰桑柘青。"]'),
('04aa594d-218e-4302-b361-682d6ecd54a3','贈泉州謝事五老','陸藻','宋','宋诗','song-poetry','','[]','五老三百九十七，俱生仁祖承平時。',32,'全唐诗/poet.song.73000.json','["五老三百九十七，俱生仁祖承平時。", "名齊廬阜久傳世，身異商山深採芝。"]'),
('31da29c1-b10e-4da7-99d7-43ae5d844f4e','句','陸藻','宋','宋诗','song-poetry','','[]','軒前山色依然綠，軒下泉聲潄玉寒。',16,'全唐诗/poet.song.73000.json','["軒前山色依然綠，軒下泉聲潄玉寒。"]'),
('207ef8e2-095b-43ea-9a1b-9d3ca9354bdd','西巖寺','翁彥國','宋','宋诗','song-poetry','','[]','澗行屈曲似乘槎，流水漂裙亂曉霞。',32,'全唐诗/poet.song.73000.json','["澗行屈曲似乘槎，流水漂裙亂曉霞。", "紫翠堆中訪蕭寺，隔溪烟樹兩三家。"]'),
('e2540a9e-d71c-4b4e-859b-a50d03419974','詩一首','翁彥國','宋','宋诗','song-poetry','','[]','新經牛渚棄星槎，倒影光中蹙紫霞。',32,'全唐诗/poet.song.73000.json','["新經牛渚棄星槎，倒影光中蹙紫霞。", "竹馬兒童休借問，君恩還許過吾家。"]'),
('ab057a6c-4fd6-498f-8048-fbbb54f73cc6','貴州','陳遘','宋','宋诗','song-poetry','','[]','冬來行部駕軺車，一日之間氣候殊。',32,'全唐诗/poet.song.73000.json','["冬來行部駕軺車，一日之間氣候殊。", "朝衣駝裘暮揮扇，未應嵐瘴得全無。"]'),
('8f8bc96e-d6e6-4182-a4c9-fdff18ae96f7','述懷','陳遘','宋','宋诗','song-poetry','','[]','不覺霜飛上鬢毛，引杯看劍興猶豪。',64,'全唐诗/poet.song.73000.json','["不覺霜飛上鬢毛，引杯看劍興猶豪。", "胸開萬古天風盪，目拭三山海月高。", "投閣羞稱揚子易，啜醨愛讀楚人騷。", "媕婀莫遣無生氣，搘住乾坤在我曹。"]'),
('d2f3baac-3b55-4f8e-acac-b9ffe2ec90b7','題李西傑水竹居','劉章','宋','宋诗','song-poetry','','[]','在昔香山老，水友而竹師。',120,'全唐诗/poet.song.73000.json','["在昔香山老，水友而竹師。", "心虛是師道，性靜友亦宜。", "孰謂物理妙，乃爲高賢資。", "佳哉隴西子，結屋溪之湄。", "溪上亦何有，有竹如在淇。", "涓涓峙寒碧，澄澄燭須眉。", "微風一披拂，雜佩聲參差。", "俄頃萬籟寂，粹然淡餘姿。", "可但子師友，我方師友之。", "未到三嘆息，徒勞形夢思。"]'),
('a20057c1-d18e-4a7e-9ddf-f4090e1e5b10','偈','釋智才','宋','宋诗','song-poetry','','[]','舜日重明四海清，滿天和氣樂昇平。',32,'全唐诗/poet.song.73000.json','["舜日重明四海清，滿天和氣樂昇平。", "延祥柱杖生歡喜，擲地山呼萬歲聲。"]'),
('781ca8a1-ff33-4299-a729-dc467a386ab1','集衆付寺事偈','釋智才','宋','宋诗','song-poetry','','[]','戊午中秋之日，出家住持事畢。',28,'全唐诗/poet.song.73000.json','["戊午中秋之日，出家住持事畢。", "臨行自己尚無，有甚虛空可覓。"]'),
('04932dd2-7e79-42e4-ab51-13d02e480794','頌古二首 溈山百年後，向山前檀越家作一頭水牯牛去。','釋智才','宋','宋诗','song-poetry','','[]','翻手書空字已成，忙忙人向兩頭爭。',32,'全唐诗/poet.song.73000.json','["翻手書空字已成，忙忙人向兩頭爭。", "屈原不是尋漁父，千古誰人論獨醒。"]'),
('de3ce3a9-ee67-4399-8b77-1a9844cf9dc3','頌古二首 玄沙白紙','釋智才','宋','宋诗','song-poetry','','[]','踏翻漁艇成家業，笑出蘆華月正圓。',32,'全唐诗/poet.song.73000.json','["踏翻漁艇成家業，笑出蘆華月正圓。", "地闊天長三幅紙，同風千里爲重宣。"]'),
('786a06d4-dffb-4853-a924-36a9002323ca','己酉歲十一月二十六日避寇至龍潭院十二月十五日作五首  其一','洪炎','宋','宋诗','song-poetry','','[]','徑轉橋橫水，林深寺據山。',48,'全唐诗/poet.song.73000.json','["徑轉橋橫水，林深寺據山。", "鐘魚告闃寂，松竹媚孱顔。", "避地欣有託，依僧成暫閒。", "東歸路不隔，片片隴雲還。"]'),
('caaef928-928a-4571-90d3-58c98f63fb7c','己酉歲十一月二十六日避寇至龍潭院十二月十五日作五首  其二','洪炎','宋','宋诗','song-poetry','','[]','突兀山椒寺，披榛二百年。',48,'全唐诗/poet.song.73000.json','["突兀山椒寺，披榛二百年。", "剎從吾祖卜，席是里僧傳。", "溪送無盡水，林供不斷烟。", "囊中有餘粒，假息且安眠。"]'),
('6290a073-2ae6-4f53-ba77-65cfc7348862','己酉歲十一月二十六日避寇至龍潭院十二月十五日作五首  其三','洪炎','宋','宋诗','song-poetry','','[]','潭黑蛟龍宅，山青虎豹林。',48,'全唐诗/poet.song.73000.json','["潭黑蛟龍宅，山青虎豹林。", "隠憂何日了，淹泊見冬深。", "薄雪恨還積，疏梅冷不禁。", "平生一樽酒，衰病廢孤斟。"]'),
('41a6f195-3f88-4e16-8953-42fc65e68f89','己酉歲十一月二十六日避寇至龍潭院十二月十五日作五首  其四','洪炎','宋','宋诗','song-poetry','','[]','殺氣纏中土，妖徵出泰階。',48,'全唐诗/poet.song.73000.json','["殺氣纏中土，妖徵出泰階。", "架橋凌禹穴，投策暗秦淮。", "匪兕歌何苦，非熊願亦乖。", "申胥雖有淚，無地寄余懷。"]'),
('b7c284cc-8401-4ea3-8b4f-0f4112d9a93c','己酉歲十一月二十六日避寇至龍潭院十二月十五日作五首  其五','洪炎','宋','宋诗','song-poetry','','[]','宵旰憂雖切，咨謀策靡長。',48,'全唐诗/poet.song.73000.json','["宵旰憂雖切，咨謀策靡長。", "築壇推騎劫，假節得糜芳。", "已矣重江險，哀哉古豫章。", "蓬茅今在否，矯首恨難忘。"]'),
('b0160623-569a-4b7a-9d8f-618fd038a61c','次韵鄭公實見贈二詩  其一','洪炎','宋','宋诗','song-poetry','','[]','鄭侯風概似虞薰，醉飽初疑對苾芬。',64,'全唐诗/poet.song.73000.json','["鄭侯風概似虞薰，醉飽初疑對苾芬。", "一日君嘗南浦水，六年我踏寶峰雲。", "詩情賦物已聞命，山色溪光儻見分。", "羣盜何曾念王粲，相逢聊喜見斯文。"]'),
('7faf78b3-3637-491b-a869-e4c52f8b5253','次韵鄭公實見贈二詩  其二','洪炎','宋','宋诗','song-poetry','','[]','百濯生香真寶薰，中泠取水挹清芬。',64,'全唐诗/poet.song.73000.json','["百濯生香真寶薰，中泠取水挹清芬。", "素娥影落秋宵月，白鶴翎翻春晝雲。", "俗客來依禪客住，林花自與雨花分。", "扶傾不假迂儒力，敢倚筆端能綴文。"]'),
('9d0dd12d-1e92-480d-9f62-4c3bd80fcf09','寶峰讀駒父壁間詩次其韵二首  其一','洪炎','宋','宋诗','song-poetry','','[]','兔迒通一線，筍輿度千尋。',48,'全唐诗/poet.song.73000.json','["兔迒通一線，筍輿度千尋。", "隔林見潭影，迎客有鈴音。", "梵唄出廣殿，飛舞來珍禽。", "履此勝絕境，一清塵慮心。"]'),
('c7b25173-4945-4429-b589-ee3806ac6de9','寶峰讀駒父壁間詩次其韵二首  其二','洪炎','宋','宋诗','song-poetry','','[]','仲氏趣玄遠，造詣非尺尋。',48,'全唐诗/poet.song.73000.json','["仲氏趣玄遠，造詣非尺尋。", "誰云干戈際，獲睹金玉音。", "七日南山霧，一鳴幽谷禽。", "依然拂塵壁，愁絕見予心。"]'),
('353716ab-037b-4664-a6bf-c92bf1ed3698','次韵公實感遇','洪炎','宋','宋诗','song-poetry','','[]','求田問舍轉頭空，十口無家寄栗蓬。',64,'全唐诗/poet.song.73000.json','["求田問舍轉頭空，十口無家寄栗蓬。", "得失自憐嬰世網，是非都欲問天公。", "綿綿不解溪邊雨，淅淅無情松下風。", "頼有詩人排悶作，且吟佳句任窮通。"]'),
('f45aafa8-dd4d-42df-94f4-e34344b306e9','次韵公實雷雨','洪炎','宋','宋诗','song-poetry','','[]','驚雷勢欲拔三山，急雨聲如倒百川。',64,'全唐诗/poet.song.73000.json','["驚雷勢欲拔三山，急雨聲如倒百川。", "但作奇寒侵客夢，若爲一震靜胡烟。", "田園荆棘漫流水，河洛腥羶今幾年。", "擬扣九關牋帝所，人非大手筆非椽。"]'),
('30413541-93a6-4fd7-b018-213cfaaaab49','次韵公實喜晴二首  其一','洪炎','宋','宋诗','song-poetry','','[]','凍雨連三日，春膏過一犂。',48,'全唐诗/poet.song.73000.json','["凍雨連三日，春膏過一犂。", "寺橋杯渡水，村徑橇行泥。", "燠若生暘谷，寒收豈石犀。", "欲窮洪範理，夕室有青藜。"]'),
('52ac0d7a-56ef-476e-98e7-9c0d4776f102','次韵公實喜晴二首  其二','洪炎','宋','宋诗','song-poetry','','[]','持璧還投鵲，鎔金恨作犂。',48,'全唐诗/poet.song.73000.json','["持璧還投鵲，鎔金恨作犂。", "行吟乘曉月，扶杖入春泥。", "願學懷文豹，終慚禿角犀。", "徒歌無好語，野飯只羹藜。"]'),
('0d77db1d-5b7c-415c-8788-c500ba3dc9a4','馮太沖置酒即事次公實韵','洪炎','宋','宋诗','song-poetry','','[]','故人同客寓，蕭寺近清明。',48,'全唐诗/poet.song.73000.json','["故人同客寓，蕭寺近清明。", "春事一樽酒，夜闌三尺檠。", "風流孔北海，文字漢西京。", "苦勸加餐飯，年來太瘦生。"]'),
('b380be4c-49c1-43ba-9487-e30e97c1e945','山中聞杜鵑','洪炎','宋','宋诗','song-poetry','','[]','山中二月聞杜鵑，百草爭芳已銷歇。',64,'全唐诗/poet.song.73000.json','["山中二月聞杜鵑，百草爭芳已銷歇。", "綠陰初不待薰風，啼鳥區區自流血。", "北窗移燈欲三更，南山高林時一聲。", "言歸汝亦無歸處，何用多言傷我情。"]'),
('be8cca7f-7019-4e91-b1e3-2bef1d875b57','寶峰筍用公實韵','洪炎','宋','宋诗','song-poetry','','[]','繞寺千林筍，高低逐澗丘。',48,'全唐诗/poet.song.73000.json','["繞寺千林筍，高低逐澗丘。", "參差舒鳳尾，突兀長貓頭。", "入鼎資甘脆，殘杯且罷休。", "會須堪小艇，裁作海楂浮。"]'),
('963f339e-55ec-4bef-9017-82b8097c0951','公實示閒字韵詩悵然有感次韵奉和三首  其一','洪炎','宋','宋诗','song-poetry','','[]','晴暉生燠雨生寒，朱夏陽春季孟間。',64,'全唐诗/poet.song.73000.json','["晴暉生燠雨生寒，朱夏陽春季孟間。", "斷雁哀猿金馬客，落花流水石門山。", "早知蟻穴成何事，欲棹漁舟去不還。", "昭氏有琴無作止，虧成都任一機關。"]'),
('6ea813dd-9232-47a5-bbcf-522ad7e39822','公實示閒字韵詩悵然有感次韵奉和三首  其二','洪炎','宋','宋诗','song-poetry','','[]','輟哭人歌行路難，畏人無地出人間。',64,'全唐诗/poet.song.73000.json','["輟哭人歌行路難，畏人無地出人間。", "欣逢北海孫賓石，猶是江南庾子山。", "野草離離隨意綠，羣鳬泛泛倦飛還。", "一川烟草松蘿外，何處梯雲叩九關。"]'),
('c06a8772-08c4-4e46-993d-b61dec048115','公實示閒字韵詩悵然有感次韵奉和三首  其三','洪炎','宋','宋诗','song-poetry','','[]','此國非燕南趙北，我琴無濮上桑間。',64,'全唐诗/poet.song.73000.json','["此國非燕南趙北，我琴無濮上桑間。", "勞生聊作夢中夢，苦語莫酬山復山。", "觸石白雲數峰起，照人明月一鉤還。", "德星已爲荀陳聚，紫氣休浮函谷關。"]'),
('70969925-41ee-4d42-8ced-35e275fee903','載酒邀公實同過西園食枇杷次公實韵','洪炎','宋','宋诗','song-poetry','','[]','有美枇杷子，三珍共一時。',48,'全唐诗/poet.song.73000.json','["有美枇杷子，三珍共一時。", "朱櫻梁苑早，盧橘蜀都遲。", "載酒寧辭病，窺園似好奇。", "酬君要佳句，從古未題詩。"]'),
('7986857f-2701-4c30-93ba-56096fc40f0a','公實再賦枇杷次韵二首  其一','洪炎','宋','宋诗','song-poetry','','[]','連雲葱蒨外，佳樹枇杷林。',48,'全唐诗/poet.song.73000.json','["連雲葱蒨外，佳樹枇杷林。", "味極東南美，恩知雨露深。", "山夫琢栗玉，谷鳥避丸金。", "永日羈棲意，茲焉一慰心。"]'),
('dca0a676-0b3a-4749-aa18-317c2f082269','公實再賦枇杷次韵二首  其二','洪炎','宋','宋诗','song-poetry','','[]','醽醁尊中酒，枇杷雲外林。',48,'全唐诗/poet.song.73000.json','["醽醁尊中酒，枇杷雲外林。", "甘餐千顆盡，軟語一杯深。", "老境宜扶杖，交情得斷金。", "遺民伐荻去，真處即吾心。"]'),
('4344471f-7170-491e-9344-8690fd3916fb','公實作暴雨詩次其韵','洪炎','宋','宋诗','song-poetry','','[]','民生惟播殖，天意在農深。',48,'全唐诗/poet.song.73000.json','["民生惟播殖，天意在農深。", "一夜盆傾雨，千家粒食心。", "知時占聚蟻，催種有鳴禽。", "喜是田間語，青青刺水鍼。"]'),
('6d763fed-5cec-4ab2-bbd9-dbb181159556','次韵即事二首  其一','洪炎','宋','宋诗','song-poetry','','[]','自愧山林士，來炊蕭寺烟。',48,'全唐诗/poet.song.73000.json','["自愧山林士，來炊蕭寺烟。", "怨驚寄猿鶴，飛躍任魚鳶。", "咄咄空中字，昏昏醉後眠。", "摛文非孟子，何以差狂顛。"]'),
('031efd2a-7e31-4c55-a237-01d166364b5a','次韵即事二首  其二','洪炎','宋','宋诗','song-poetry','','[]','寄榻逢僧夏，登場喜麥秋。',48,'全唐诗/poet.song.73000.json','["寄榻逢僧夏，登場喜麥秋。", "一風將浹日，四月尚重裘。", "去矣吁何及，歸歟幸少休。", "雨晴寒自戢，桂魄更添愁。"]'),
('5b38b6c0-9d7c-4338-870e-b3bea2e12050','次韵野步','洪炎','宋','宋诗','song-poetry','','[]','意行無遠近，山徑自橫斜。',48,'全唐诗/poet.song.73000.json','["意行無遠近，山徑自橫斜。", "烟月生晴嶺，風幡接暮霞。", "影歸巢幕燕，聲散宿林鴉。", "屣履相隨處，僧垣即是家。"]'),
('a66d6e03-7719-4d63-938f-042a0b3a89ed','遊都梁山','洪炎','宋','宋诗','song-poetry','','[]','風吹古渡口，雲滿都梁山。',120,'全唐诗/poet.song.73000.json','["風吹古渡口，雲滿都梁山。", "執熱厭偪仄，幽尋上孱顔。", "清泉似石乳，滴瀝巖竇間。", "乞此一瓢飲，爲祛千載煩。", "山靈知我意，殷然下層巒。", "散空作急雨，抉石出甘寒。", "一酌蕩齒頰，三咽縈肺肝。", "輕軀變滯骨，塵鞅思靈關。", "來當踏雲至，去當御風還。", "再拜謝神休，幸汝不我慳。"]'),
('e735c1fe-417b-4d1d-8894-bd5abf842f58','四月二十三日晚同太沖表之公實野步','洪炎','宋','宋诗','song-poetry','','[]','四山矗矗野田田，近是人烟遠是村。',64,'全唐诗/poet.song.73000.json','["四山矗矗野田田，近是人烟遠是村。", "鳥外疏鐘靈隠寺，花邊流水武陵源。", "有逢即畫元非筆，所見皆詩本不言。", "閒看插秧欲忘返，杖藜徙倚到黄昏。"]'),
('3f45d9a0-c270-4881-9080-274f4ba81db4','野步','洪炎','宋','宋诗','song-poetry','','[]','散策尋溪偶緩行，羈栖愁眼忽雙明。',64,'全唐诗/poet.song.73000.json','["散策尋溪偶緩行，羈栖愁眼忽雙明。", "非烟羃羃平蕪合，倒影層層遠翠橫。", "鷗鷺低飛映山去，江湖一諾百金輕。", "直知已造洞天內，身在人間却自驚。"]'),
('0bd2d4fd-207a-4f79-89ef-671f9bfa4e2b','石門中夏雨寒','洪炎','宋','宋诗','song-poetry','','[]','五年胡騎穢中原，四月江南尚薄寒。',64,'全唐诗/poet.song.73000.json','["五年胡騎穢中原，四月江南尚薄寒。", "入昴誰能移太白，來朝我亦見呼韓。", "灌壇風雨行將戢，陋巷簞瓢且自寬。", "紅日再中天地正，泥塗不辱漢衣冠。"]'),
('894fff43-63fd-49aa-a746-704b0b558d40','次韵即事','洪炎','宋','宋诗','song-poetry','','[]','端居入夏愁更新，不數多愁過一春。',64,'全唐诗/poet.song.73000.json','["端居入夏愁更新，不數多愁過一春。", "躡虛難同若士去，取醉但與索郎親。", "朝天幾日車同軌，擊地共唱胡無人。", "自許世才非管樂，聊將心事比雷陳。"]'),
('6910476c-3341-4481-99c3-8017e662f3d9','嘗白酒用糜韵','洪炎','宋','宋诗','song-poetry','','[]','竹葉榴花久擅場，一尊雲液勝椒漿。',64,'全唐诗/poet.song.73000.json','["竹葉榴花久擅場，一尊雲液勝椒漿。", "人惟任達常中聖，藥自消憂不作狂。", "滿泛冰甆無別色，錯斟瓶水有真香。", "祇應剩醖逡巡酒，始耐仙山日月長。"]'),
('e36c59cb-9189-4e3b-828d-10d6398dd363','庚戌歲六月四日至洪城舊廬無復尺椽悵然傷懷用丙午歲遷居詩韵','洪炎','宋','宋诗','song-poetry','','[]','南州一炬火，我歸無所歸。',180,'全唐诗/poet.song.73000.json','["南州一炬火，我歸無所歸。", "六月下驚湍，一葉正復敧。", "空城何所有，城闕雙闔扉。", "遺氓四五輩，𥈭眙蟲鳥棲。", "潭潭大都府，灰滅餘空基。", "委重者誰子，汝實凡且卑。", "螻蟻輕民命，泥沙捐國貲。", "犬狼肆噬齧，敺逐乃其宜。", "胡爲使羣吠，如惡草蔓滋。", "哀哉三萬室，鍾此百六期。", "故居不可識，將是復疑非。", "階前手種花，自憐託根微。", "露草相對泣，吟風作悲詩。", "人言城門火，魚禍自靡遺。", "我亦無淚哭，且復一解頤。"]'),
('97f4a08d-91b0-40e1-8a42-3e07beb387cd','病間和公實飲酒詩','洪炎','宋','宋诗','song-poetry','','[]','憂每傷人人亦憂，花蒙兩眼雪蒙頭。',64,'全唐诗/poet.song.73000.json','["憂每傷人人亦憂，花蒙兩眼雪蒙頭。", "干戈滿地不可觸，蓑笠爲家何處浮。", "秋入鳴蟬催暑去，酒如凝露與清謀。", "寫成庾信江南賦，更續相如老倦遊。"]'),
('ca07ffad-6879-4838-818c-21738dabf9a2','戲和公實感秋對酒','洪炎','宋','宋诗','song-poetry','','[]','青山愛客長青眼，白水知時泛白雲。',64,'全唐诗/poet.song.73000.json','["青山愛客長青眼，白水知時泛白雲。", "少日悲歡纔一瞬，中星寒暑又平分。", "稻粱狼藉餘棲畝，雀鼠穿窬自立勳。", "一葉已驚秋意早，映階黄落更紛紛。"]'),
('06ab0e73-28d6-4434-937c-a615f8f61b7f','次韵公實七月一日雨感懷二首  其一','洪炎','宋','宋诗','song-poetry','','[]','平生離俗得閒多，素髮驚秋奈老何。',64,'全唐诗/poet.song.73000.json','["平生離俗得閒多，素髮驚秋奈老何。", "賓從盤飧惟白石，意行供帳有青蘿。", "御風獨往松三徑，踏月空歸雪一蓑。", "短布單衣窮至骭，醉吟不作飯牛歌。"]'),
('817c6b0c-45fd-43d0-ad89-3c20d0390a90','次韵公實七月一日雨感懷二首  其二','洪炎','宋','宋诗','song-poetry','','[]','日日愁隨萬緒多，遣愁不去若愁何。',64,'全唐诗/poet.song.73000.json','["日日愁隨萬緒多，遣愁不去若愁何。", "文書引睡繙黄卷，福地求生訪綠蘿。", "酒厭銀瓶聊注瓦，衣辭錦襖且披蓑。", "五更風雨作金石，助我貫珠商頌歌。"]'),
('67fcaabe-04ff-4aa7-9047-e62306a191c6','將去寶峰誦老杜更欲投何處賦五言三首  其一','洪炎','宋','宋诗','song-poetry','','[]','更欲投何處，乾坤老病身。',48,'全唐诗/poet.song.73000.json','["更欲投何處，乾坤老病身。", "窮愁但有骨，棲泊渺無津。", "巖穴探幽藪，人烟隔幾秦。", "驅車上九折，回首想傷神。"]'),
('5023bae7-6e85-42d2-a84e-3a8d2c57443e','將去寶峰誦老杜更欲投何處賦五言三首  其二','洪炎','宋','宋诗','song-poetry','','[]','更欲投何處，窮猿不擇林。',48,'全唐诗/poet.song.73000.json','["更欲投何處，窮猿不擇林。", "低回竹柏語，慘戚鐘魚心。", "邑邑出門淚，行行度嶺吟。", "西江如可吸，在處海潮音。"]'),
('11fb973c-7d21-42f7-92c9-43f2bc3e87ab','將去寶峰誦老杜更欲投何處賦五言三首  其三','洪炎','宋','宋诗','song-poetry','','[]','更欲投何處，仙山不可窺。',48,'全唐诗/poet.song.73000.json','["更欲投何處，仙山不可窺。", "欲尋吳許跡，默與綺園期。", "裹飯隨妻子，清秋問路歧。", "神真有汲引，逸駕或容追。"]'),
('3f43c517-daef-4257-b7db-e1f5c2c983d8','弈棋絕句二首  其一','洪炎','宋','宋诗','song-poetry','','[]','新秋遣悶只圍棋，病不銜杯亦廢詩。',32,'全唐诗/poet.song.73000.json','["新秋遣悶只圍棋，病不銜杯亦廢詩。", "對局蕭然兩無語，箇中君子有爭時。"]'),
('31d244db-e686-456f-a5d8-9337d51cc218','弈棋絕句二首  其二','洪炎','宋','宋诗','song-poetry','','[]','鷺落寒江鴉點汀，晴窗飛雹擊槃聲。',32,'全唐诗/poet.song.73000.json','["鷺落寒江鴉點汀，晴窗飛雹擊槃聲。", "方圓動靜隨機見，清簟疏簾眼倍明。"]'),
('a4036936-7ee4-4009-824b-f5a48358bd37','又疊前韵二首  其一','洪炎','宋','宋诗','song-poetry','','[]','白日惟銷一局棋，攬棋還誦李侯詩。',32,'全唐诗/poet.song.73000.json','["白日惟銷一局棋，攬棋還誦李侯詩。", "旁觀不作千年計，會有局成柯爛時。"]'),
('dbd58db1-0b29-4df8-b898-678c28a8ddd9','又疊前韵二首  其二','洪炎','宋','宋诗','song-poetry','','[]','棋局醒心過博局，棋聲娛耳勝琴聲。',32,'全唐诗/poet.song.73000.json','["棋局醒心過博局，棋聲娛耳勝琴聲。", "少年此戲殊不惡，坐隠時聞夜達明。"]'),
('a389fc38-2c15-49aa-b0fc-d5a6497f1a38','再賦弈棋五首  其一','洪炎','宋','宋诗','song-poetry','','[]','荆璞玉爲子，井文楸作枰。',48,'全唐诗/poet.song.73000.json','["荆璞玉爲子，井文楸作枰。", "有求惟別墅，不喜得宣城。", "跕跕飛鳶墮，丁丁伐木聲。", "破愁逢一笑，無地著虧成。"]'),
('c63caeff-f347-40d0-871d-38d48de726d7','再賦弈棋五首  其二','洪炎','宋','宋诗','song-poetry','','[]','祇園三日雨，碧澗一枰秋。',48,'全唐诗/poet.song.73000.json','["祇園三日雨，碧澗一枰秋。", "試問酒中趣，何如林下幽。", "從他著虎口，尋我鎮神頭。", "惟悟爭先法，當機與手謀。"]'),
('54c0196e-abd8-4f59-a7ef-f7fb391b3f75','再賦弈棋五首  其三','洪炎','宋','宋诗','song-poetry','','[]','不作丹朱戲，難禁清晝長。',48,'全唐诗/poet.song.73000.json','["不作丹朱戲，難禁清晝長。", "敢言白玉局，聊取紫羅囊。", "角道空傳記，乘除自有方。", "兒童爭畫紙，漫學老夫狂。"]'),
('0374d81f-6c45-41a2-bb72-adc425cac8ce','再賦弈棋五首  其四','洪炎','宋','宋诗','song-poetry','','[]','眉山非快手，弈勝亦欣然。',48,'全唐诗/poet.song.73000.json','["眉山非快手，弈勝亦欣然。", "變態一翻覆，幾微繫後先。", "陶公慮太過，雪女慧堪憐。", "張弛誠吾道，斯文許爾賢。"]'),
('51518fe6-2907-48a3-ab3b-3ab4b07b2ff4','再賦弈棋五首  其五','洪炎','宋','宋诗','song-poetry','','[]','凝神迷遠躅，致一有全功。',48,'全唐诗/poet.song.73000.json','["凝神迷遠躅，致一有全功。", "皎皎婦姑月，冥冥鴻鵠風。", "置君愚甯子，議樂哂溫公。", "誰謂商山老，飄然到橘中。"]'),
('3caa5efe-4e7b-470a-8edd-fa32cdde8332','越王山二首  其一','洪炎','宋','宋诗','song-poetry','','[]','朝登萬仞岡，夕宿雲霞間。',120,'全唐诗/poet.song.73000.json','["朝登萬仞岡，夕宿雲霞間。", "越王昔何時，稅駕宅此山。", "山巔有石室，險絕未可攀。", "烟樹相映带，尚想飆輪還。", "文吳二仙子，騰踔跨兩斑。", "俯仰五百秋，下視悲人寰。", "王室久蕩析，世路方孔艱。", "我尋真人居，荷鋤芟蓬菅。", "林泉依福地，樵汲闖靈關。", "庶以遠兵革，返茲後死顔。"]'),
('878822db-d950-42ef-9c0c-e518d4b90d5e','越王山二首  其二','洪炎','宋','宋诗','song-poetry','','[]','越王名茲山，無復車馬跡。',120,'全唐诗/poet.song.73000.json','["越王名茲山，無復車馬跡。", "絕頂有佳處，軒然大磐石。", "靈洞閟其中，神池蕩其側。", "雲氣朝夕生，合散一瞬息。", "吾聞王子搜，隠遁辭越國。", "玉輿去不返，丹竈鏁荆棘。", "二仙出季世，故老猶記識。", "遺蹤落人間，不稽傳寶墨。", "我睎伯夷清，願作老聃役。", "脫身塵𡏖外，捄暍獲三益。"]'),
('86d28bc0-5825-4a32-b453-59ff3d2e7ed0','嶺雲','洪炎','宋','宋诗','song-poetry','','[]','吾居半山上，繞屋猶峻嶺。',144,'全唐诗/poet.song.73000.json','["吾居半山上，繞屋猶峻嶺。", "舉頭即見之，坐卧作牆屏。", "忽復不可求，澒洞雲萬頃。", "初疑岸谷變，身不踐人境。", "俄頃如故常，突兀在屋頂。", "隠現須臾間，變態莫記省。", "烟霞成痼疾，終日常炯炯。", "早閱金丹訣，未辦卜竈井。", "世亂一丘壑，斯志或可逞。", "鳴猿落空巖，翥鶴颺晴影。", "石泉漱芳潤，草木皆秀整。", "洞天有歸路，未往心已領。"]'),
('4945a241-8364-467b-b13f-b3833a159d58','從寶峰長老惟足求貓頭筍','洪炎','宋','宋诗','song-poetry','','[]','不識貓頭筍，還思馬祖山。',48,'全唐诗/poet.song.73000.json','["不識貓頭筍，還思馬祖山。", "庭蘭生舊茁，綳錦換新斑。", "藴玉爭懷寶，登盤想飫餐。", "分甘須剩劚，遠助一瓢簞。"]'),
('31e46059-9de2-422f-8b70-b5336c93d5fd','食榧子','洪炎','宋','宋诗','song-poetry','','[]','若榴資彭糧，榧實伐彭兵。',144,'全唐诗/poet.song.73000.json','["若榴資彭糧，榧實伐彭兵。", "三彭穴身中，各以尸自名。", "伺隙戕所託，睢盱爲己榮。", "仙山無凡木，榧林高且清。", "八月實纍纍，斗量亦囊盛。", "盈盤得恣食，不與汝糧并。", "嗟汝小黠耳，安所逃汝生。", "蚤讀黄老書，五牙漱琅英。", "雖微玉山果，知汝久已行。", "喪亂食不足，長饑病所嬰。", "蟠桃未能致，橡栗庶可營。", "作詩頌榧子，期子以主盟。"]'),
('b9bf76b2-fae4-4ffb-b985-e133651c2794','十月十五日山中下視雲氣自山椒出已而瀰漫咫尺不辨巖谷戲成五言一首','洪炎','宋','宋诗','song-poetry','','[]','一歲下元日，千山小雪天。',48,'全唐诗/poet.song.73000.json','["一歲下元日，千山小雪天。", "雲層生遠壑，雨渰隔平川。", "放牧虛橫笛，樵蘇樂靜眠。", "遥知載酒客，無路到齋前。"]'),
('9b612f05-ef0a-4d7e-9b57-a7614dbe7c4c','十月十六日','洪炎','宋','宋诗','song-poetry','','[]','雲氣依然合，山蹊舊不通。',48,'全唐诗/poet.song.73000.json','["雲氣依然合，山蹊舊不通。", "虀鹽猶可問，牢醴頓成空。", "細覓泉聲外，疏籬犬吠中。", "無人披宿霧，採藥過龐公。"]'),
('4e5e5688-d434-4b61-be0e-386fb16eade8','南城鄧氏亭','洪炎','宋','宋诗','song-poetry','','[]','小麥青青山一曲，江南千里傷春目。',64,'全唐诗/poet.song.73000.json','["小麥青青山一曲，江南千里傷春目。", "盱母江頭喚渡人，遥指麻源第三谷。", "裹鹽包飯各匆匆，回首烟霞樓觀中。", "詩成更覓羊何和，猶是前身內史公。"]'),
('18bbe11e-9fe5-44c3-8419-a27a6ce3764d','遊麻姑山仙都觀','洪炎','宋','宋诗','song-poetry','','[]','浥露出南郭，遵塗眄西嶺。',180,'全唐诗/poet.song.73000.json','["浥露出南郭，遵塗眄西嶺。", "幽尋不憚遠，陟巘造殊境。", "懸瀑瀉天路，高齋跨參井。", "麻姑固神人，上下凌倒景。", "逸駕不容追，遺蹤摶塵影。", "仙壇獨巋然，蘚蝕此山頂。", "古屋鳴鵂鶹，汙池浴蛙黽。", "葛顔有異聞，源委邈難省。", "空餘豐碑字，欻若猊驥騁。", "永言賞心遇，所樂塵務屏。", "濯纓欲師孔，斲鼻還思郢。", "安得斯人徒，置論挈裘領。", "聖真豈遠而，炯炯金在鑛。", "九淵孕明月，七返閟神鼎。", "至道如可求，汲深願修綆。"]'),
('64ec5eb5-96eb-436b-8945-83d17dd316ba','靜思院上元日二首  其一','洪炎','宋','宋诗','song-poetry','','[]','麻姑山換越王山，憶昨下元今上元。',64,'全唐诗/poet.song.73000.json','["麻姑山換越王山，憶昨下元今上元。", "老去休驚長客寓，春來不擬問田園。", "畏途豺虎中原近，挾日風雲四海昏。", "夢繞瀟湘無落處，憑誰楚些與招魂。"]'),
('2ac9e047-fb9f-4cfe-a534-c7bce426cf79','靜思院上元日二首  其二','洪炎','宋','宋诗','song-poetry','','[]','欲趨嚴蹕萬重山，且酌清尊慶改元。',64,'全唐诗/poet.song.73000.json','["欲趨嚴蹕萬重山，且酌清尊慶改元。", "穡事何時銷劍戟，賢書不用到丘園。", "傷心華屋燈如晝，觸眼荒塗犬吠昏。", "今日江東須管仲，可憐窮寇尚遊魂。"]'),
('19f82c3f-4110-4a58-8d4a-b437dfa7b63c','雲溪院','洪炎','宋','宋诗','song-poetry','','[]','水竹依山住，烟霞並舍分。',48,'全唐诗/poet.song.73000.json','["水竹依山住，烟霞並舍分。", "秋添中夜雨，冷浸一溪雲。", "滿目干戈地，關心鳥獸羣。", "歸塗如可問，猛犬莫狺狺。"]'),
('d12cb6e4-67ae-4108-b4d7-8390eee81348','二月十二日偶成','洪炎','宋','宋诗','song-poetry','','[]','金谿東行二十里，高即登山下臨水。',64,'全唐诗/poet.song.73000.json','["金谿東行二十里，高即登山下臨水。", "亂山中斷水橫流，水際招提對山起。", "丹青像設半泥塗，野僧一飯無鐘魚。", "散策閑尋筍蕨芽，密林時逢桃李花。"]'),
('0ad8907b-e453-4d59-ad81-bf93dc14853a','信州逢寒食','洪炎','宋','宋诗','song-poetry','','[]','客行寒食路，春晚上饒城。',48,'全唐诗/poet.song.73000.json','["客行寒食路，春晚上饒城。", "野寺鳥烏樂，山蹊荆棘生。", "人隨乘雁集，地隔一牛鳴。", "俛首征途內，官曹何日清。"]'),
('8055dfa5-6c63-4dd1-8b45-a37797fb29f7','題盛彥光邱壑軒','洪炎','宋','宋诗','song-poetry','','[]','盛子卜居南澗濱，開軒自比葛天民。',64,'全唐诗/poet.song.73000.json','["盛子卜居南澗濱，開軒自比葛天民。", "一丘一壑有能事，三浴三薰無俗塵。", "閒逐逸人同執射，偶逢漁父亦垂綸。", "此軒成毀吾何預，畫著巖間恐未真。"]'),
('fcddec4c-0115-4a1c-8a4f-83e1a0b181c2','代簡呈信州李使君','洪炎','宋','宋诗','song-poetry','','[]','萬斛誰能破客愁，一尊風味泛醇酘。',64,'全唐诗/poet.song.73000.json','["萬斛誰能破客愁，一尊風味泛醇酘。", "中丞自許憐漁父，鬲上無端住督郵。", "必使索郎頻有顧，也知歡伯解消憂。", "蘇州刺史詩盈卷，還憶山僧冷病不。"]'),
('dbc2c554-3d41-45a1-935e-c57f5b98951d','曉發鵝湖','洪炎','宋','宋诗','song-poetry','','[]','萬松參嶺路，千畝動春耕。',48,'全唐诗/poet.song.73000.json','["萬松參嶺路，千畝動春耕。", "不復紅鵝下，空餘碧澗橫。", "佛扃穿縹緲，仙馭鎖崢嶸。", "道釋分殊境，籃輿許我行。"]'),
('c598bfe2-984d-4ccd-8864-e1a86997d769','古田縣','洪炎','宋','宋诗','song-poetry','','[]','勾吳於越通舟車，南走甌閩城百餘。',64,'全唐诗/poet.song.73000.json','["勾吳於越通舟車，南走甌閩城百餘。", "鑿山架橋窮奧區，班春不行猶一墟。", "此邦自與桃源並，不能深藏即人境。", "五百年間閱戰爭，淳樸散盡狙詐生。"]'),
('ecbba6f2-6e6d-4813-a991-92476ccffce6','次韵和古田縣丞方景南見惠詩','洪炎','宋','宋诗','song-poetry','','[]','疏慵我似海鷗閑，文采君如霧豹斑。',64,'全唐诗/poet.song.73000.json','["疏慵我似海鷗閑，文采君如霧豹斑。", "不省流離思樂土，深知嚮往愧高山。", "低飛乳燕聲相接，小叩華鯨夢亦還。", "共看圍棋欲終日，忘年初在立談間。"]'),
('82115f99-da28-4f4b-806b-2a855014bd85','遊石鼓山湧泉院','洪炎','宋','宋诗','song-poetry','','[]','昔聞石鼓鳴，今作石鼓遊。',216,'全唐诗/poet.song.73000.json','["昔聞石鼓鳴，今作石鼓遊。", "擊拊久已息，甲兵殊未休。", "精廬莊嚴海，百室雲霧浮。", "維時當長夏，蕭颯如凉秋。", "高崖不見日，老木枝相樛。", "靈泉發嵌竇，下注千仞溝。", "向來經行人，頗以名字留。", "俯仰百年內，磨鎸遍巖幽。", "石橋可坐卧，清絕無等儔。", "衆山合沓來，響答相獻酬。", "雖逢會心欣，未弭當世憂。", "不知稽山上，復有勝處不。", "六飛尚東巡，狐兔穴中州。", "戈鋋塞河洛，冠蓋集閩甌。", "墮此吠雪國，烈火爛不收。", "炎飆方焚輪，赫曦欲停輈。", "微生類焦穀，茲焉得依投。", "一乘凌風翰，濯纓天漢流。"]'),
('1857c014-b0a1-41ca-89ba-377782078cfb','石湖院','洪炎','宋','宋诗','song-poetry','','[]','古木參天水一溝，潮來曲折可藏舟。',64,'全唐诗/poet.song.73000.json','["古木參天水一溝，潮來曲折可藏舟。", "招提密映晴嵐起，滄海潜通夜氣浮。", "丹荔薦盤驚北客，赤蟳供饌識炎洲。", "却疑江左知名士，不作乘桴浩蕩遊。"]'),
('6445d86e-ab78-4eb1-a0da-ec878a6e792d','初食生荔枝二首  其一','洪炎','宋','宋诗','song-poetry','','[]','六月寓閩山，初逢荔子丹。',48,'全唐诗/poet.song.73000.json','["六月寓閩山，初逢荔子丹。", "皺紅分顆顆，凝白作團團。", "品目誠無限，珍甘擬亦難。", "不勞走馬使，安坐得加餐。"]'),
('3bf3d036-5b64-4b68-9406-66e7c121cc03','初食生荔枝二首  其二','洪炎','宋','宋诗','song-poetry','','[]','獨擅東南美，誰知十八娘。',48,'全唐诗/poet.song.73000.json','["獨擅東南美，誰知十八娘。", "笑顰俱有味，朱粉不迷香。", "璀璨珠生掌，清泠露入囊。", "風流須第一，飣座每難忘。"]'),
('e8d190e1-da06-4f1e-b56a-5ad11c0c9d84','秋日登萬歲寺平遠臺次糜韵','洪炎','宋','宋诗','song-poetry','','[]','山川信美自愁多，嶺海窮途可若何。',64,'全唐诗/poet.song.73000.json','["山川信美自愁多，嶺海窮途可若何。", "倦客難尋越絕記，畸人但唱郢中歌。", "天香不入伊蒲塞，佛水猶開優鉢羅。", "還是浮雲韜白日，鳳凰臺上一經過。"]'),
('5059bd26-7a0f-4d75-8627-a1e4a2fbdeff','次韵和了信上座','洪炎','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','天公下觀戲魚龍，分披惇物隳岱宗。',192,'全唐诗/poet.song.73000.json','["天公下觀戲魚龍，分披惇物隳岱宗。", "塵沙欲枯罔象眼，酒醴難澆磊塊胸。", "會稽之南曰閩海，東行萬里因雄風。", "二兒得邑古長樂，意擬分治三山中。", "門張雀羅即我室，弔影不識求羊蹤。", "擔簦挾卷者誰氏，捉筆言詩有此公。", "紛紛道旁皆苦李，辛酸交攻無復理。", "入林初聞薝蔔香，知味自覺醍醐美。", "今時杜陵見老人，他日湯休望吾子。", "我觀蓬壺纔一水，桐柏羅浮相對起。", "赤烏銜符得寶書，青鳥拂簷來報喜。", "君能無事如懶殘，吾兒儻不慚張底。"]'),
('40b1964e-5181-4da1-be26-9734065df691','題團欒圖','洪炎','宋','宋诗','song-poetry','','[]','一老滅塵慮，七兒同靜緣。',48,'全唐诗/poet.song.73000.json','["一老滅塵慮，七兒同靜緣。", "境超法界觀，身作地行仙。", "男女非殊相，丹青亦浪傳。", "襄陽聚首話，猶是在家禪。"]'),
('190b9a01-9bae-478a-b9e2-b6e9f8cc83dd','社日宇文德和送酒次糜韵','洪炎','宋','宋诗','song-poetry','','[]','羈遊苦似澤藏山，老境難希藥駐顔。',64,'全唐诗/poet.song.73000.json','["羈遊苦似澤藏山，老境難希藥駐顔。", "日日尋香穿窈窕，行行止渴漱潺湲。", "忽聞歡伯來傾蓋，無數愁城盡斬關。", "多謝天公愛狂客，九衢忙裏獨偷閑。"]'),
('eccee848-9084-4b27-9573-b5cd850ad5f5','次韵許子大王豐父圓明送春之作','洪炎','宋','宋诗','song-poetry','','[]','鶗鴂能愁物外人，芳菲聊借夢中身。',64,'全唐诗/poet.song.73000.json','["鶗鴂能愁物外人，芳菲聊借夢中身。", "要知瓊刃非凡骨，信有金庭不盡春。", "伯雅相將浮鴨綠，素娥應共踏蟾銀。", "休驚麗句同仙授，王許從來侍帝宸。"]'),
('2274bb25-91f7-4ca3-bba4-75f65a6ee8ff','次韵許子大李丞相宅牡丹芍藥詩','洪炎','宋','宋诗','song-poetry','','[]','山丹麗質冠年華，復有餘容殿百花。',64,'全唐诗/poet.song.73000.json','["山丹麗質冠年華，復有餘容殿百花。", "看取三春如轉影，折來一笑是生涯。", "綺羅不妒傾城色，蜂蝶難窺上相家。", "京國十年昏病眼，可憐風雨落朝霞。"]'),
('c3809123-1470-4eb5-a23b-b073235dd5f6','福州程使君止戈堂二首  其一','洪炎','宋','宋诗','song-poetry','','[]','甌山閩海兩高深，幕府同開閱古今。',64,'全唐诗/poet.song.73000.json','["甌山閩海兩高深，幕府同開閱古今。", "堂號止戈賢守意，郡名長樂聖君心。", "行看鑄劍爲農器，即有飛鴞集泮林。", "比日東南是洙泗，喜聞弦誦發清音。"]'),
('6336393e-5ae0-4109-81a3-3fea70eb714b','福州程使君止戈堂二首  其二','洪炎','宋','宋诗','song-poetry','','[]','跳梁山谷有頑民，電掃風除一聚塵。',64,'全唐诗/poet.song.73000.json','["跳梁山谷有頑民，電掃風除一聚塵。", "排闥江山千里眼，滿庭桃李四時春。", "定知當宁思龔遂，政恐攀輿借寇恂。", "誰是諸侯老賓客，酣歌應許杜陵人。"]'),
('21124d54-b83b-477e-99ae-6cbe678c145d','聞師川諫議至漳州作建除字詩十二韵迓之','洪炎','宋','宋诗','song-poetry','','[]','建武下詔書，海嶠識明主。',144,'全唐诗/poet.song.73000.json','["建武下詔書，海嶠識明主。", "除吏得陽城，所喜逸民舉。", "滿腹懷經綸，筆間含露雨。", "平生相期心，中興爾乎取。", "定交自疇昔，契闊及再暑。", "執熱子南來，五月憩漳浦。", "破啼謀一笑，預置風月俎。", "危言儻可陳，正學當盡吐。", "成虧在須臾，得失宜熟數。", "收功謝王魏，取道迹傅呂。", "開茲衆正路，慰彼蒼生苦。", "閉關拒他盜，拂席招巢許。"]'),
('89688399-85d5-483d-908f-85ddb6a5ce74','坐上呈師川有懷駒父','洪炎','宋','宋诗','song-poetry','','[]','上坡諫議立清班，入奉威顔咫尺天。',64,'全唐诗/poet.song.73000.json','["上坡諫議立清班，入奉威顔咫尺天。", "仲氏三山久憔悴，徵君五嶺亦迍邅。", "欣逢白鶴歸華表，更想黄能出羽淵。", "客舍一樽雙淚落，相逢里社復何年。"]'),
('8dfd833d-04e3-4add-b41c-2063b6d62ad4','師川見和再用元韵','洪炎','宋','宋诗','song-poetry','','[]','河洛中秋已凜然，甌閩八月尚炎天。',64,'全唐诗/poet.song.73000.json','["河洛中秋已凜然，甌閩八月尚炎天。", "方懷許國忠言切，不計歸途道里邅。", "子産未能忘季札，太阿應必待龍淵。", "樹人樹木有明算，誰謂百年同十年。"]'),
('0dd24d7d-a507-45ab-aff6-3da70e5a978d','鉛山縣石井院','洪炎','宋','宋诗','song-poetry','','[]','兩年再踏鉛山路，今日初嘗石井泉。',32,'全唐诗/poet.song.73000.json','["兩年再踏鉛山路，今日初嘗石井泉。", "碧玉巖邊瀹湯餠，全勝五鼎擊肥鮮。"]'),
('fec9e4f5-7c9f-49d4-8f6a-edddf441f0f5','初入浙中三首  其一','洪炎','宋','宋诗','song-poetry','','[]','松竹籠官道，牛羊食野田。',48,'全唐诗/poet.song.73000.json','["松竹籠官道，牛羊食野田。", "岊山低送客，蕩水遠涵天。", "乍聽吳兒語，初逢傖父船。", "平生足未歷，聊以慰華顛。"]'),
('48f0e3c4-d35c-48a1-b978-c4db23ad8949','初入浙中三首  其二','洪炎','宋','宋诗','song-poetry','','[]','我生豫章汭，遊宦在京華。',48,'全唐诗/poet.song.73000.json','["我生豫章汭，遊宦在京華。", "百粵非吾土，三吳亦爾家。", "客星嚴瀨釣，西子越溪紗。", "一洗眵昏眼，如乘上漢槎。"]'),
('90adcfb6-6aba-46af-97fd-8ff32eef475f','初入浙中三首  其三','洪炎','宋','宋诗','song-poetry','','[]','山村柿栗熟，客舍稻粱秋。',48,'全唐诗/poet.song.73000.json','["山村柿栗熟，客舍稻粱秋。", "池足能言鴨，蹊多喘月牛。", "如聞息戰鬭，剩欲起歌謳。", "鼓檝臨江誓，誰爲祖豫州。"]'),
('af383c12-d2d2-4e2a-9fc6-49e9f1ebfcb5','立秋日上饒郡偶成二首  其一','洪炎','宋','宋诗','song-poetry','','[]','承明非厭直，衰疾自投閑。',48,'全唐诗/poet.song.73000.json','["承明非厭直，衰疾自投閑。", "江漢蒸炊內，盤盂嗒哈間。", "層冰萬里夢，謁帝九重關。", "願借摶風翼，追游物外山。"]'),
('cd0caf9a-4afd-4d8d-a93f-d9a87c2412df','立秋日上饒郡偶成二首  其二','洪炎','宋','宋诗','song-poetry','','[]','平生逃暑飲，病著不濡脣。',48,'全唐诗/poet.song.73000.json','["平生逃暑飲，病著不濡脣。", "熨齒甘瓜冷，流匙香粒勻。", "加餐雖意决，對案已眉顰。", "却歎廉頗老，猶爲善飯人。"]'),
('e54c770e-6964-47f7-9f95-7c969f902dbd','盛彥光次韵見和復用前韵因以自嘆  其一','洪炎','宋','宋诗','song-poetry','','[]','星織烏同織，鶴閑鷗亦閑。',48,'全唐诗/poet.song.73000.json','["星織烏同織，鶴閑鷗亦閑。", "問君離俗久，何事落人間。", "末伏秋無雨，殘歊晝掩關。", "寒泉聊洗耳，清冷似吾山。"]'),
('50938672-0ae6-4202-a202-be7893dc4e42','盛彥光次韵見和復用前韵因以自嘆  其二','洪炎','宋','宋诗','song-poetry','','[]','凉飆將透齒，烈火謝燋脣。',48,'全唐诗/poet.song.73000.json','["凉飆將透齒，烈火謝燋脣。", "壁織梭梭應，簷珠顆顆勻。", "隠憂成獨樂，淺笑換深顰。", "更上藐姑射，問途冰雪人。"]'),
('5dd77790-13c3-4145-a464-18c6a207fe0e','夢中作四言用前韵二首  其一','洪炎','宋','宋诗','song-poetry','','[]','事有怕愛，語分忙閑。',40,'全唐诗/poet.song.73000.json','["事有怕愛，語分忙閑。", "左右前後，內外中間。", "青雲千里，紫氣浮關。", "五星東井，微臣北山。"]'),
('64fc0ff5-6ec5-49d1-adb7-9766f45ffe0b','夢中作四言用前韵二首  其二','洪炎','宋','宋诗','song-poetry','','[]','鶂鶂珍腿，猩猩美脣。',40,'全唐诗/poet.song.73000.json','["鶂鶂珍腿，猩猩美脣。", "醴齊調適，勺藥和勻。", "老商嬉笑，西施解顰。", "倦龜若士，翳桑餓人。"]'),
('051bce2f-a475-4f4a-9e33-47da46d8085b','再次四言韵二首  其一','洪炎','宋','宋诗','song-poetry','','[]','執虎入圈，縶駒在閑。',40,'全唐诗/poet.song.73000.json','["執虎入圈，縶駒在閑。", "志六合外，身十畝間。", "組繫單于，泥封函關。", "樂我叢桂，淮南小山。"]'),
('c2a6b4e8-baeb-46d6-bbcc-d316216b57a7','再次四言韵二首  其二','洪炎','宋','宋诗','song-poetry','','[]','魯兄衛弟，虞齒虢脣。',40,'全唐诗/poet.song.73000.json','["魯兄衛弟，虞齒虢脣。", "倚伏相因，否泰惟勻。", "履茲艱虞，慎厥笑顰。", "水清見石，天定勝人。"]'),
('db6ca4b1-b08a-4d7e-84f6-2d62b027775f','三次四言韵二首  其一','洪炎','宋','宋诗','song-poetry','','[]','入聖有域，存誠以閑。',40,'全唐诗/poet.song.73000.json','["入聖有域，存誠以閑。", "德不德上，材不材間。", "堂上不糞，門設常關。", "鄙哉丘垤，覆簣爲山。"]'),
('bb6222dc-bb0f-4485-a8db-03da21d0fca2','三次四言韵二首  其二','洪炎','宋','宋诗','song-poetry','','[]','編貝皓齒，含朱絳脣。',40,'全唐诗/poet.song.73000.json','["編貝皓齒，含朱絳脣。", "甄陶圓熟，琢削細勻。", "不笑不言，倚席以顰。", "商略有此，爲若而人。"]'),
('21873ac6-722c-4688-8ea5-abe8b241ce8a','秋分日偶成','洪炎','宋','宋诗','song-poetry','','[]','洪崖山下一臞儒，碧玉巖邊抱病夫。',32,'全唐诗/poet.song.73000.json','["洪崖山下一臞儒，碧玉巖邊抱病夫。", "永日翛然無復事，人欺憔悴鬼揶揄。"]'),
('c03d2293-6777-4acd-838f-5fd2b2fb7df2','曾仲共和予春日登滕王閣詩蓋舊詩也復次韵','洪炎','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','西江東畔見江樓，江月江風萬斛愁。',32,'全唐诗/poet.song.73000.json','["西江東畔見江樓，江月江風萬斛愁。", "試問海潮應念我，爲將雙淚到南州。"]'),
('646b6306-6d5c-4c49-b0fd-25c62fa48004','蠟梅','洪炎','宋','宋诗','song-poetry','','[]','見江樓下蠟梅花，香撲金尊醉落霞。',32,'全唐诗/poet.song.73000.json','["見江樓下蠟梅花，香撲金尊醉落霞。", "獨依東風如夢覺，一枝春色別人家。"]'),
('42544e8d-959b-449e-8757-15959d229901','人日','洪炎','宋','宋诗','song-poetry','','[]','開歲逢人日，吾衰不夢周。',48,'全唐诗/poet.song.73000.json','["開歲逢人日，吾衰不夢周。", "家書生遠恨，客舍起離憂。", "朔雪驚南服，江梅笑隴頭。", "誰能結綵勝，一爲散春愁。"]'),
('5701e333-93f0-41ac-8562-f22c55b8b5ef','鍾乳','洪炎','宋','宋诗','song-poetry','','[]','鍾乳宜爲粉，扶衰老所便。',48,'全唐诗/poet.song.73000.json','["鍾乳宜爲粉，扶衰老所便。", "緘藏鵝管細，冶鍊玉丸堅。", "石髓誠難值，雲腴恐浪傳。", "刀圭聊已疾，未敢議真仙。"]'),
('2982902b-9fb7-4ec7-8ede-1f42827f12f2','葉少藴出示鄭先覺閱駿圖爲作長歌','洪炎','宋','宋诗','song-poetry','','[]','丹青得名曹將軍，畫馬已來無復人。',216,'全唐诗/poet.song.73000.json','["丹青得名曹將軍，畫馬已來無復人。", "諸生韓幹受肉法，絕足亦傳沙苑真。", "儒林望郎李公麟，曹韓復生能與鄰。", "心胸可納天西極，紈素頻空糞北羣。", "鄭生晚識李侯比，自許筆端輕萬里。", "山川初出大宛城，翰墨猶沾渥洼水。", "汗血歕沙指顧間，霧鬣風鬃卷中起。", "戲成十馬皆龍材，前有飛黄後山子。", "葉公好尚有祖風，苦愛真龍似畫龍。", "千金不惜市駿骨，睥睨神物秋毫中。", "英雄嘗聞妾換馬，意氣欲將詩換畫。", "詩工畫妙兩崛奇，谷量馬觀未論價。", "公詩自是生驊騮，恨公不身親李侯，向來曹韓空白頭。"]'),
('2fcad2b1-0f5d-4bb6-8b99-d15091822704','和曾仲共大風折木歌','洪炎','宋','宋诗','song-poetry','','[]','疾風岌嶪土囊口，陽崖中裂陰崖吼。',192,'全唐诗/poet.song.73000.json','["疾風岌嶪土囊口，陽崖中裂陰崖吼。", "南山喬木大百圍，頃刻翦伐如斷臼。", "修枝偃蹇擲龍蛇，直幹崩山塞巖岫。", "干雲蔽日掃地空，掣電奔霆翻覆手。", "山靈掩泣惋惜深，匠石含悲涕洟久。", "折臂而公黥而王，精金當鎔玉當剖。", "斷木刳爲浮海航，路指銀河上牛斗。", "委餘猶得宮殿材，瑣細亦蒙梁棟取。", "萬斛之舟可弗論，大厦帡幪此焉有。", "狂飆卷空欲奚爲，壽被金石長不朽。", "天生大材將有用，乖逢相因孰先後。", "嗟爾乾楓與枯柳，摧折爲薪尚誰咎。"]'),
('3666a85d-0890-44fe-ac2a-b7a15c2a89fa','楚州阻水漲懷汪信民呂居仁二士四言','洪炎','宋','宋诗','song-poetry','','[]','大江北理，長淮西逝。',140,'全唐诗/poet.song.73000.json','["大江北理，長淮西逝。", "厥隩射陽，城邑嶽峙。", "鑿渠而漕，首淮江尾。", "舳艫岢峨，連檣千里。", "青雀翩翩，彩虹嶷嶷。", "梁跼舟蹐，限茲潢水。", "昔我至止，得二國士。", "簞瓢相樂，汪呂氏子。", "于今幾年，乖隔生死。", "梗泛萍飄，乃復于此。", "菱花浄吐，鷺羽徐起。", "如欲我留，盼睞以喜。", "俯仰山川，感念成毀。", "一瞬千古，寓非予恥。"]'),
('a7255485-c4ef-48ce-97cb-921e71a62aa9','奉送駒父師川二郎中赴召四言','洪炎','宋','宋诗','song-poetry','','[]','火中暑退，庚伏在婁。',130,'全唐诗/poet.song.73000.json','["火中暑退，庚伏在婁。", "赫熾方炎，金石欲流。", "之二大夫，服章紑紑。", "文昌臺郎，祗命是憂。", "中江有舳，中涂有輈。", "風檣雨轂，長夏爲秋。", "白雲在天，崒如巖丘。", "倏忽西東，不我告謀。", "翩翩者鵠，俯矚魚游。", "將逝復止，矯影河洲。", "嗟予去國，三葛于休。", "止車生耳，永謝鳴騶。", "揮袂江干，長嘯林幽。"]'),
('40df7fba-1bdd-433d-b263-7b253fb6446a','遷居','洪炎','宋','宋诗','song-poetry','','[]','從宦三十載，故山凡幾歸。',180,'全唐诗/poet.song.73000.json','["從宦三十載，故山凡幾歸。", "昔歸尚有屋，再歸已傾欹。", "今歸但喬木，竹落荆薪扉。", "上爲鸛鳥都，下爲雞犬棲。", "相彼東北隅，三畝以爲基。", "積塊與運甓，實漥而培庳。", "成茲道傍舍，空我橐中貲。", "堂室敢即安，牖戶適所宜。", "嘉樹三四株，當窗發華滋。", "馨香入懷袖，似與遷徙期。", "我今六十老，豈不知前非。", "咨謀愚見拾，就列筋力微。", "竊食奉祠祿，永負伐檀詩。", "松楸幸在望，鄰曲不見遺。", "葛巾隨里社，庶以保期頤。"]'),
('8cd351e3-2166-431d-8472-770010c6325e','次韵公實與用中夜話','洪炎','宋','宋诗','song-poetry','','[]','賢哉鄭圃客，去爲五漿驚。',48,'全唐诗/poet.song.73000.json','["賢哉鄭圃客，去爲五漿驚。", "解榻棲雲表，開窗納水聲。", "忽逢京國舊，相對夜燈明。", "歎息胡証老，猶思摘鐵檠。"]'),
('76fc4035-f51a-4e95-ab7e-e75b7fd800e0','玉女峰','洪炎','宋','宋诗','song-poetry','','[]','玉女何時見，茲峰獨挺羣。',48,'全唐诗/poet.song.73000.json','["玉女何時見，茲峰獨挺羣。", "古容餘佛座，虛室但鑪薰。", "林隠投壺電，山藏出岫雲。", "自慚非屈宋，欲賦不成文。"]'),
('0fa49159-72d7-4a17-afde-35e81ddfa7ea','再任秘書少監','洪炎','宋','宋诗','song-poetry','','[]','再入蘭臺逢舊史，重遊東觀閱新書。',32,'全唐诗/poet.song.73000.json','["再入蘭臺逢舊史，重遊東觀閱新書。", "家徒四壁今無屋，誰爲君王奏子虛。"]'),
('21d3701a-1485-45d7-a9fe-7855f9a13851','絕句','洪炎','宋','宋诗','song-poetry','','[]','桃花浪打散花樓，南浦西山送客愁。',32,'全唐诗/poet.song.73000.json','["桃花浪打散花樓，南浦西山送客愁。", "爲理伊州十二疊，緩歌聲裏看洪州。"]'),
('a36f2ff9-595a-40d1-bed6-b2418cc0c66e','逍遥閣','洪炎','宋','宋诗','song-poetry','','[]','傑閣龍樓依翠微，中秋午夜望清輝。',64,'全唐诗/poet.song.73000.json','["傑閣龍樓依翠微，中秋午夜望清輝。", "桂枝委地三千尺，柏影垂壇四十圍。", "簫鼓或疑風雨下，雲霞猶想錦帆飛。", "只今井臼依然在，不見歸來丁令威。"]'),
('a635b0f0-3150-482a-8e33-6f15f47d013f','玉女峰','洪炎','宋','宋诗','song-poetry','','[]','曾折山花獻阿魔，茫茫仙意果如何。',32,'全唐诗/poet.song.73000.json','["曾折山花獻阿魔，茫茫仙意果如何。", "千年舊跡今蕪沒，惟有長松掛蔦蘿。"]'),
('908f5d78-8e53-44ba-b791-2c25ad3a0734','句','洪炎','宋','宋诗','song-poetry','','[]','處世真同逐隊魚。',8,'全唐诗/poet.song.73000.json','["處世真同逐隊魚。"]'),
('a7915f3e-e667-4371-b302-4b9a6c4c282b','存目','洪炎','宋','宋诗','song-poetry','','[]','詩題：胡偉《宮詞集句》句首：不應青女妒容華。',22,'全唐诗/poet.song.73000.json','["詩題：胡偉《宮詞集句》句首：不應青女妒容華。"]'),
('0f512b7f-c926-4842-a8ae-097edba27cc3','久陰初晴奉陪宮使樞密觀梅','范沖','宋','宋诗','song-poetry','','[]','掃盡陰氛儘見春，荒山風物一時新。',32,'全唐诗/poet.song.73000.json','["掃盡陰氛儘見春，荒山風物一時新。", "謫仙自是和羹手，聊與梅花作主人。"]'),
('994f0eea-9dbe-4820-ba45-fd0661fe0eaa','石橋  其一','范沖','宋','宋诗','song-poetry','','[]','石梁傑出望南州，登覽從公破旅愁。',64,'全唐诗/poet.song.73000.json','["石梁傑出望南州，登覽從公破旅愁。", "棋罷未應消一日，人歸無奈已千秋。", "塵纓自喜臨流濯，車轄仍逢好事投。", "莫怪神仙近如許，當年此地絕深幽。"]'),
('e0e09b71-8ca7-4971-a703-d44e71efa0c4','石橋  其二','范沖','宋','宋诗','song-poetry','','[]','秋風吹上景華天，醉夢醒來一灑然。',64,'全唐诗/poet.song.73000.json','["秋風吹上景華天，醉夢醒來一灑然。", "萬古林泉招我老，百年風雨復誰憐。", "頓除熱惱初無病，剩買安閑不用錢。", "尋得青霞是歸處，漫修巖穴小乘禪。"]'),
('db55f6f8-59f9-4c38-b411-ad1994ea2a40','贈永平寺僧了空','范沖','宋','宋诗','song-poetry','','[]','幾回飛錫入紅塵，一任隨緣自在身。',64,'全唐诗/poet.song.73000.json','["幾回飛錫入紅塵，一任隨緣自在身。", "琢句不妨明日用，援琴誰與聽陽春。", "揚眉瞬目如相委，捧腹狂歌即是真。", "湯餠藜羹奉朝夕，自憐擔板小乘人。"]'),
('adbc2dc9-e520-4c7c-94a4-3fcc58361508','建寧丹青閣','趙岍','宋','宋诗','song-poetry','','[]','跨壑飛簷屋數楹，上橫山色下溪聲。',32,'全唐诗/poet.song.73000.json','["跨壑飛簷屋數楹，上橫山色下溪聲。", "等閑題作丹青閣，未必丹青畫得成。"]'),
('76456d0a-55ef-4b24-843e-9b62ef0cdc5b','句','趙岍','宋','宋诗','song-poetry','','[]','美景天湖呈六六。',8,'全唐诗/poet.song.73000.json','["美景天湖呈六六。"]'),
('e1d82999-a072-42e6-9588-e926a14e3a06','自舂陵還題驛舍壁','朱輅','宋','宋诗','song-poetry','','[]','邵陵北望幾勞魂，白首慈親日倚門。',32,'全唐诗/poet.song.73000.json','["邵陵北望幾勞魂，白首慈親日倚門。", "雲外歸鴻如可托，平安先爲慰晨昏。"]'),
('d6450aa2-def0-4268-824e-31aea5e4a5e2','任桂陽監使挂冠養母述懷','朱輅','宋','宋诗','song-poetry','','[]','勇退無心戀一麾，叩閽乞得侍庭闈。',64,'全唐诗/poet.song.73000.json','["勇退無心戀一麾，叩閽乞得侍庭闈。", "二千石祿人皆羨，九十慈親古亦稀。", "東閣雖無文舉酒，北堂幸有老萊衣。", "黄粱未熟渾閒事，且卧南山飽蕨薇。"]'),
('49b6422a-bcc7-4b76-831b-0f16314dec36','仁壽樓','徐庚','宋','宋诗','song-poetry','','[]','撥置南荒果是非，性真全取未生時。',32,'全唐诗/poet.song.73000.json','["撥置南荒果是非，性真全取未生時。", "前溪流水日夜逝，樓上主人渾不知。"]'),
('86a36b61-8843-4d9a-8be0-731d7f918572','題閶門外小寺壁','寇國寶','宋','宋诗','song-poetry','','[]','黄葉西陂水漫流，籧篨風急滯扁舟。',32,'全唐诗/poet.song.73000.json','["黄葉西陂水漫流，籧篨風急滯扁舟。", "夕陽暝色來千里，人語鷄聲共一丘。"]'),
('5cc4eb36-05cf-4c75-8c75-b37d872b94a1','寄謝無逸','汪革','宋','宋诗','song-poetry','','[]','問訊江南謝康樂，溪堂春木想扶疏。',64,'全唐诗/poet.song.73000.json','["問訊江南謝康樂，溪堂春木想扶疏。", "高談何日看揮麈，安步從來可當車。", "但得丹霞訪龐老，何須狗監薦相如。", "新年更勵於陵節，妻子同鉏五畝蔬。"]'),
('c26f2bc7-772e-4adb-9027-ec0dd99c9197','和呂居仁春日','汪革','宋','宋诗','song-poetry','','[]','晏坐黌堂一事無，居官蕭散似相如。',32,'全唐诗/poet.song.73000.json','["晏坐黌堂一事無，居官蕭散似相如。", "偶違濁酒風前約，不見繁英雨後疏。"]'),
('210914cc-04ce-4822-ac8b-dc2375cc48da','代滎陽公作張先生哀詞','汪革','宋','宋诗','song-poetry','','[]','惟古制行，必中庸兮。',30,'全唐诗/poet.song.73000.json','["惟古制行，必中庸兮。", "降及末世，戾不通兮。", "首陽柱下，更拙工兮。"]'),
('9f3bc621-7d5d-49e2-8c47-086efac770b3','賢女浦  其一','汪革','宋','宋诗','song-poetry','','[]','賢女標名幾度秋，行人撫事至今愁。',32,'全唐诗/poet.song.73000.json','["賢女標名幾度秋，行人撫事至今愁。", "湘雲楚雨知何處，月冷風悲江自流。"]'),
('1faa562d-e3c1-47d3-be50-39b392540fb3','賢女浦  其二','汪革','宋','宋诗','song-poetry','','[]','女子能留身後名，包羞忍恥漫公卿。',32,'全唐诗/poet.song.73000.json','["女子能留身後名，包羞忍恥漫公卿。", "可憐嗚咽灘頭水，渾似曹娥江上聲。"]'),
('c8e9903e-776f-4096-abb8-7fda4d04da14','歲暮書堂','汪革','宋','宋诗','song-poetry','','[]','霜重階鋪紈，風凜肌生粟。',24,'全唐诗/poet.song.73000.json','["霜重階鋪紈，風凜肌生粟。", "心莊耳目清，思慮無由俗。"]'),
('3182dd69-dce9-4a85-b399-e0fe95ea59b7','詩一首','汪革','宋','宋诗','song-poetry','','[]','富貴空中花，文章木上癭。',24,'全唐诗/poet.song.73000.json','["富貴空中花，文章木上癭。", "要知真實地，惟有華嚴境。"]'),
('07d9a26b-d872-40ec-8c03-f42e9d34e74e','句  其一','汪革','宋','宋诗','song-poetry','','[]','釜星晚雜出，雨脚晨可歇。',12,'全唐诗/poet.song.74000.json','["釜星晚雜出，雨脚晨可歇。"]'),
('899b695c-8abe-4a87-acb1-187427f505cb','句  其二','汪革','宋','宋诗','song-poetry','','[]','紫闥青雲俱未遂。',8,'全唐诗/poet.song.74000.json','["紫闥青雲俱未遂。"]'),
('b7c5ba7d-bc07-41c3-8c0f-efe98a99024e','贈翠微主僧沖邈','姚舜明','宋','宋诗','song-poetry','','[]','僧臘俗年俱老大，儒書佛教舊精勤。',32,'全唐诗/poet.song.74000.json','["僧臘俗年俱老大，儒書佛教舊精勤。", "姑蘇一萬披緇客，四事無如彼上人。"]'),
('290f7342-2c14-46fe-b75e-116868446591','三江亭','蔣璿','宋','宋诗','song-poetry','','[]','安仁不放二毛侵，爽氣凌虛玉萬尋。',64,'全唐诗/poet.song.74000.json','["安仁不放二毛侵，爽氣凌虛玉萬尋。", "談笑薄施三昧手，登臨誰會五湖心。", "倦游方戢沖天翼，高賦難賡擲地金。", "怪得朝雲飛畫棟，夜來曾聽老龍吟。"]'),
('6add1bca-ac3c-43db-bec8-5b8a2a5611e6','詩一首','林虙','宋','宋诗','song-poetry','','[]','我公道德祖東丘，志小全吳見此游。',64,'全唐诗/poet.song.74000.json','["我公道德祖東丘，志小全吳見此游。", "遠意最稱包萬里，佳名直欲付千秋。", "眷憐今日踰文獻，友愛終身負道州。", "扶病强隨都騎去，回腸百折伴江流。"]'),
('7bad3a6c-01ec-4f3b-996b-fa935156bbc9','句','胡伸','宋','宋诗','song-poetry','','[]','誰能分夢覺，真妄兩悠悠。',12,'全唐诗/poet.song.74000.json','["誰能分夢覺，真妄兩悠悠。"]'),
('34114725-6965-412b-a39a-90bfff840b40','河朔同官倡和用山字韵','胡直孺','宋','宋诗','song-poetry','','[]','章句飄飄續小山，古風蕭瑟筆追還。',64,'全唐诗/poet.song.74000.json','["章句飄飄續小山，古風蕭瑟筆追還。", "海鵬共擊三千里，鐵馬同歸十二閑。", "功業會看鍾鼎上，聲華已在搢紳間。", "他年記憶憐衰老，爲報西川引一班。"]'),
('82d49000-8160-4092-b919-b2ce0d79948b','與劉邦直','胡直孺','宋','宋诗','song-poetry','','[]','夢魂南北昧平生，邂逅相逢意已傾。',64,'全唐诗/poet.song.74000.json','["夢魂南北昧平生，邂逅相逢意已傾。", "楚國山川千疊遠，隋堤烟雨一帆輕。", "我無健筆翻三峽，君有長才肅五兵。", "同是行人更分首，不堪風樹作秋聲。"]'),
('5318e1e4-c01e-48ee-834c-176db26acf7f','送春','胡直孺','宋','宋诗','song-poetry','','[]','含酸梅子漸生仁，鶑老花飛迹已陳。',32,'全唐诗/poet.song.74000.json','["含酸梅子漸生仁，鶑老花飛迹已陳。", "一夜南風摇斗柄，明朝烟柳不關春。"]'),
('7f42ec34-2ad3-448a-8477-92fc7e2fbf5e','春日','胡直孺','宋','宋诗','song-poetry','','[]','風雲吹絮柳飛花，睡起鉤簾日半斜。',32,'全唐诗/poet.song.74000.json','["風雲吹絮柳飛花，睡起鉤簾日半斜。", "四海隨人雙燕子，相逢處處作生涯。"]'),
('5f370b54-c72d-4fbf-a23c-82f8febc5fb6','譏章持','紹聖時人','宋','宋诗','song-poetry','','[]','何處難忘酒，南宮放榜時。',48,'全唐诗/poet.song.74000.json','["何處難忘酒，南宮放榜時。", "有才如杜牧，無勢似章持。", "不取通經士，先收執政兒。", "此時無一盞，何以展愁眉。"]'),
('5fe704fd-16aa-4597-ac00-68ab3dfb1dd4','紀夢八詩  其一','劉允','宋','宋诗','song-poetry','','[]','銀築層臺玉砌成，五雲深映百花明。',32,'全唐诗/poet.song.74000.json','["銀築層臺玉砌成，五雲深映百花明。", "獸環響徹重門啟，無限青娥喜笑迎。"]'),
('5c34f0ee-a060-4870-aff7-8d3cc4950cc4','紀夢八詩  其二','劉允','宋','宋诗','song-poetry','','[]','青鬟前引度回廊，簾捲雲間舊院堂。',32,'全唐诗/poet.song.74000.json','["青鬟前引度回廊，簾捲雲間舊院堂。", "松桂滿庭龜鶴在，儼然丰觀道家裝。"]'),
('88b9669a-8357-4373-9f0e-4e864e7ce0c7','紀夢八詩  其三','劉允','宋','宋诗','song-poetry','','[]','徐入東堂百步餘，虛堂猶記舊來居。',32,'全唐诗/poet.song.74000.json','["徐入東堂百步餘，虛堂猶記舊來居。", "窗紗掩映瓊籤軸，盡是當時讀遍書。"]'),
('d171e8cb-adad-489d-9c4e-e96e5005f825','紀夢八詩  其四','劉允','宋','宋诗','song-poetry','','[]','曈矓瑞日照觚稜，溶曳祥烟遠棟甍。',32,'全唐诗/poet.song.74000.json','["曈矓瑞日照觚稜，溶曳祥烟遠棟甍。", "松檜雅知人趣尚，風來偏作步虛聲。"]'),
('384bb9ad-cb63-44fe-bce8-5ceb06272e49','紀夢八詩  其五','劉允','宋','宋诗','song-poetry','','[]','側金壇畔虬松老，甃玉池邊綬虉長。',32,'全唐诗/poet.song.74000.json','["側金壇畔虬松老，甃玉池邊綬虉長。", "吟折紫芝香滿手，數聲鳴鳳在修篁。"]'),
('bc4d0387-ee61-4c0f-9294-db9e17e520b7','紀夢八詩  其六','劉允','宋','宋诗','song-poetry','','[]','獸爐烟和百花香，玉葉瓊枝倚兩旁。',32,'全唐诗/poet.song.74000.json','["獸爐烟和百花香，玉葉瓊枝倚兩旁。", "一曲雲和鸞鶴舞，勸人爭捧九霞觴。"]'),
('af79d259-2809-42dd-9a00-3cb0ea2c45c2','紀夢八詩  其七','劉允','宋','宋诗','song-poetry','','[]','雲母屏間看舊題，醉吟阿母碧桃枝。',32,'全唐诗/poet.song.74000.json','["雲母屏間看舊題，醉吟阿母碧桃枝。", "羣仙指點未題處，更乞凌虛白鶴詞。"]'),
('c8797ed0-0e4d-4454-a996-f315a83524c3','紀夢八詩  其八','劉允','宋','宋诗','song-poetry','','[]','步出朱宮日漸移，青鬟羅拜問歸期。',32,'全唐诗/poet.song.74000.json','["步出朱宮日漸移，青鬟羅拜問歸期。", "塵緣若斷人間世，看取蟠桃正熟時。"]'),
('0e338fac-440a-4861-b99c-a4a4c546144d','夢中作  其一','劉允','宋','宋诗','song-poetry','','[]','劉郎平昔志烟霞，時到雲山隠士家。',32,'全唐诗/poet.song.74000.json','["劉郎平昔志烟霞，時到雲山隠士家。", "除却松篁芝朮外，川源遠近遍桃花。"]'),
('4f37d468-5875-44be-8992-3d4d9d38e6b8','夢中作  其二','劉允','宋','宋诗','song-poetry','','[]','盡日看山不厭山，白雲飛去又飛還。',32,'全唐诗/poet.song.74000.json','["盡日看山不厭山，白雲飛去又飛還。", "傍人莫指雲相似，雲自無心我自閑。"]'),
('02c993c4-70a7-4871-8753-a891e87b4dc7','又五言絕句一首','劉允','宋','宋诗','song-poetry','','[]','武陵源上雪，片片雜雲霞。',24,'全唐诗/poet.song.74000.json','["武陵源上雪，片片雜雲霞。", "惟有雪中桃，長開三尺花。"]'),
('d5e89f92-5493-440d-b504-ce9bc2a83f29','韓山','劉允','宋','宋诗','song-poetry','','[]','惆悵昌黎去不還，小亭牢落古松間。',32,'全唐诗/poet.song.74000.json','["惆悵昌黎去不還，小亭牢落古松間。", "月明夜靜神遊處，三十二峰江上山。"]'),
('f5d4c8bf-472f-4bde-8f57-eb2ac98d45fd','皇恩寺','陳之邵','宋','宋诗','song-poetry','','[]','老檜喬松路屈盤，翬飛金碧照巖端。',64,'全唐诗/poet.song.74000.json','["老檜喬松路屈盤，翬飛金碧照巖端。", "僧尋翠巘曾揮錫，客厭紅塵屢解鞍。", "望斷四天春野闊，夢回一枕夜濤寒。", "陽休況是多佳句，吟罷碧雲時倚闌。"]'),
('b77a8f15-0ff7-4af7-9f50-1f98ee305c90','壽時相','陳汝錫','宋','宋诗','song-poetry','','[]','五百年間瑞氣鍾，堂堂皎月衆星中。',64,'全唐诗/poet.song.74000.json','["五百年間瑞氣鍾，堂堂皎月衆星中。", "甄陶四海規模大，心膂三朝體貌隆。", "壽杖終扶黄髮老，衮衣今拜黑頭公。", "彭聃豈足延遐算，願助昇平到不窮。"]'),
('f4f6f856-aae5-47ff-87c1-6273fe35b09d','壽周侍講','陳汝錫','宋','宋诗','song-poetry','','[]','我聞仙翁山，秀色媚崗嶺。',168,'全唐诗/poet.song.74000.json','["我聞仙翁山，秀色媚崗嶺。", "昔人已仙去，飛步凌絕頂。", "世緣磨不盡，一念墮塵境。", "先生豈其人，骨相倍清整。", "神鍾金莖秀，氣與霜月冷。", "詞源倒三峽，筆力扛九鼎。", "書林知幾年，文字浩千頃。", "談經動旒纊，屢被前席請。", "當隨鳳閣班，徑步花磚影。", "胡爲罷勸講，禁幄出揚秉。", "一麾眇淮甸，素髮欲隨領。", "先生謫仙人，壽與龜鶴等。", "富貴要長年，功名看晚景。", "未須歎淹回，住世日月永。"]'),
('f821f503-d6c7-4468-86be-37656521a8e3','壽劉漕二首  其一','陳汝錫','宋','宋诗','song-poetry','','[]','清薰應候貢微凉，瑞靄蟠空報吉祥。',64,'全唐诗/poet.song.74000.json','["清薰應候貢微凉，瑞靄蟠空報吉祥。", "仙籍掛名書富貴，彩毫叶夢送文章。", "眉間已有陰功色，肘後何須不老方。", "節物也隨人意好，荷花爭入壽樽香。"]'),
('ede7f17f-df50-400a-bd1d-cce1c91eb0da','壽劉漕二首  其二','陳汝錫','宋','宋诗','song-poetry','','[]','碧槐風細篆烟清，綠芰香濃壽酒傾。',64,'全唐诗/poet.song.74000.json','["碧槐風細篆烟清，綠芰香濃壽酒傾。", "眉上嵩衡元秀整，胸中涇渭太分明。", "巨材閱世三千歲，修翮摶風九萬程。", "積粟流錢皆細事，異時鍾鼎看功名。"]'),
('9508cfe1-d0c4-45f3-93c3-76edd2a42599','石門山','陳汝錫','宋','宋诗','song-poetry','','[]','落帆倚芳洲，冷日銜翠壁。',180,'全唐诗/poet.song.74000.json','["落帆倚芳洲，冷日銜翠壁。", "沙平野步穩，不費支筇力。", "邂逅到幽洞，雲水已昏夕。", "陰崖上蒼穹，杳不見轍迹。", "巖前月色薄，細路稍有覓。", "瀑泉號秋聲，飛練不計尺。", "僧房得少憩，坐久耳方寂。", "河梁謫仙人，握手見胸臆。", "囊無一錢看，志有萬里適。", "拄頰望西山，琢句愈工績。", "同遊得二妙，筆障亦勁敵。", "笑談頗傾坐，酬唱屢即席。", "顧予舌本强，咀嚼覺清液。", "林泉信幽奇，歲月尤迅亟。", "茲游莫辭頻，能著幾兩屐。"]'),
('1994d04f-12c7-469a-a087-efcc4011be45','句','陳汝錫','宋','宋诗','song-poetry','','[]','閑愁莫浪遣，留爲痛飲資。',12,'全唐诗/poet.song.74000.json','["閑愁莫浪遣，留爲痛飲資。"]'),
('cda8285a-6d59-49de-bea8-04d718e06dfa','流花亭','陳與京','宋','宋诗','song-poetry','','[]','丹雘依巖腹，翬飛枕碧闉。',48,'全唐诗/poet.song.74000.json','["丹雘依巖腹，翬飛枕碧闉。", "應教臨水客，頻問種桃人。", "野色低籠日，溪光長占春。", "仙槎消息便，咫尺到龍津。"]'),
('d394f395-9458-4ff0-8290-2213576d8db4','瑞蓮橋即九曲池和王肱原韵','周公弼','宋','宋诗','song-poetry','','[]','石門雙峙聳前蹊，溪白疑藏照水犀。',64,'全唐诗/poet.song.74000.json','["石門雙峙聳前蹊，溪白疑藏照水犀。", "古木萬株清露染，曉風千疊瑞烟迷。", "虛巖伏虎和風嘯，峻壁聞猿向晚啼。", "更有淡軒軒上趣，妙緣真覺證菩提。"]'),
('6cd02389-afe3-45c9-917a-ac9a69c8e7e8','觀臨淮雙頭白蓮圖','周知微','宋','宋诗','song-poetry','','[]','君不學叔隗季隗南歸晉，又不學大喬小喬東入吳。',134,'全唐诗/poet.song.74000.json','["君不學叔隗季隗南歸晉，又不學大喬小喬東入吳。", "一種桃根與桃葉，若爲化作雙芙渠。", "臨淮政成有餘暇，坐令華屋生瀟灑。", "鵝溪一幅萬里寬，移得浙川入圖畫。", "天空水闊江茫茫，想見女英與娥皇。", "九疑雲深蒼梧遠，冰姿玉泣不成妝。", "苦心抱恨何時了，香骨應甘沒秋草。", "不如回首謝秋風，分作尹邢來漢宮。"]'),
('a711f040-2bdf-4413-b39a-41e2721ab996','浮萍','周知微','宋','宋诗','song-poetry','','[]','小靨浮青水拍堤，堤邊草色更相宜。',64,'全唐诗/poet.song.74000.json','["小靨浮青水拍堤，堤邊草色更相宜。", "一番穀雨晚晴後，萬點楊花春盡時。", "解與曲池藏寶鑑，不教新月妒蛾眉。", "怪來別岸波光闊，知是漁郎艇子移。"]'),
('30c37fe8-a3cb-4645-ae98-335d5ec281f1','題龜山','周知微','宋','宋诗','song-poetry','','[]','迢迢綠樹淮天曉，靄靄紅霞海日晴。',32,'全唐诗/poet.song.74000.json','["迢迢綠樹淮天曉，靄靄紅霞海日晴。", "遥望四山雲接水，碧峰千點數帆輕。"]'),
('eeec822b-476b-42dd-80b6-88ef47d0f49d','句  其一','周知微','宋','宋诗','song-poetry','','[]','疾風暴雨悲遊子，峻嶺崇山非故鄉。',16,'全唐诗/poet.song.74000.json','["疾風暴雨悲遊子，峻嶺崇山非故鄉。"]'),
('1f5e5e9f-45b3-461d-959b-a7dd8ddf93c1','句  其二','周知微','宋','宋诗','song-poetry','','[]','後車鶑燕春聲早，前騎熊羆夜氣遒。',16,'全唐诗/poet.song.74000.json','["後車鶑燕春聲早，前騎熊羆夜氣遒。"]'),
('4d8f6d89-cc80-4b36-94fc-314172795124','句  其三','周知微','宋','宋诗','song-poetry','','[]','暮天斜去空成字，遠地頻來不寄書。',16,'全唐诗/poet.song.74000.json','["暮天斜去空成字，遠地頻來不寄書。"]'),
('69069bf3-c772-4de8-b646-808d131eff02','擬梅軒三首  其一','吳幵','宋','宋诗','song-poetry','','[]','陰陰綠葉不勝垂，著子全多欲壓枝。',32,'全唐诗/poet.song.74000.json','["陰陰綠葉不勝垂，著子全多欲壓枝。", "自得君王一留顧，故應雨露亦饒滋。"]'),
('e2b77652-0f0b-4573-be44-e618bea477d0','擬梅軒三首  其二','吳幵','宋','宋诗','song-poetry','','[]','五月霏霏雨不開，若耶溪畔摘楞梅。',32,'全唐诗/poet.song.74000.json','["五月霏霏雨不開，若耶溪畔摘楞梅。", "朱丸忽向雲窗見，疑是靈根越嶺來。"]'),
('d1d299fa-6a95-4cf7-a3ef-a0294be8c4fa','擬梅軒三首  其三','吳幵','宋','宋诗','song-poetry','','[]','誰將蜜漬借微酸，小摘曾聞脩玉盤。',32,'全唐诗/poet.song.74000.json','["誰將蜜漬借微酸，小摘曾聞脩玉盤。", "爭似江南風致在，瓶紅初向綠陰看。"]'),
('52e35ace-7cfa-4e0d-ab75-eec447773852','句  其一','吳幵','宋','宋诗','song-poetry','','[]','李衡千樹橘，張翰一漁舟。',12,'全唐诗/poet.song.74000.json','["李衡千樹橘，張翰一漁舟。"]'),
('098da2e8-3bb8-4e6e-8bc9-af532a534a3e','句  其二','吳幵','宋','宋诗','song-poetry','','[]','木落千山瘦，天高一雁橫。',12,'全唐诗/poet.song.74000.json','["木落千山瘦，天高一雁橫。"]'),
('ae7dcf0e-b7c2-4d82-8eee-0e4ab959faa3','句  其三','吳幵','宋','宋诗','song-poetry','','[]','鳥聲催暮急，山氣欲晴寒。',12,'全唐诗/poet.song.74000.json','["鳥聲催暮急，山氣欲晴寒。"]'),
('f9c51403-abcf-4353-a573-f4158eb6c103','句  其四','吳幵','宋','宋诗','song-poetry','','[]','鳴玉不妨風細細，瑣窗時借月娟娟。',16,'全唐诗/poet.song.74000.json','["鳴玉不妨風細細，瑣窗時借月娟娟。"]'),
('c2a4c439-59be-443f-a679-823c4bbfa7fc','句  其五','吳幵','宋','宋诗','song-poetry','','[]','星斗垂光燭紫壇。',8,'全唐诗/poet.song.74000.json','["星斗垂光燭紫壇。"]'),
('2c087104-c865-436c-bc1b-8292891c9663','句  其六','吳幵','宋','宋诗','song-poetry','','[]','欲識懽心從四海，鈞天一曲引回鑾。',16,'全唐诗/poet.song.74000.json','["欲識懽心從四海，鈞天一曲引回鑾。"]'),
('55f4c2b3-3b34-4c7b-b2cc-3a3599edae49','句  其七','吳幵','宋','宋诗','song-poetry','','[]','紛綸委貺知旁達，滲漉流恩亦下蟠。',16,'全唐诗/poet.song.74000.json','["紛綸委貺知旁達，滲漉流恩亦下蟠。"]'),
('f77bd3b6-a9a9-4958-8943-202aadde574d','感夢口占二絕  其一','倪昱','宋','宋诗','song-poetry','','[]','誰謂仙家隔一方，神遊原不閉毫芒。',32,'全唐诗/poet.song.74000.json','["誰謂仙家隔一方，神遊原不閉毫芒。", "歸來謾話長年事，老不饒人白鬢蒼。"]'),
('afc6c5d7-49c6-4aeb-a104-c03cc4eb9e63','感夢口占二絕  其二','倪昱','宋','宋诗','song-poetry','','[]','死生常事不須愁，我亦無心任去留。',32,'全唐诗/poet.song.74000.json','["死生常事不須愁，我亦無心任去留。", "人事重來聊爾爾，濁醪脫粟外何求。"]'),
('783f20f1-f6c0-432c-86f9-9f404a2953e7','登華頂峰','鮑朝賓','宋','宋诗','song-poetry','','[]','籃輿直上八重峰，千里秋蟾咫尺中。',32,'全唐诗/poet.song.74000.json','["籃輿直上八重峰，千里秋蟾咫尺中。", "寄語塵寰高會者，清光不與世間同。"]'),
('5fba883d-7337-4a2f-ae84-12318b8483b9','登南山','趙伯純','宋','宋诗','song-poetry','','[]','少陵雲間詩，重巖班菊蕊。',24,'全唐诗/poet.song.74000.json','["少陵雲間詩，重巖班菊蕊。", "二章刻巖腹，千載今可視。"]'),
('1bd12d46-c5e3-447e-a4a8-2e787007a5a9','句','趙伯光','宋','宋诗','song-poetry','','[]','誰云嶺外皆炎熱，此是西南第一州。',16,'全唐诗/poet.song.74000.json','["誰云嶺外皆炎熱，此是西南第一州。"]'),
('8e9d8842-9462-4439-bc25-4e679dcbb36a','句','趙伯琳','宋','宋诗','song-poetry','','[]','爲嫌陶令醉，來伴屈原醒。',12,'全唐诗/poet.song.74000.json','["爲嫌陶令醉，來伴屈原醒。"]'),
('4dbbfeab-25e7-4db2-9ca3-2812813be405','歲熟','趙彥邁','宋','宋诗','song-poetry','','[]','蕞地曾無一掌平，由來作郡亦强名。',32,'全唐诗/poet.song.74000.json','["蕞地曾無一掌平，由來作郡亦强名。", "峰連萬翠山橫障，川合三溪水遶城。"]'),
('d0c1e444-879c-4cf3-ab74-f7e123a5424a','句','趙彥邁','宋','宋诗','song-poetry','','[]','風俗連巴楚，封疆接播溱。',12,'全唐诗/poet.song.74000.json','["風俗連巴楚，封疆接播溱。"]'),
('5e185316-ede7-4747-a5b3-9f5cfbdfb3db','株林山却笠嶺','周因','宋','宋诗','song-poetry','','[]','萬疊青山鎖翠烟，山間別是一家天。',32,'全唐诗/poet.song.74000.json','["萬疊青山鎖翠烟，山間別是一家天。", "須臾却笠乘雲去，已是浮生七百年。"]'),
('8be5737e-ca58-42bd-b2d9-adc89e28a7c5','子期巖','周因','宋','宋诗','song-poetry','','[]','聞得當年華子期，閑敲石鼓動人時。',32,'全唐诗/poet.song.74000.json','["聞得當年華子期，閑敲石鼓動人時。", "雲門却笠人何在，不見臨流別世詩。"]'),
('f4d3c85b-fce8-46a7-92a7-31947a34fdec','無餘居士齋壁有沈傳師游道山岳麓詩石刻穆仲等和之因亦次韵','司馬朴','宋','宋诗','song-poetry','','[]','湘西勝景豈易論，羣山騰闖萬里奔。',208,'全唐诗/poet.song.74000.json','["湘西勝景豈易論，羣山騰闖萬里奔。", "鶴泉一麓騫鵬噣，松風十里藏祇園。", "當時侍御偶題寫，筆力孰敢爭雄尊。", "東京少年妙詞藻，南陽舊族齊陰樊。", "天心月脅出奇語，使我展讀忘朝昏。", "差差戈劍隠一敵，落落旗鼓嚴千屯。", "無餘居士厲幽志，細研六藝方專門。", "凍骭嬌兒慣腸莧，啼饑瘦婦餘淚痕。", "惟君德義允相愜，每窮道妙角與根。", "他人勸酒驚逐魂，二子頻酌勤空樽。", "醉中詩成渺江海，風外幡影徒飛翻。", "卷藏篋笥已戢戢，風生襟袖何軒軒。", "嗟乎我亦有餘腐，陋哉羊政囚華元。"]'),
('85b0b1a2-8f42-4176-8bc6-1dedf589acf5','句','司馬朴','宋','宋诗','song-poetry','','[]','積雪日出杲，雪飛梅已殘。',84,'全唐诗/poet.song.74000.json','["積雪日出杲，雪飛梅已殘。", "朋游要及時，閣鄰有遐觀。", "乘此蕪穢平，快覽天宇寬。", "霽色混銀界，曠望連江干。", "山如白毫相，滉溢清揚端。", "一氣轉浩渺，萬里皆瀰漫。", "優哉賦梁苑，想像排廣寒。"]'),
('56b2ed7c-55bf-4dc5-a7c5-ba4b6e8e1c01','句  其一','張氏','宋','宋诗','song-poetry','','[]','莫訝淚頻滴，都緣心未灰。',12,'全唐诗/poet.song.74000.json','["莫訝淚頻滴，都緣心未灰。"]'),
('dfd3a196-92fd-4608-a7c8-5e4291ebcb25','句  其二','張氏','宋','宋诗','song-poetry','','[]','滿目烟含芳草綠，倚蘭露泣海棠紅。',16,'全唐诗/poet.song.74000.json','["滿目烟含芳草綠，倚蘭露泣海棠紅。"]'),
('cc4a284a-ee16-4ee2-a8a0-8c947edf401b','句  其三','張氏','宋','宋诗','song-poetry','','[]','尊前獨垂淚，應爲未灰心。',12,'全唐诗/poet.song.74000.json','["尊前獨垂淚，應爲未灰心。"]'),
('b23b5b42-a427-4700-a5fe-5cf6cc9524a3','吳江太湖笠澤虹橋詩二首  其一','范致君','宋','宋诗','song-poetry','','["\u592a\u6e56"]','欲自荆溪泛太湖，三月風濤正可虞。',32,'全唐诗/poet.song.74000.json','["欲自荆溪泛太湖，三月風濤正可虞。", "却自姑蘇操小艇，吳松江下買蓴鱸。"]'),
('b4a06731-5d4d-404a-808b-9d25730c5016','吳江太湖笠澤虹橋詩二首  其二','范致君','宋','宋诗','song-poetry','','["\u592a\u6e56"]','黛潑峰巒安用染，鏡澄湖面不須磨。',32,'全唐诗/poet.song.74000.json','["黛潑峰巒安用染，鏡澄湖面不須磨。", "已驚張翰鱸如玉，想見西施髻似螺。"]'),
('df0f9696-c713-4917-87c8-31e6fcc5a538','呂公洞','范致君','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','朝遊北海暮瀛洲，仙珮何年到此遊。',32,'全唐诗/poet.song.74000.json','["朝遊北海暮瀛洲，仙珮何年到此遊。", "安得相從問丹訣，春風同醉岳陽樓。"]'),
('57100a69-1ac1-4a85-a89c-cfd9698800e4','竹林寺','范致君','宋','宋诗','song-poetry','','[]','竹林深處有招提，靜掩禪關過客稀。',32,'全唐诗/poet.song.74000.json','["竹林深處有招提，靜掩禪關過客稀。", "薝蔔花開春欲暮，泠泠鐘磬白雲低。"]'),
('e036301e-96b6-4ed1-9c98-19741370523d','散金歌','范致虛','宋','宋诗','song-poetry','','[]','北人半是南朝民，食祿南朝終爲君。',32,'全唐诗/poet.song.74000.json','["北人半是南朝民，食祿南朝終爲君。", "失意暫時辭漢主，彷徨不忍痛思親。"]'),
('6997be32-4a18-4343-85fe-6c74678f6b62','與運使桑景詢','范致虛','宋','宋诗','song-poetry','','[]','參旗井鉞出西秦，糾合諸侯付老臣。',64,'全唐诗/poet.song.74000.json','["參旗井鉞出西秦，糾合諸侯付老臣。", "風引旆旌趨魏闕，雪晴宇宙滅天塵。", "寒威等却邊人懼，炎運方隆廟略神。", "已見旄頭墜天外，乞身當喜及今春。"]'),
('dc7ef1a2-c200-4469-ba39-707ab3fedbe3','題保祿寺鐵龍亭','范致虛','宋','宋诗','song-poetry','','[]','數載詩書居保祿，至今常是憶單溪。',64,'全唐诗/poet.song.74000.json','["數載詩書居保祿，至今常是憶單溪。", "幾偎石甕憑欄在，靜聽山禽繞樹啼。", "巖溜潺湲清入骨，林間紅白聞行提。", "吟詩聊寫遥相寄，爲向鐵龍亭上題。"]'),
('dd832095-8150-4b8c-9fa3-c6670db6035d','陽臺山','范致虛','宋','宋诗','song-poetry','','[]','傷心獨立陽臺望，暮雨凄凉宋玉情。',64,'全唐诗/poet.song.74000.json','["傷心獨立陽臺望，暮雨凄凉宋玉情。", "極目草深雲夢澤，連天水闊漢陽城。", "當年楚國山猶在，千古襄王夢不成。", "往事悠悠魂已斷，高唐今日有虛名。"]'),
('49c1b305-86c6-4e04-9cee-e8e84aa37d5e','和公城','范致虛','宋','宋诗','song-poetry','','[]','築壘山前捍道沖，保全黎庶著仁功。',32,'全唐诗/poet.song.74000.json','["築壘山前捍道沖，保全黎庶著仁功。", "寒鴉也解知恩澤，來往飛鳴古塹中。"]'),
('38c957bf-7b34-4711-8ea9-84ba4f2ad18c','甑山城','范致虛','宋','宋诗','song-poetry','','[]','朱伺屯兵古戰場，甑山城堞久凄凉。',32,'全唐诗/poet.song.74000.json','["朱伺屯兵古戰場，甑山城堞久凄凉。", "閒來搔手高岡上，萬里碧天秋思長。"]'),
('e7c8f432-81f1-4add-afd3-d89c9c4dc87b','雨晴登樓','范致虛','宋','宋诗','song-poetry','','[]','自從南北避胡塵，懷抱衰殘不復新。',64,'全唐诗/poet.song.74000.json','["自從南北避胡塵，懷抱衰殘不復新。", "萬里家鄉常入夢，一簾風雨最關春。", "紅疏綠暗能傷客，江靜山明却慰人。", "老去也知登覽倦，閉門僵卧動經旬。"]'),
('34647d85-8d2a-4f32-a8ca-59fa8457ab5e','泛松江','范致虛','宋','宋诗','song-poetry','','[]','黛潑峰巒安用染，鏡澄湖面不須磨。',64,'全唐诗/poet.song.74000.json','["黛潑峰巒安用染，鏡澄湖面不須磨。", "已驚張翰鱸如玉，想見西施髻如螺。", "目斷樓高知水闊，雲開山盡見天多。", "吾家本是烟波主，好律漁翁一曲歌。"]'),
('01c42851-0d97-4e6c-9db2-5cbfd938ca02','句  其一','范致虛','宋','宋诗','song-poetry','','[]','回首陽臺漢川路，隔江烟雨暗漁簑。',16,'全唐诗/poet.song.74000.json','["回首陽臺漢川路，隔江烟雨暗漁簑。"]'),
('e1069867-8189-499a-b701-f3a5fc19a0ae','句  其二','范致虛','宋','宋诗','song-poetry','','[]','瀲灧郎官水，崔巍大別山。',12,'全唐诗/poet.song.74000.json','["瀲灧郎官水，崔巍大別山。"]'),
('4e41520d-0b3a-4282-8c7e-c7857156bf9e','遊永豐寺','劉韞','宋','宋诗','song-poetry','','[]','古寺崢嶸隠翠微，茂林修竹正依依。',32,'全唐诗/poet.song.74000.json','["古寺崢嶸隠翠微，茂林修竹正依依。", "買山也作他年計，何必傍人□是非。"]'),
('d37eafca-fbc9-42ef-ac8c-7431d6210a37','金精','劉韞','宋','宋诗','song-poetry','','[]','空山何代落星躔，今作陽靈小洞天。',64,'全唐诗/poet.song.74000.json','["空山何代落星躔，今作陽靈小洞天。", "試覓丹梯攀絕壁，遥尋絳闕在層巔。", "霜戈雜沓兵初合，霞珮飄摇女已仙。", "靈跡羽人同指點，身輕我欲便凌烟。"]'),
('286900f2-05f0-4a19-a949-cbc71d286abc','場南寺','劉韞','宋','宋诗','song-poetry','','[]','曉起陰霾喜絕收，急快扶酒爲春留。',64,'全唐诗/poet.song.74000.json','["曉起陰霾喜絕收，急快扶酒爲春留。", "落花千點野亭寂，啼鳥一聲春寺幽。", "施食臺高禽易啄，長明燈暗鼠潜偷。", "山僧摘茗吹茶竈，留客殷勤學道州。"]'),
('25b35e1a-327d-44fd-a455-7c551cb883cb','偈','釋景淳','宋','宋诗','song-poetry','','[]','怕寒懶剃髼鬆髮，愛暖頻添榾柮柴。',32,'全唐诗/poet.song.74000.json','["怕寒懶剃髼鬆髮，愛暖頻添榾柮柴。", "破衲伽黎撩亂搭，誰能勞力强安排。"]'),
('fc77221a-d742-4a89-924a-8b4258dda30e','偈','釋道淵','宋','宋诗','song-poetry','','[]','香山有箇話頭，彌滿四大神州。',28,'全唐诗/poet.song.74000.json','["香山有箇話頭，彌滿四大神州。", "若以佛法批判，還如認馬作牛。"]'),
('2b37cc17-8608-40f1-a3f0-40e74bc497c8','偈二首  其一','釋崇哲','宋','宋诗','song-poetry','','[]','妙體堂堂觸處彰，快須回首便承當。',32,'全唐诗/poet.song.74000.json','["妙體堂堂觸處彰，快須回首便承當。", "今朝對衆全分付，莫道儂家有覆藏。"]'),
('0daade45-4fb4-4851-af27-da64aced7353','偈二首  其二','釋崇哲','宋','宋诗','song-poetry','','[]','山僧有三印，更無增減剩。',95,'全唐诗/poet.song.74000.json','["山僧有三印，更無增減剩。", "覿面便相呈，能轉凡成聖。", "一印印空，日月星辰列下風。", "一印印泥，頭頭物物顯真機。", "一印印水，捩轉魚龍頭作尾。", "三印分明體一同，看來非赤亦非紅。", "互換高低如不薦，青山依舊白雲中。"]'),
('7917bd4d-f439-438c-baa0-1fd1cf29cec2','偈','僧某','宋','宋诗','song-poetry','','[]','一水吞空遠，三峰峭壁危。',24,'全唐诗/poet.song.74000.json','["一水吞空遠，三峰峭壁危。", "猊臺重拂拭，共喜主人歸。"]'),
('6942fccf-82d7-4dca-9219-9196a966d82e','偈七首  其一','釋繼成','宋','宋诗','song-poetry','','[]','茫茫盡是覓佛漢，舉世難尋閑道人。',32,'全唐诗/poet.song.74000.json','["茫茫盡是覓佛漢，舉世難尋閑道人。", "棒喝交馳成藥忌，了亡藥忌未天真。"]'),
('8d046b7d-7d21-4b08-9cdc-b73c1d856534','偈七首  其二','釋繼成','宋','宋诗','song-poetry','','[]','崑崙奴著鐵袴，打一棒行一步。',40,'全唐诗/poet.song.74000.json','["崑崙奴著鐵袴，打一棒行一步。", "爭似火中釣鼈，日裏藏冰。", "陰影間翻魍魎，虛空縛殺麻繩。"]'),
('76f924a4-530e-413e-96f5-cd2f810ba5df','偈七首  其三','釋繼成','宋','宋诗','song-poetry','','[]','狹路相逢且莫疑，電光石火已遲遲。',32,'全唐诗/poet.song.74000.json','["狹路相逢且莫疑，電光石火已遲遲。", "若教直下三心徹，祇在如今一餉時。"]'),
('dadfda5c-527a-4dcf-8981-47e146b13f2f','偈七首  其四','釋繼成','宋','宋诗','song-poetry','','[]','舉不顧，即差互。',32,'全唐诗/poet.song.74000.json','["舉不顧，即差互。", "擬思量，何劫悟。", "兔角杖頭挑法界，龜毛拂子舞三臺。"]'),
('25b1a51f-455b-4e70-bdaa-eba0c80c8b75','偈七首  其五','釋繼成','宋','宋诗','song-poetry','','[]','鼻裏音聲耳裏香，眼中鹹淡舌玄黄。',32,'全唐诗/poet.song.74000.json','["鼻裏音聲耳裏香，眼中鹹淡舌玄黄。", "意能覺觸身分別，冰室如春九夏凉。"]'),
('29c1ec11-5ae0-4b72-942f-877cdf5791eb','偈七首  其六','釋繼成','宋','宋诗','song-poetry','','[]','葵花隨日轉，犀紋玩月生。',27,'全唐诗/poet.song.74000.json','["葵花隨日轉，犀紋玩月生。", "香楓化老人，螟𧕅成蜾{虫嬴}。"]'),
('cff817e3-88fe-4bf8-9884-5c3a9c16e867','偈七首  其七','釋繼成','宋','宋诗','song-poetry','','[]','一念心清浄，佛居魔王殿。',24,'全唐诗/poet.song.74000.json','["一念心清浄，佛居魔王殿。", "一念惡心生，魔王居佛殿。"]'),
('e5249e47-97ca-484e-98ca-32432edbf913','偈二首  其一','釋繼成','宋','宋诗','song-poetry','','[]','太陽門下，日日三秋，從東過西。',30,'全唐诗/poet.song.74000.json','["太陽門下，日日三秋，從東過西。", "明月堂前，時時九夏，指鹿爲馬。"]'),
('a269e94f-35ab-4f50-9481-36280e17ac5d','偈二首  其二','釋繼成','宋','宋诗','song-poetry','','[]','擒虎兕，剉於菟。',22,'全唐诗/poet.song.74000.json','["擒虎兕，剉於菟。", "坐斷千聖路頭，打破群魔境界。"]'),
('988f8646-f923-48bb-a38f-b0328fd5d324','頌古四首 夾山境話。','釋繼成','宋','宋诗','song-poetry','','[]','古路雪深覆，好山雲更遮。',24,'全唐诗/poet.song.74000.json','["古路雪深覆，好山雲更遮。", "雁聲天外急，遊子夜還家。"]'),
('45397dae-4256-4074-a375-39020d6db688','頌古四首 德山托鉢。','釋繼成','宋','宋诗','song-poetry','','[]','巫峽山頭窈窕女，朝爲行雲暮爲雨。',32,'全唐诗/poet.song.74000.json','["巫峽山頭窈窕女，朝爲行雲暮爲雨。", "王孫一見空斷腸，便作紅霞隠身去。"]'),
('30de4c03-836d-453d-becf-47dac0d0ca94','頌古四首 女子出定。','釋繼成','宋','宋诗','song-poetry','','[]','文殊頭白，罔明頭黑。',34,'全唐诗/poet.song.74000.json','["文殊頭白，罔明頭黑。", "女子冶容，瞿曇是賊。", "山僧不犯鋒芒，直下并贓捉獲。"]'),
('f2f924c9-d244-43be-890e-a1adc211e22f','頌古四首 龍牙問翠微臨濟佛法大意。','釋繼成','宋','宋诗','song-poetry','','[]','駕與青龍不解騎，人人盡道阿師癡。',32,'全唐诗/poet.song.74000.json','["駕與青龍不解騎，人人盡道阿師癡。", "爛泥中有傷人刺，三度曾施陷虎機。"]'),
('5ec0633e-e83c-4378-b1f7-1e20f86d4aa6','偈','釋彥孜','宋','宋诗','song-poetry','','[]','若是諦當漢，通身無隔礙。',74,'全唐诗/poet.song.74000.json','["若是諦當漢，通身無隔礙。", "舉措絕毫釐，把手出紅塵。", "撥開向上竅，當頭劄定，不犯鋒稜。", "轉握將來，應用恰好。", "絲毫不漏，函蓋相應。", "任是諸佛諸祖，覷著寒毛卓豎。"]'),
('093ef222-4ea6-4db2-a8a6-23bfe25831ca','偈二首  其一','釋法真','宋','宋诗','song-poetry','','[]','蘆峰深處無人到，門前雪壓枯松倒。',32,'全唐诗/poet.song.74000.json','["蘆峰深處無人到，門前雪壓枯松倒。", "板聲驚起夢中人，一條古路清風掃。"]'),
('6093f78f-55b7-449c-b789-e21efa860868','偈二首  其二','釋法真','宋','宋诗','song-poetry','','[]','欲明向上事，須具頂門眼。',36,'全唐诗/poet.song.74000.json','["欲明向上事，須具頂門眼。", "若具頂門眼，始契出家心。", "既契出家心，常具頂門眼。"]'),
('79af1e3a-de5b-4df6-b685-31c3d3f520ec','會頂門眼偈','釋法真','宋','宋诗','song-poetry','','[]','四京人著衣喫飯，兩浙人飽暖自如。',32,'全唐诗/poet.song.74000.json','["四京人著衣喫飯，兩浙人飽暖自如。", "通玄峰頂香風清，花發蟠桃三四株。"]'),
('0dc2073e-51b5-4990-af08-60a93cdf8f03','偈頌十五首  其一','釋慧方','宋','宋诗','song-poetry','','[]','圓伊三點未輕酬，句句無私即便休。',32,'全唐诗/poet.song.74000.json','["圓伊三點未輕酬，句句無私即便休。", "點的鋒芒徒擬議，明明端的不當頭。"]'),
('07de074a-365e-4d17-a86c-8b4cf120918c','偈頌十五首  其二','釋慧方','宋','宋诗','song-poetry','','[]','律管吹灰是此辰，應當識取看牛人。',32,'全唐诗/poet.song.74000.json','["律管吹灰是此辰，應當識取看牛人。", "心田耕徧無餘地，須信靈苗不犯春。"]'),
('349b33da-f51a-4c91-9fa4-87b86d89a2f0','偈頌十五首  其三','釋慧方','宋','宋诗','song-poetry','','[]','山河大地，燈籠露柱。',20,'全唐诗/poet.song.74000.json','["山河大地，燈籠露柱。", "厨庫三門，皆是光境。"]'),
('9d8fbce0-4f05-4c23-a538-e406ebd9e1a8','偈頌十五首  其四','釋慧方','宋','宋诗','song-poetry','','[]','要會入門句，未語先分付。',24,'全唐诗/poet.song.74000.json','["要會入門句，未語先分付。", "直下苦精神，不必通回互。"]'),
('31b8a468-c343-4d05-94a3-6d391c2fbae5','偈頌十五首  其五','釋慧方','宋','宋诗','song-poetry','','[]','回首光陰若轉蓬，看看九夏又將終。',32,'全唐诗/poet.song.74000.json','["回首光陰若轉蓬，看看九夏又將終。", "快須悟取玄中句，莫逐情塵枉用功。"]'),
('ec0eb227-6d58-4654-8ca7-fde9bf79b7ed','偈頌十五首  其六','釋慧方','宋','宋诗','song-poetry','','[]','瑞雪飄空，銀蟾出海。',38,'全唐诗/poet.song.74000.json','["瑞雪飄空，銀蟾出海。", "曹山異中見異，龐公手裏明機。", "一箇覿面全提，一箇通途叶妙。"]'),
('9407ef87-95fc-4ccd-903a-97823620faad','偈頌十五首  其七','釋慧方','宋','宋诗','song-poetry','','[]','第一玄，拶破髑髏前。',60,'全唐诗/poet.song.74000.json','["第一玄，拶破髑髏前。", "第二玄，照用在機先。", "第三玄，物我兩俱全。", "第一要，箇中明得兆。", "第二要，機俊未爲妙。", "第三要，覿面須回照。"]'),
('0dd2a9e5-6116-4099-b0a1-61e266ba3c67','偈頌十五首  其八','釋慧方','宋','宋诗','song-poetry','','[]','日炙風吹知幾年，玄中密意妙難傳。',32,'全唐诗/poet.song.74000.json','["日炙風吹知幾年，玄中密意妙難傳。", "當機若見首山老，直下應須了目前。"]'),
('ce109afe-4d93-4eaa-8ce1-c30928fe3e02','偈頌十五首  其九','釋慧方','宋','宋诗','song-poetry','','[]','令人翻憶老雲門，問答全超未足論。',32,'全唐诗/poet.song.74000.json','["令人翻憶老雲門，問答全超未足論。", "棒下責情還會否，夜深明月照前村。"]'),
('ff014b37-b580-46d1-8249-81ef702c7d0e','偈頌十五首  其一○','釋慧方','宋','宋诗','song-poetry','','[]','露柱患癰癤，燈籠却皺眉。',24,'全唐诗/poet.song.74000.json','["露柱患癰癤，燈籠却皺眉。", "箇中無限意，曾不墮聞思。"]'),
('12ed9570-4aa4-49cf-be05-cf8cf2119010','偈頌十五首  其一一','釋慧方','宋','宋诗','song-poetry','','[]','吹毛寶劍當機妙，切玉如泥孰可猜。',32,'全唐诗/poet.song.74000.json','["吹毛寶劍當機妙，切玉如泥孰可猜。", "不犯鋒芒全正令，法王心印爲君開。"]'),
('fa519610-665d-46e4-af99-528cd0268a4d','偈頌十五首  其一二','釋慧方','宋','宋诗','song-poetry','','[]','十字街中六不收，本來面目絕蹤由。',32,'全唐诗/poet.song.74000.json','["十字街中六不收，本來面目絕蹤由。", "縱饒悟得分明去，已落儂家第二頭。"]'),
('9beee20f-e108-46a6-8c04-ca652fea8f05','偈頌十五首  其一三','釋慧方','宋','宋诗','song-poetry','','[]','一住禾山又八年，臨岐一句妙難傳。',32,'全唐诗/poet.song.74000.json','["一住禾山又八年，臨岐一句妙難傳。", "後宵欲見雲巖老，雲綻青天月正圓。"]'),
('a05f6a44-5bbe-47f7-8c82-101f5607d9e3','偈頌十五首  其一四','釋慧方','宋','宋诗','song-poetry','','[]','第一玄，直透威音前。',30,'全唐诗/poet.song.74000.json','["第一玄，直透威音前。", "第二玄，曾不落正偏。", "第三玄，照用兩俱全。"]'),
('fa59cee5-d514-4db3-b6c8-88d7deff651f','偈頌十五首  其一五','釋慧方','宋','宋诗','song-poetry','','[]','銅壺送客歸家去，玉漏催人好坐禪。',32,'全唐诗/poet.song.74000.json','["銅壺送客歸家去，玉漏催人好坐禪。", "何事金吾不惜夜，心燈徧界爲君燃。"]'),
('f683c5e8-1666-4748-b6af-0c572ac91fb4','趙州勘婆','釋慧方','宋','宋诗','song-poetry','','[]','兩重問答絕聱訛，趙老於中却勘婆。',32,'全唐诗/poet.song.74000.json','["兩重問答絕聱訛，趙老於中却勘婆。", "若不全身探虎穴，安能徹底驗仙陀。"]'),
('f15310ce-0b2d-4b5c-88fe-7f2c73739bea','百丈野狐','釋慧方','宋','宋诗','song-poetry','','[]','百丈堂前驗野狐，還如水上捺葫蘆。',32,'全唐诗/poet.song.74000.json','["百丈堂前驗野狐，還如水上捺葫蘆。", "而今到處全機入，便好當場捋虎鬚。"]'),
('1e040110-55f0-4469-8379-7baeabcc974c','大隋蓋龜','釋慧方','宋','宋诗','song-poetry','','[]','千古清聲老大隨，機鋒壁立杳難窺。',32,'全唐诗/poet.song.74000.json','["千古清聲老大隨，機鋒壁立杳難窺。", "未能直下超凡聖，只道將鞋蓋却龜。"]'),
('329c13a8-2514-406c-bd94-696edb6e3e82','女子出定','釋慧方','宋','宋诗','song-poetry','','[]','當機密薦箇中玄，女子何因坐佛前。',32,'全唐诗/poet.song.74000.json','["當機密薦箇中玄，女子何因坐佛前。", "切莫途中爲解礙，刻舟求劍實徒然。"]'),
('b383f2e2-5b29-4f38-8b99-fc1c22b7e12b','諸佛居何國土','釋慧方','宋','宋诗','song-poetry','','[]','千佛靈蹤莫別求，長沙機轉有來由。',32,'全唐诗/poet.song.74000.json','["千佛靈蹤莫別求，長沙機轉有來由。", "要知覿體難藏處，黄鶴樓前鸚鵡洲。"]'),
('3fd290a4-9a87-46c3-9613-620394dd198a','曹山雪中因緣','釋慧方','宋','宋诗','song-poetry','','[]','群峰雪覆已超然，絕頂寧同一色邊。',64,'全唐诗/poet.song.74000.json','["群峰雪覆已超然，絕頂寧同一色邊。", "儻向異中能辨異，雖居偏位不成偏。", "入塵直截須明要，在類還殊密造玄。", "欲混千差通不犯，曹山穿過髑髏前。"]'),
('be9e3979-00ca-4854-bed6-7cdca8331559','保福簽瓜','釋慧方','宋','宋诗','song-poetry','','[]','古今時節正相歡，指外明機沒異端。',64,'全唐诗/poet.song.74000.json','["古今時節正相歡，指外明機沒異端。", "未入口時先識味，已簽瓜處被渠瞞。", "大原接處當頭嶮，保福拈來却放難。", "若也未能超影響，盡從死活句中看。"]'),
('c0967f03-2ab6-4a4e-8453-8e4a93ce6410','玄沙指虎','釋慧方','宋','宋诗','song-poetry','','[]','欲識玄沙虎，覿面是誰睹。',24,'全唐诗/poet.song.74000.json','["欲識玄沙虎，覿面是誰睹。", "直下透牢關，全機超佛祖。"]'),
('a6f9db53-b2fb-4ee4-835d-55fdeb2c1f20','酬徐樞密三問  其一','釋慧方','宋','宋诗','song-poetry','','[]','擬將心意學玄宗，妙用縱橫觸處通。',32,'全唐诗/poet.song.74000.json','["擬將心意學玄宗，妙用縱橫觸處通。", "捩轉箇中關捩子，休論南北與西東。"]'),
('32ec504e-50d8-4a64-a77d-1eb6e1caa16c','酬徐樞密三問  其二','釋慧方','宋','宋诗','song-poetry','','[]','或有恐怖或斷疑，雙明一句絕針錐。',32,'全唐诗/poet.song.74000.json','["或有恐怖或斷疑，雙明一句絕針錐。", "於茲切莫生欣厭，覿面還須眼似眉。"]'),
('f0785ed0-4f51-478f-836d-411a4086feb0','酬徐樞密三問  其三','釋慧方','宋','宋诗','song-poetry','','[]','衆生病故維摩病，妙見全提越我人。',32,'全唐诗/poet.song.74000.json','["衆生病故維摩病，妙見全提越我人。", "既了病源無箇事，何如示現宰官身。"]'),
('28534efd-b493-4ac0-82d9-a9c1b348708d','和蔣運使三頌  其一','釋慧方','宋','宋诗','song-poetry','','[]','未下山來已見，箇中法法全真。',28,'全唐诗/poet.song.74000.json','["未下山來已見，箇中法法全真。", "大地都是自己，覿面更無別人。"]'),
('1f9ea24e-8685-435f-8121-96560f3d1a6b','和蔣運使三頌  其二','釋慧方','宋','宋诗','song-poetry','','[]','了得爲官勳業，便是祖佛門風。',28,'全唐诗/poet.song.74000.json','["了得爲官勳業，便是祖佛門風。", "心外實無一法，孰云曠劫難逢。"]'),
('7482dd90-1162-4bf5-9198-8ded7c71d182','和蔣運使三頌  其三','釋慧方','宋','宋诗','song-poetry','','[]','此去欲尋相見，大千俱是禾山。',28,'全唐诗/poet.song.74000.json','["此去欲尋相見，大千俱是禾山。", "徹底洞明這箇，廓然超過八還。"]'),
('33a01770-7b93-41a2-aeda-86e10629318b','和董承事三頌見別  其一','釋慧方','宋','宋诗','song-poetry','','[]','道存愈遠却彌親，去住情忘尚隔津。',32,'全唐诗/poet.song.74000.json','["道存愈遠却彌親，去住情忘尚隔津。", "直下是家歸甚處，大千全現本來人。"]'),
('d8b2641f-a917-4d2f-91fc-66912906ffe9','和董承事三頌見別  其二','釋慧方','宋','宋诗','song-poetry','','[]','順水張帆息浪花，截流一句不周遮。',32,'全唐诗/poet.song.74000.json','["順水張帆息浪花，截流一句不周遮。", "已登彼岸無餘事，入海誰能更筭沙。"]'),
('8d9d13e5-59f2-4add-a035-84cbd6623ebc','和董承事三頌見別  其三','釋慧方','宋','宋诗','song-poetry','','[]','長憶當年陸大夫，同根底事强分疏。',32,'全唐诗/poet.song.74000.json','["長憶當年陸大夫，同根底事强分疏。", "道人固有超然句，雖別應難不見渠。"]'),
('0530555d-7fd5-4f47-9a5c-78d13da540f6','古鏡銘','釋慧方','宋','宋诗','song-poetry','','[]','有古菱花，物來斯現。',60,'全唐诗/poet.song.74000.json','["有古菱花，物來斯現。", "演若倍瞻，仰山親薦。", "迷悟雖殊，寒光不變。", "惡像弗祛，麗質奚羨。", "歷照千差，肯隨物轉。", "覷破前塵，是誰對面。"]'),
('5f670f7e-da8c-4f56-851e-97b287c70036','和靈源和尚善護頌','釋慧方','宋','宋诗','song-poetry','','[]','靈性包群象，千年壽最優。',48,'全唐诗/poet.song.74000.json','["靈性包群象，千年壽最優。", "既知身是幻，何用殻埋頭。", "護惜雖深固，推遷已密流。", "大隨鞋蓋處，若箇辨蹤由。"]'),
('d4c0775b-474d-47f3-8739-733d91ceb3a7','送禪人化緣轉藏','釋慧方','宋','宋诗','song-poetry','','[]','經頭以字孰能測，舉起分明好消息。',64,'全唐诗/poet.song.74000.json','["經頭以字孰能測，舉起分明好消息。", "勞生未曉直截機，雙林大士運神力。", "括囊五教妙全提，高張八面真奇特。", "汝行如是化檀那，推轉機關超奧域。"]'),
('f2b65346-1a69-4f41-bdd6-a96f2d92413a','送化士','釋慧方','宋','宋诗','song-poetry','','[]','青春條風至，無情闡化機。',48,'全唐诗/poet.song.74000.json','["青春條風至，無情闡化機。", "法本自何來，要當探極微。", "只在紅塵中，忽見勝珠璣。", "雖然皆舊物，爭奈昔人非。"]'),
('7dd1913a-42d6-47a7-9046-db3a14acd655','禪人呈雪竇頂相求贊','釋慧方','宋','宋诗','song-poetry','','[]','勘破北塔歸來，接得鐵佛即透。',28,'全唐诗/poet.song.74000.json','["勘破北塔歸來，接得鐵佛即透。", "分明覿面全彰，不可喚作雪竇。"]'),
('16e9a134-1766-4c70-b91d-be2fc82f9398','禪人寫余真求贊  其一','釋慧方','宋','宋诗','song-poetry','','[]','打破直要坐禪，佛祖亦須超越。',28,'全唐诗/poet.song.74000.json','["打破直要坐禪，佛祖亦須超越。", "若言祇這便是，大似水中捉月。"]'),
('218959b4-fa20-4f3b-903a-8b1e490db7bb','禪人寫余真求贊  其二','釋慧方','宋','宋诗','song-poetry','','[]','古松怪石，全體是我。',20,'全唐诗/poet.song.74000.json','["古松怪石，全體是我。", "若謂一如，莫教話墮。"]'),
('c297cc69-4a50-4714-8f6f-6a2aa7e604e1','偈','釋祖秀','宋','宋诗','song-poetry','','[]','枯木巖前夜放華，鐵牛依舊卧烟沙。',32,'全唐诗/poet.song.74000.json','["枯木巖前夜放華，鐵牛依舊卧烟沙。", "儂家鞭影重拈出，一念回心便到家。"]'),
('3dac9c51-807d-49d1-b6a7-caba7002c7d2','自像贊','釋齊謐','宋','宋诗','song-poetry','','[]','箇漢灰頭土面，尋常不欲露現。',39,'全唐诗/poet.song.74000.json','["箇漢灰頭土面，尋常不欲露現。", "而今寫出人前，大似虛空著箭。", "怨怨，可惜人間三尺絹。"]'),
('a140224c-f8c1-4780-8da9-9ab95c4dc903','題佛鑒禪師語錄後','釋慧古','宋','宋诗','song-poetry','','[]','流水高山不在弦，等閑成曲又成篇。',64,'全唐诗/poet.song.74000.json','["流水高山不在弦，等閑成曲又成篇。", "列珊瑚樹枝枝好，撒水銀珠顆顆圓。", "揮落禪關無少滯，增添衲子幾重冤。", "擬於紙上明端的，爭似當機自造玄。"]'),
('785c601d-d0e9-4ff4-a300-2dab0d50df51','咨叩有省呈黄龍清禪師偈','戴道純','宋','宋诗','song-poetry','','[]','杳冥源底全機處，一片心花露印紋。',32,'全唐诗/poet.song.74000.json','["杳冥源底全機處，一片心花露印紋。", "知是幾生曾供養，時時微笑動香雲。"]'),
('6207518e-c558-419d-866f-915b2672e16b','偈二首  其一','釋咸靜','宋','宋诗','song-poetry','','[]','氣候欲流金，炎威將鑠石。',80,'全唐诗/poet.song.74000.json','["氣候欲流金，炎威將鑠石。", "扇子摇明月，雲片聳奇峰。", "蠶成繭而麥漸收，笋抽簪而梅已熟。", "薰風習習，逝水滔滔。", "鵲噪森松，鶑啼修竹。", "觀音勢至，文殊普賢。", "有願必從，無剎不現。"]'),
('d611dd44-f3ea-43c0-b302-4fc87941fb34','偈二首  其二','釋咸靜','宋','宋诗','song-poetry','','[]','匣中寶劍，袖裏金鎚。',74,'全唐诗/poet.song.74000.json','["匣中寶劍，袖裏金鎚。", "時節既彰，莫辭拈出。", "擊開關鎖，斬斷葛藤。", "令他跳出生死門，驚過荆棘路。", "人人似生師子，箇箇如活大蟲。", "休教著布過他州，直待還鄉衣晝錦。"]'),
('4a07f60c-a493-469c-872d-84cd07746407','臨終偈','釋咸靜','宋','宋诗','song-poetry','','[]','弄罷影戲，七十一載。',20,'全唐诗/poet.song.74000.json','["弄罷影戲，七十一載。", "更問如何，回來別賽。"]'),
('cb57cef1-4ab0-4fd1-8cb6-d51796323d14','頌古四首 勘婆二 其一','釋咸靜','宋','宋诗','song-poetry','','[]','婆子只知指路，雞犬被人偷去。',28,'全唐诗/poet.song.74000.json','["婆子只知指路，雞犬被人偷去。", "直待趙州勘了，這回緊閉門戶。"]'),
('56fe6858-5446-422f-9790-6b690448b832','頌古四首 勘婆二 其二','釋咸靜','宋','宋诗','song-poetry','','[]','趙州老老大大，不解山中打坐。',28,'全唐诗/poet.song.74000.json','["趙州老老大大，不解山中打坐。", "自言去勘婆了，倒被婆子勘破。"]'),
('f0e2b30a-32ac-403a-90de-7ffc9a099a45','頌古四首 犀牛扇','釋咸靜','宋','宋诗','song-poetry','','[]','扇上犀牛從古畫，索來既破要元牛。',32,'全唐诗/poet.song.74000.json','["扇上犀牛從古畫，索來既破要元牛。", "縱教戴子重描出，不是當時那一頭。"]'),
('e4c6ca69-425c-4b09-a399-e1118d425b0e','頌古四首 四不遷','釋咸靜','宋','宋诗','song-poetry','','[]','掐珠不念佛，開眼不見色。',24,'全唐诗/poet.song.74000.json','["掐珠不念佛，開眼不見色。", "喫飯誰擇日，任東西南北。"]'),
('72f25ee4-5d2d-48ea-9fa8-4f5d6dd6c64a','擬寒山自述  其一','釋咸靜','宋','宋诗','song-poetry','','[]','多見擬寒山，不然擬拾得。',48,'全唐诗/poet.song.74000.json','["多見擬寒山，不然擬拾得。", "沖天各有志，擬彼復何益。", "居山山色翠，臨水水聲長。", "風華與雪月，時處自歌揚。"]'),
('31717337-d936-4696-abe8-973ac0d3fda6','擬寒山自述  其二','釋咸靜','宋','宋诗','song-poetry','','[]','頗憶未參禪，教中聽十年。',48,'全唐诗/poet.song.74000.json','["頗憶未參禪，教中聽十年。", "晝夜數他寶，何曾得半錢。", "發志出行脚，遍求無病藥。", "及至休歇時，依舊沒鞋著。"]'),
('6f1a8afb-c930-4e4f-894d-838cb5472b82','擬寒山自述  其三','釋咸靜','宋','宋诗','song-poetry','','[]','行時唯信脚，到處便爲家。',51,'全唐诗/poet.song.74000.json','["行時唯信脚，到處便爲家。", "午飯隨麤細，三衣亂掩遮。", "空名耳裏水，微利眼中砂。", "一覺黄昏睡，金鳥出{氵毒}涯。"]'),
('823de19e-3234-43df-aa43-c80ad9ad1b99','擬寒山自述  其四','釋咸靜','宋','宋诗','song-poetry','','[]','目述自高吟，自高非倨傲。',48,'全唐诗/poet.song.74000.json','["目述自高吟，自高非倨傲。", "高懷肯隨動，幽鳥徒輕噪。", "無水定無源，有烟必有竈。", "天堂并地獄，自作還自報。"]'),
('6826506e-6fb3-43cf-bb29-31809077f256','擬寒山自述  其五','釋咸靜','宋','宋诗','song-poetry','','[]','近見一般人，堂堂似佛祖。',48,'全唐诗/poet.song.74000.json','["近見一般人，堂堂似佛祖。", "入室求知識，爲明生死事。", "問汝莫是賊，當時面如土。", "語言勿生嗔，只箇是生死。"]'),
('98a4a55b-c80c-465b-8423-904bda52c330','擬寒山自述  其六','釋咸靜','宋','宋诗','song-poetry','','[]','參禪脫生死，輒莫被魔使。',48,'全唐诗/poet.song.74000.json','["參禪脫生死，輒莫被魔使。", "八風一任吹，六塵終不污。", "非語亂如麻，截斷衆流句。", "仰面看青天，立地超佛祖。"]'),
('0794f9d0-3eab-4a91-968b-6f51dc5a3a2b','擬寒山自述  其七','釋咸靜','宋','宋诗','song-poetry','','[]','五更一盂粥，辰時一頓飯。',48,'全唐诗/poet.song.74000.json','["五更一盂粥，辰時一頓飯。", "晝夜兩覺眠，一日事俱辨。", "毀我還自毀，贊我還自贊。", "是非與榮辱，紅爐赤金彈。"]'),
('3bc1be04-5401-43b1-9865-f2e03e4c8af5','擬寒山自述  其八','釋咸靜','宋','宋诗','song-poetry','','[]','良田著力耕，自利復利故。',48,'全唐诗/poet.song.74000.json','["良田著力耕，自利復利故。", "莫栽荆棘樹，子孫沒出路。", "仁者愛安仁，狡佞生嫉妬。", "勸汝早回頭，翻覆面前覷。"]'),
('87827b96-adcc-42bc-acfa-afe4bdc7f837','擬寒山自述  其九','釋咸靜','宋','宋诗','song-poetry','','[]','莫笑我自述，麤言無義理。',48,'全唐诗/poet.song.74000.json','["莫笑我自述，麤言無義理。", "豈爲騁文辭，因筆寫其志。", "百年呼吸間，何用苦較計。", "勸汝莫癡毒，無常忽忽至。"]'),
('475535c0-ac5d-4c27-9e15-4c8d8cb6114e','擬寒山自述  其一○','釋咸靜','宋','宋诗','song-poetry','','["\u8861\u5c71"]','一曲樂昇平，非關囉哩棱。',48,'全唐诗/poet.song.74000.json','["一曲樂昇平，非關囉哩棱。", "山河俱屬宋，雲水且饒僧。", "時擊松風磬，長然澗月燈。", "願王似南嶽，萬世碧層層。"]'),
('5531d668-cb4a-4279-8e8d-7a227f3a2371','十二時  其一','釋咸靜','宋','宋诗','song-poetry','','[]','半夜子，心境俱忘正莽鹵。',28,'全唐诗/poet.song.74000.json','["半夜子，心境俱忘正莽鹵。", "撚轉天關萬象移，泥牛入海誰親睹。"]'),
('a13ed25b-dfde-4701-967b-0fe7e951acf7','十二時  其二','釋咸靜','宋','宋诗','song-poetry','','[]','雞鳴丑，一聲相報無前後。',28,'全唐诗/poet.song.74000.json','["雞鳴丑，一聲相報無前後。", "驚覺騰騰夢裏身，釋迦老子交橫走。"]'),
('036bf1e2-d011-4c44-af83-363bd0a9d617','十二時  其三','釋咸靜','宋','宋诗','song-poetry','','[]','平旦寅，翠竹黄華拂眼明。',28,'全唐诗/poet.song.74000.json','["平旦寅，翠竹黄華拂眼明。", "靈禽異獸爭嘲哄，總解回頭轉眼睛。"]'),
('74846741-e68a-4d73-8d4d-ce3cfa7d207f','十二時  其四','釋咸靜','宋','宋诗','song-poetry','','[]','日出卯，紫霧紅霞騰海島。',28,'全唐诗/poet.song.74000.json','["日出卯，紫霧紅霞騰海島。", "擠排無限利名人，出門忘却衣中寶。"]'),
('277f7931-992e-435d-a444-ee7633595c53','十二時  其五','釋咸靜','宋','宋诗','song-poetry','','[]','食時辰，掌鉢徒勞入市巡。',28,'全唐诗/poet.song.74000.json','["食時辰，掌鉢徒勞入市巡。", "若將心受檀那飯，也似無功食祿人。"]'),
('34ff6e13-fd9b-4d7b-a63e-b99b908986fc','十二時  其六','釋咸靜','宋','宋诗','song-poetry','','[]','禺中巳，選甚婬坊并酒肆。',28,'全唐诗/poet.song.74000.json','["禺中巳，選甚婬坊并酒肆。", "回頭便是出塵人，翻笑曼殊携慶喜。"]'),
('df56e213-21a5-4bdb-bdab-864365418338','十二時  其七','釋咸靜','宋','宋诗','song-poetry','','[]','日南午，卓然獨耀無今古。',28,'全唐诗/poet.song.74000.json','["日南午，卓然獨耀無今古。", "糞埽堆頭玉馬嘶，瑠璃殿上金剛舞。"]'),
('f1019fc8-434a-4799-91d3-6829961d015d','十二時  其八','釋咸靜','宋','宋诗','song-poetry','','[]','日昳未，萬樹千峰影斜墜。',28,'全唐诗/poet.song.74000.json','["日昳未，萬樹千峰影斜墜。", "兔角龜毛遶市尋，貴賣還思買時貴。"]'),
('965b19c6-a5e8-4313-9156-4735eab32a63','十二時  其九','釋咸靜','宋','宋诗','song-poetry','','[]','晡時申，一日三分過二分。',28,'全唐诗/poet.song.74000.json','["晡時申，一日三分過二分。", "直饒省得來時路，到家急急也黄昏。"]'),
('95620fab-30a2-4c72-8ce9-6e91fe05df47','十二時  其一○','釋咸靜','宋','宋诗','song-poetry','','[]','日入酉，殘霞返照門前柳。',28,'全唐诗/poet.song.74000.json','["日入酉，殘霞返照門前柳。", "無聲一曲牧童歸，背跨牛兒師子吼。"]'),
('104581b1-cc75-4578-af54-1b4a1222daef','十二時  其一一','釋咸靜','宋','宋诗','song-poetry','','[]','黄昏戌，角韵鍾聲遐邇一。',28,'全唐诗/poet.song.74000.json','["黄昏戌，角韵鍾聲遐邇一。", "要會聞復翳根除，補陀巖上尋彌勒。"]');
